          return (
            <div className="space-y-3">
              <SelectField label="Cart type" value={theme.cartStyle} onChange={updateSetting("cartStyle")} options={[
                { label: "Drawer", value: "drawer" }, { label: "Page", value: "page" }, { label: "Popup notification", value: "dropdown" },
              ]} />
              <SelectField label="Icon style" value={theme.cartIconStyle} onChange={updateSetting("cartIconStyle")} options={[
                { label: "Bag", value: "bag" }, { label: "Cart", value: "cart" }, { label: "Basket", value: "basket" },
              ]} />
              <CheckboxField label="Show item count" checked={theme.showCartCount} onChange={updateSetting("showCartCount")} />
              <CheckboxField label="Show vendor" checked={theme.cartShowVendor} onChange={updateSetting("cartShowVendor")} />
              <CheckboxField label="Enable cart note" checked={theme.cartEnableNote} onChange={updateSetting("cartEnableNote")} />
              <TextField label="Empty cart text" value={theme.cartEmptyText} onChange={updateSetting("cartEmptyText")} />
              {theme.cartStyle === "drawer" && (
                <div className="border-t border-border/30 pt-2">
                  <Label className="text-[10px] uppercase tracking-wider text-gray-500 mb-2 block">Cart drawer</Label>
                  <div className="space-y-2">
                    <SelectField
                      label="Collection"
                      value={drawerCollectionValue}
                      onChange={updateSetting("cartDrawerCollectionId")}
                      options={drawerCollectionOptions}
                      disabled
                      placeholder="Coming soon"
                    />
                    <CheckboxField
                      label="Visible when cart drawer is empty"
                      checked={theme.cartDrawerShowWhenEmpty}
                      onChange={updateSetting("cartDrawerShowWhenEmpty")}
                    />
                    <SelectField
                      label="Color scheme"
                      value={theme.cartDrawerColorScheme}
                      onChange={updateSetting("cartDrawerColorScheme")}
                      options={theme.colorSchemes.map((scheme: ColorScheme) => ({ label: scheme.name, value: scheme.id }))}
                    />
                  </div>
                </div>
              )}
            </div>
          );
        }

        // ---------------------------------------------------------------
        case "Custom CSS":
          return (
            <div className="space-y-2">
              <Label className="text-[10px] uppercase tracking-wider text-gray-500">Custom CSS</Label>
              <TextField
                label="CSS selectors"
                value={theme.customCssSelectors}
                onChange={updateSetting("customCssSelectors")}
                placeholder=".product-card, #cart, .footer"
              />
              <textarea
                value={theme.customCss}
                onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => update("customCss", e.target.value)}
                placeholder={".my-class {\n  color: red;\n}"}
                className="w-full rounded border border-border/50 bg-gray-800/40 p-2 font-mono text-xs text-gray-300 placeholder:text-gray-600 focus:border-blue-500 focus:outline-none min-h-[120px] resize-y"
                spellCheck={false}
              />
            </div>
          );

        // ---------------------------------------------------------------
        case "Theme Style":
          return (
            <div className="space-y-3">
              <SelectField label="Preset" value={theme.themePreset} onChange={handleThemePresetChange} options={themePresetOptions} />
              <CheckboxField label="Dark mode" checked={theme.darkMode} onChange={updateSetting("darkMode")} />
            </div>
          );

        // ---------------------------------------------------------------
        default:
          return <div className="text-xs text-gray-500">Settings coming soon.</div>;
      }
    },
    [
      activeScheme,
      handleSaveScheme,
      handleLogoChange,
      handlePickLogo,
      editingSchemeId,
      logoFile?.name,
      logoPreviewUrl,
      logoWidth,
      newSchemeColors,
      newSchemeName,
      startAddScheme,
      startEditScheme,
      schemeView,
      isGlobalPaletteOpen,
      themePresetOptions,
      handleThemePresetChange,
      toggleGlobalPalette,
      updateSchemeColor,
      updateSetting,
      theme,
      update,
    ]
  );

  return (
    <div className="flex min-h-0 flex-1 flex-col">
      {showHeader && (
        <div className="border-b border-border px-4 py-3">
          <div className="text-xs font-semibold uppercase tracking-wide text-gray-400">
            Theme settings
          </div>
          <p className="mt-1 text-[11px] text-gray-500">
            Configure global styles and storefront components.
          </p>
        </div>
      )}
      <div className="flex-1 overflow-y-auto p-3">
        <div className="space-y-2">
          {THEME_SECTIONS.map((section: string): React.JSX.Element => {
            const isOpen = openSections.has(section);
            return (
              <div key={section} className="rounded border border-border/40 bg-gray-900/60">
                <button
                  type="button"
                  onClick={(): void => toggleSection(section)}
                  className="flex w-full items-center justify-between gap-2 px-3 py-2 text-left text-sm text-gray-200 hover:bg-muted/40"
                  aria-expanded={isOpen}
                >
                  <span>{section}</span>
                  <ChevronDown className={`size-4 text-gray-500 transition ${isOpen ? "rotate-180" : ""}`} />
                </button>
                {isOpen && (
                  <div className="px-3 pb-3">{renderSectionBody(section)}</div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

import type { SectionInstance } from "../../types/page-builder";

export const GRID_TEMPLATE_SETTINGS_KEY = "cms_grid_templates.v1";

export type GridTemplateRecord = {
  id: string;
  name: string;
  description?: string;
  createdAt: string;
  section: SectionInstance;
};

export function normalizeGridTemplates(input: unknown): GridTemplateRecord[] {
  if (!Array.isArray(input)) return [];
  return input
    .map((entry, index): GridTemplateRecord | null => {
      if (!entry || typeof entry !== "object") return null;
      const record = entry as Partial<GridTemplateRecord>;
      const section = record.section;
      if (!section || typeof section !== "object" || section.type !== "Grid") return null;
      return {
        id: typeof record.id === "string" && record.id.length > 0 ? record.id : `grid-template-${index + 1}`,
        name: typeof record.name === "string" && record.name.trim().length > 0 ? record.name.trim() : `Grid template ${index + 1}`,
        description: typeof record.description === "string" ? record.description : "",
        createdAt: typeof record.createdAt === "string" && record.createdAt.length > 0 ? record.createdAt : new Date().toISOString(),
        section: section as SectionInstance,
      };
    })
    .filter((record): record is GridTemplateRecord => Boolean(record));
}

export function cloneGridTemplateSection(section: SectionInstance): SectionInstance {
  return JSON.parse(JSON.stringify(section)) as SectionInstance;
}

"use client";

import { Button, Input, Label, SectionHeader, Checkbox } from "@/shared/ui";
import { useState } from "react";
import { useRouter } from "next/navigation";

import { CmsDomainSelector } from "@/features/cms";
import { useCmsDomainSelection } from "@/features/cms/hooks/useCmsDomainSelection";
import { useCmsSlugs, useCreatePage } from "@/features/cms/hooks/useCmsQueries";

export default function CreatePagePage() {
  const [name, setName] = useState("");
  const [slugIds, setSlugIds] = useState<string[]>([]);
  const router = useRouter();
  const { activeDomainId } = useCmsDomainSelection();
  const slugsQuery = useCmsSlugs(activeDomainId);
  const createPage = useCreatePage();
  const [search, setSearch] = useState("");

  const slugs = slugsQuery.data ?? [];
  const filteredSlugs = slugs.filter((slug) =>
    slug.slug.toLowerCase().includes(search.trim().toLowerCase())
  );

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    await createPage.mutateAsync({ name, slugIds });
    router.push("/admin/cms/pages");
  };

  return (
    <div className="container mx-auto py-10">
      <SectionHeader title="Create Page" className="mb-6" />
      <div className="mb-6">
        <CmsDomainSelector />
      </div>
      <form onSubmit={(e) => { void handleSubmit(e); }}>
        <div className="mb-4">
          <Label htmlFor="name">Page Name</Label>
          <Input
            id="name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
          />
        </div>
        <div className="mb-4 space-y-2">
          <Label htmlFor="slug-search">Slugs</Label>
          <Input
            id="slug-search"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search slugs..."
          />
          <div className="max-h-56 space-y-2 overflow-y-auto rounded border border-border/50 bg-gray-900/40 p-2">
            {filteredSlugs.length === 0 ? (
              <p className="py-4 text-center text-xs text-gray-500">
                No slugs available for this zone.
              </p>
            ) : (
              filteredSlugs.map((slug) => {
                const checked = slugIds.includes(slug.id);
                return (
                  <label key={slug.id} className="flex items-center gap-2 text-sm text-gray-200">
                    <Checkbox
                      checked={checked}
                      onCheckedChange={() => {
                        setSlugIds((prev) =>
                          checked ? prev.filter((id) => id !== slug.id) : [...prev, slug.id]
                        );
                      }}
                    />
                    /{slug.slug}
                  </label>
                );
              })
            )}
          </div>
          <p className="text-xs text-gray-500">{slugIds.length} selected</p>
        </div>
        <Button type="submit">Create</Button>
      </form>
    </div>
  );
}

