"use client";

import { Button, Checkbox, Input, Label, SectionHeader } from "@/shared/ui";
import { useEffect, useMemo, useRef, useState } from "react";
import { useRouter, useParams } from "next/navigation";

import CmsEditorLayout from "@/features/cms/components/CmsEditorLayout";
import { CmsDomainSelector } from "@/features/cms";
import { useCmsDomainSelection } from "@/features/cms/hooks/useCmsDomainSelection";
import { useCmsAllSlugs, useCmsPage, useCmsSlugs, useUpdatePage } from "@/features/cms/hooks/useCmsQueries";
import type { Page, Slug } from "@/features/cms/types";

export default function EditPagePageLoader() {
  const { id } = useParams();
  const pageQuery = useCmsPage(id as string | undefined);

  if (pageQuery.isLoading || !pageQuery.data) {
    return <div>Loading...</div>;
  }

  return <EditPageContent initialPage={pageQuery.data} id={id as string} />;
}

function EditPageContent({ initialPage, id }: { initialPage: Page; id: string }) {
  const [page, setPage] = useState<Page>(initialPage);
  const { activeDomainId } = useCmsDomainSelection();
  const slugsQuery = useCmsSlugs(activeDomainId);
  const allSlugsQuery = useCmsAllSlugs(true);
  const [search, setSearch] = useState("");
  const [selectedSlugIds, setSelectedSlugIds] = useState<string[]>([]);
  const initializedRef = useRef(false);
  const router = useRouter();
  const updatePage = useUpdatePage();

  useEffect(() => {
    setPage(initialPage);
    initializedRef.current = false;
  }, [initialPage]);

  const allSlugs = allSlugsQuery.data ?? [];
  const domainSlugs = slugsQuery.data ?? [];
  const allSlugByValue = useMemo(() => {
    const map = new Map<string, { id: string; slug: string }>();
    allSlugs.forEach((slug) => map.set(slug.slug, { id: slug.id, slug: slug.slug }));
    return map;
  }, [allSlugs]);

  useEffect(() => {
    if (initializedRef.current) return;
    if (!allSlugs.length) return;
    const pageSlugValues = (initialPage.slugs ?? []).map((s) => s.slug.slug);
    const ids = pageSlugValues
      .map((value) => allSlugByValue.get(value)?.id)
      .filter((value): value is string => Boolean(value));
    setSelectedSlugIds(ids);
    initializedRef.current = true;
  }, [allSlugs, allSlugByValue, initialPage.slugs]);

  const domainSlugIds = useMemo(() => new Set(domainSlugs.map((slug) => slug.id)), [domainSlugs]);
  const selectedSlugs = useMemo(() => {
    const byId = new Map(allSlugs.map((slug) => [slug.id, slug]));
    const isSlug = (value: Slug | undefined): value is Slug => Boolean(value);
    return selectedSlugIds.map((idValue) => byId.get(idValue)).filter(isSlug);
  }, [allSlugs, selectedSlugIds]);

  const crossZoneSlugs = useMemo(
    () => selectedSlugs.filter((slug) => !domainSlugIds.has(slug.id)),
    [selectedSlugs, domainSlugIds]
  );

  const filteredDomainSlugs = useMemo(() => {
    const term = search.trim().toLowerCase();
    if (!term) return domainSlugs;
    return domainSlugs.filter((slug) => slug.slug.toLowerCase().includes(term));
  }, [domainSlugs, search]);

  const handleSave = async () => {
    if (!page) return;

    await updatePage.mutateAsync({
      id,
      input: { ...page, showMenu: page.showMenu ?? true, slugIds: selectedSlugIds },
    });
    router.push("/admin/cms/pages");
  };

  return (
    <CmsEditorLayout>
      <div className="mx-auto flex w-full max-w-3xl flex-col gap-6">
        <div className="flex items-center justify-between gap-4">
          <SectionHeader title={page.name} description="Manage page slugs per zone." />
          <Button onClick={() => { void handleSave(); }}>
            {updatePage.isPending ? "Saving..." : "Save"}
          </Button>
        </div>

        <div className="rounded-lg border border-border/50 bg-gray-900/40 p-4">
          <div className="mb-4">
            <CmsDomainSelector />
          </div>

          <div className="space-y-3">
            <Label htmlFor="slug-search">Slugs for this zone</Label>
            <Input
              id="slug-search"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search slugs..."
            />
            <div className="max-h-64 space-y-2 overflow-y-auto rounded border border-border/50 bg-gray-900/40 p-2">
              {filteredDomainSlugs.length === 0 ? (
                <p className="py-4 text-center text-xs text-gray-500">
                  No slugs available for this zone.
                </p>
              ) : (
                filteredDomainSlugs.map((slug) => {
                  const checked = selectedSlugIds.includes(slug.id);
                  return (
                    <label key={slug.id} className="flex items-center gap-2 text-sm text-gray-200">
                      <Checkbox
                        checked={checked}
                        onCheckedChange={() => {
                          setSelectedSlugIds((prev) =>
                            checked ? prev.filter((idValue) => idValue !== slug.id) : [...prev, slug.id]
                          );
                        }}
                      />
                      /{slug.slug}
                    </label>
                  );
                })
              )}
            </div>
            <p className="text-xs text-gray-500">{selectedSlugIds.length} selected</p>
          </div>

          {crossZoneSlugs.length > 0 ? (
            <div className="mt-6 rounded border border-amber-500/40 bg-amber-500/10 p-3">
              <p className="text-xs font-semibold uppercase tracking-wide text-amber-200">
                Cross-zone slugs
              </p>
              <p className="mt-1 text-xs text-amber-200/80">
                These slugs are not part of the current zone. Remove them or switch zones.
              </p>
              <div className="mt-3 flex flex-wrap gap-2">
                {crossZoneSlugs.map((slug) => (
                  <button
                    key={slug.id}
                    type="button"
                    onClick={() =>
                      setSelectedSlugIds((prev) => prev.filter((idValue) => idValue !== slug.id))
                    }
                    className="rounded-full border border-amber-500/40 bg-amber-500/20 px-2 py-1 text-[11px] text-amber-200"
                  >
                    /{slug.slug} ×
                  </button>
                ))}
              </div>
            </div>
          ) : null}
        </div>
      </div>
    </CmsEditorLayout>
  );
}

"use client";
import {
  Button,
  ListPanel,
  SectionHeader,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/shared/ui";
import Link from "next/link";

import { useAdminLayout } from "@/features/admin";
import { useRouter } from "next/navigation";
import { useCmsPages, useCmsSlugs, useDeletePage } from "@/features/cms/hooks/useCmsQueries";
import { CmsDomainSelector } from "@/features/cms";
import { useCmsDomainSelection } from "@/features/cms/hooks/useCmsDomainSelection";
import type { PageStatus, PageSummary, PageSlugLink } from "@/features/cms/types";
import { useMemo, useState } from "react";
import { Eye } from "lucide-react";

const STATUS_BADGE_CLASSES: Record<PageStatus, string> = {
  draft: "bg-gray-600/20 text-gray-400 border-gray-600/40",
  published: "bg-green-600/20 text-green-400 border-green-600/40",
  scheduled: "bg-amber-600/20 text-amber-400 border-amber-600/40",
};

const STATUS_LABELS: Record<PageStatus, string> = {
  draft: "Draft",
  published: "Published",
  scheduled: "Scheduled",
};

type StatusFilter = PageStatus | "all";

const STATUS_FILTERS: Array<{ label: string; value: StatusFilter }> = [
  { label: "All", value: "all" },
  { label: "Draft", value: "draft" },
  { label: "Published", value: "published" },
  { label: "Scheduled", value: "scheduled" },
];

export default function PagesPage(): React.ReactNode {
  const { setIsMenuCollapsed, setIsProgrammaticallyCollapsed } = useAdminLayout();
  const router = useRouter();
  const { activeDomainId, activeDomain } = useCmsDomainSelection();
  const pagesQuery = useCmsPages(activeDomainId);
  const slugsQuery = useCmsSlugs(activeDomainId);
  const deletePage = useDeletePage();
  const [statusFilter, setStatusFilter] = useState<StatusFilter>("all");
  const [previewSelections, setPreviewSelections] = useState<Record<string, string>>({});

  const pages = pagesQuery.data ?? [];
  const domainSlugs = slugsQuery.data ?? [];
  const domainSlugSet = useMemo(
    () => (domainSlugs.length ? new Set(domainSlugs.map((slug) => slug.slug)) : null),
    [domainSlugs]
  );
  const filteredPages = useMemo(() => {
    if (statusFilter === "all") return pages;
    return pages.filter((page: PageSummary) => (page.status ?? "draft") === statusFilter);
  }, [pages, statusFilter]);

  const handleDelete = async (id: string): Promise<void> => {
    if (window.confirm("Are you sure you want to delete this page?")) {
      await deletePage.mutateAsync(id);
    }
  };

  const handleCreatePage = (): void => {
    setIsMenuCollapsed(true);
    setIsProgrammaticallyCollapsed(true);
    router.push("/admin/cms/pages/create");
  };

  const handlePreview = (slug: string): void => {
    if (typeof window === "undefined") return;
    const protocol = window.location.protocol;
    const currentHost = window.location.host;
    const currentHostname = window.location.hostname;
    const targetHost = activeDomain?.domain ?? currentHostname;
    const resolvedHost = targetHost === currentHostname ? currentHost : targetHost;
    const path = slug.startsWith("/") ? slug : `/${slug}`;
    window.open(`${protocol}//${resolvedHost}${path}`, "_blank", "noopener,noreferrer");
  };

  return (
    <div className="container mx-auto py-10">
      <ListPanel
        header={
          <SectionHeader
            title="Pages"
            actions={
              <>
                <CmsDomainSelector />
                <Button onClick={handleCreatePage}>Create Page</Button>
              </>
            }
          />
        }
      >
        <div className="mb-4 flex flex-wrap gap-2">
          {STATUS_FILTERS.map((filter) => (
            <button
              key={filter.value}
              type="button"
              onClick={() => setStatusFilter(filter.value)}
              className={`rounded-md border px-3 py-1 text-xs font-medium transition ${
                statusFilter === filter.value
                  ? "border-blue-500 bg-blue-500/10 text-blue-300"
                  : "border-border/40 bg-gray-900/40 text-gray-400 hover:border-border/60"
              }`}
            >
              {filter.label}
            </button>
          ))}
        </div>
        <ul>
          {filteredPages.map((page: PageSummary) => {
            const status: PageStatus = page.status ?? "draft";
            const slugValues = page.slugs.map((s: PageSlugLink) => s.slug.slug);
            const outOfZone = domainSlugSet
              ? slugValues.filter((value) => !domainSlugSet.has(value))
              : [];
            const zoneSlugs = domainSlugSet
              ? slugValues.filter((value) => domainSlugSet.has(value))
              : [];
            const selectedSlugCandidate = previewSelections[page.id];
            const previewSlug = zoneSlugs.length
              ? (selectedSlugCandidate && zoneSlugs.includes(selectedSlugCandidate)
                  ? selectedSlugCandidate
                  : zoneSlugs[0])
              : null;
            const previewPath = previewSlug ? (previewSlug.startsWith("/") ? previewSlug : `/${previewSlug}`) : "";
            const previewTitle = slugsQuery.isLoading
              ? "Loading zone slugs..."
              : previewSlug
                ? `Preview ${activeDomain?.domain ?? "current"}${previewPath}`
                : "No slug in current zone";
            return (
              <li key={page.id} className="flex justify-between items-center py-2 border-b border">
                <div className="flex items-center gap-3">
                  <Link href={`/admin/cms/builder?pageId=${page.id}`}>
                    <span className="hover:underline">{page.name}</span>
                  </Link>
                  <span className={`inline-flex rounded-full border px-2 py-0.5 text-[10px] font-medium ${STATUS_BADGE_CLASSES[status]}`}>
                    {STATUS_LABELS[status]}
                  </span>
                  {page.slugs.length > 0 && (
                    <span className="text-xs text-gray-500">
                      {page.slugs.map((s: PageSlugLink) => `/${s.slug.slug}`).join(", ")}
                      {outOfZone.length > 0 && (
                        <span className="ml-2 rounded-full border border-amber-500/40 bg-amber-500/10 px-2 py-0.5 text-[10px] text-amber-300">
                          Cross-zone
                        </span>
                      )}
                    </span>
                  )}
                </div>
                <div className="flex items-center gap-3">
                  {outOfZone.length > 0 && (
                    <span className="text-xs text-amber-400">
                      Out of zone: {outOfZone.map((slug) => `/${slug}`).join(", ")}
                    </span>
                  )}
                  {zoneSlugs.length > 1 ? (
                    <Select
                      value={previewSlug ?? ""}
                      onValueChange={(value) =>
                        setPreviewSelections((prev) => ({ ...prev, [page.id]: value }))
                      }
                      disabled={slugsQuery.isLoading}
                    >
                      <SelectTrigger className="h-8 w-[170px] text-xs">
                        <SelectValue placeholder="Preview slug" />
                      </SelectTrigger>
                      <SelectContent>
                        {zoneSlugs.map((slug) => (
                          <SelectItem key={slug} value={slug}>
                            /{slug}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  ) : zoneSlugs.length === 1 ? (
                    <div className="rounded-full border border-blue-500/30 bg-blue-500/10 px-3 py-1 text-[10px] text-blue-200">
                      Preview: {activeDomain?.domain ?? "current"}/{zoneSlugs[0]}
                    </div>
                  ) : null}
                  <Button
                    variant="outline"
                    size="sm"
                    disabled={!previewSlug || slugsQuery.isLoading}
                    title={previewTitle}
                    onClick={() => {
                      if (previewSlug) handlePreview(previewSlug);
                    }}
                  >
                    <Eye className="mr-2 size-4" />
                    Preview
                  </Button>
                  <Button variant="destructive" size="sm" onClick={() => { void handleDelete(page.id); }}>
                    Delete
                  </Button>
                </div>
              </li>
            );
          })}
          {filteredPages.length === 0 && (
            <li className="py-6 text-center text-sm text-gray-500">
              No pages match this filter.
            </li>
          )}
        </ul>
      </ListPanel>
    </div>
  );
}

"use client";

import { Button, Input, Label, SectionHeader } from "@/shared/ui";
import { useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";



import { useCreateSlug } from "@/features/cms/hooks/useCmsQueries";
import { SLUG_REGEX } from "@/features/cms/validations/slug";

export default function CreateSlugPage() {
  const [slug, setSlug] = useState("");
  const [error, setError] = useState("");
  const router = useRouter();
  const searchParams = useSearchParams();
  const domainId = searchParams.get("domainId") ?? undefined;
  const createSlug = useCreateSlug();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    if (!SLUG_REGEX.test(slug)) {
      setError(
        "Invalid slug format. Use only lowercase letters, numbers, and hyphens."
      );
      return;
    }

    try {
      await createSlug.mutateAsync({ slug, domainId });
      const next = domainId ? `/admin/cms/slugs?domainId=${encodeURIComponent(domainId)}` : "/admin/cms/slugs";
      router.push(next);
    } catch (err) {
      setError(err instanceof Error ? err.message : "An unexpected error occurred.");
    }
  };

  return (
    <div className="container mx-auto py-10">
      <SectionHeader title="Create Slug" className="mb-6" />
      <form onSubmit={(e) => void handleSubmit(e)}>
        <div className="mb-4">
          <Label htmlFor="slug">Slug</Label>
          <Input
            id="slug"
            value={slug}
            onChange={(e) => setSlug(e.target.value)}
            placeholder="e.g., my-awesome-page"
            required
          />
          {error && <p className="text-red-500 text-sm mt-1">{error}</p>}
        </div>
        <Button type="submit">Create</Button>
      </form>
    </div>
  );
}

"use client";

import { Button, Input, Label, Switch, SectionHeader } from "@/shared/ui";
import { useState } from "react";
import { useRouter, useParams, useSearchParams } from "next/navigation";




import { useCmsSlug, useUpdateSlug } from "@/features/cms/hooks/useCmsQueries";
import type { Slug } from "@/features/cms/types";

export default function EditSlugPageLoader() {
  const params = useParams();
  const id = params.id as string;
  const searchParams = useSearchParams();
  const domainId = searchParams.get("domainId") ?? undefined;
  const slugQuery = useCmsSlug(id, domainId);

  if (slugQuery.isLoading || !slugQuery.data) {
    return <div>Loading...</div>;
  }

  return <EditSlugForm initialSlug={slugQuery.data} id={id} domainId={domainId} />;
}

function EditSlugForm({
  initialSlug,
  id,
  domainId,
}: {
  initialSlug: Slug;
  id: string;
  domainId?: string;
}) {
  const [slug, setSlug] = useState<Slug>(initialSlug);
  const router = useRouter();
  const updateSlug = useUpdateSlug();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!slug) return;

    await updateSlug.mutateAsync({ id, input: slug, domainId });
    const next = domainId ? `/admin/cms/slugs?domainId=${encodeURIComponent(domainId)}` : "/admin/cms/slugs";
    router.push(next);
  };

  return (
    <div className="container mx-auto py-10">
      <SectionHeader title="Edit Slug" className="mb-6" />
      <form onSubmit={(e) => { void handleSubmit(e); }}>
        <div className="mb-4">
          <Label htmlFor="slug">Slug</Label>
          <Input
            id="slug"
            value={slug.slug}
            onChange={(e) => setSlug({ ...slug, slug: e.target.value })}
            required
          />
        </div>
        <div className="mb-4 flex items-center">
          <Switch
            id="isDefault"
            checked={Boolean(slug.isDefault)}
            onCheckedChange={(checked) => setSlug({ ...slug, isDefault: checked })}
          />
          <Label htmlFor="isDefault" className="ml-2">
            Set as default
          </Label>
        </div>
        <Button type="submit">Update</Button>
      </form>
    </div>
  );
}

"use client";

import { useMemo, useState } from "react";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import {
  Button,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  ListPanel,
  SectionHeader,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Input,
  Label,
  Checkbox,
  Switch,
} from "@/shared/ui";
import Link from "next/link";

import {
  useCmsAllSlugs,
  useCmsSlugs,
  useCreateSlug,
  useDeleteSlug,
} from "@/features/cms/hooks/useCmsQueries";
import { useCmsDomainSelection } from "@/features/cms/hooks/useCmsDomainSelection";
import { useSettingsMap, useUpdateSetting } from "@/shared/hooks/useSettings";
import { parseJsonSetting, serializeSetting } from "@/shared/utils/settings-json";
import { CMS_DOMAIN_SETTINGS_KEY, normalizeCmsDomainSettings } from "@/features/cms/types/domain-settings";

export default function SlugsPage() {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const domainIdParam = searchParams.get("domainId") ?? undefined;
  const {
    domains,
    activeDomainId,
    hostDomainId,
    canonicalDomain,
    sharedWithDomains,
    setActiveDomainId,
    zoningEnabled,
  } = useCmsDomainSelection({ initialDomainId: domainIdParam ?? null });
  const settingsQuery = useSettingsMap();
  const updateSetting = useUpdateSetting();
  const domainSettings = useMemo(
    () =>
      normalizeCmsDomainSettings(
        parseJsonSetting(settingsQuery.data?.get(CMS_DOMAIN_SETTINGS_KEY), null)
      ),
    [settingsQuery.data]
  );
  const zoningToggleValue = domainSettings.zoningEnabled;
  const [attachOpen, setAttachOpen] = useState(false);
  const [attachSelectedIds, setAttachSelectedIds] = useState<string[]>([]);
  const [attachSearch, setAttachSearch] = useState("");
  const [attachError, setAttachError] = useState("");
  const slugsQuery = useCmsSlugs(activeDomainId);
  const allSlugsQuery = useCmsAllSlugs(attachOpen);
  const createSlug = useCreateSlug();
  const deleteSlug = useDeleteSlug();
  const slugs = slugsQuery.data ?? [];
  const allSlugs = allSlugsQuery.data ?? [];

  const handleDomainChange = (value: string): void => {
    const params = new URLSearchParams(searchParams.toString());
    if (value) {
      params.set("domainId", value);
    } else {
      params.delete("domainId");
    }
    const next = params.toString();
    router.replace(next ? `${pathname}?${next}` : pathname);
    setActiveDomainId(value || null);
  };

  const handleZoningToggle = (checked: boolean): void => {
    const next = normalizeCmsDomainSettings({ ...domainSettings, zoningEnabled: checked });
    updateSetting.mutate({ key: CMS_DOMAIN_SETTINGS_KEY, value: serializeSetting(next) });
  };

  const buildDomainHref = useMemo(() => {
    return (href: string) =>
      activeDomainId ? `${href}?domainId=${encodeURIComponent(activeDomainId)}` : href;
  }, [activeDomainId]);

  const availableAttachSlugs = useMemo(() => {
    const assigned = new Set(slugs.map((slug) => slug.id));
    const base = allSlugs.filter((slug) => !assigned.has(slug.id));
    const term = attachSearch.trim().toLowerCase();
    if (!term) return base;
    return base.filter((slug) => slug.slug.toLowerCase().includes(term));
  }, [allSlugs, slugs, attachSearch]);

  const selectedAttachCount = useMemo(() => attachSelectedIds.length, [attachSelectedIds]);

  const toggleAttachSelection = (slugId: string) => {
    setAttachSelectedIds((prev) =>
      prev.includes(slugId) ? prev.filter((id) => id !== slugId) : [...prev, slugId]
    );
  };

  const selectAllVisible = () => {
    const visibleIds = availableAttachSlugs.map((slug) => slug.id);
    setAttachSelectedIds((prev) => Array.from(new Set([...prev, ...visibleIds])));
  };

  const clearSelection = () => {
    setAttachSelectedIds([]);
  };

  const handleAttach = async (): Promise<void> => {
    if (!attachSelectedIds.length) {
      setAttachError("Select at least one slug to attach.");
      return;
    }
    const selected = allSlugs.filter((item) => attachSelectedIds.includes(item.id));
    if (!selected.length) {
      setAttachError("Selected slugs are no longer available.");
      return;
    }
    setAttachError("");
    for (const slug of selected) {
      await createSlug.mutateAsync({ slug: slug.slug, domainId: activeDomainId });
    }
    setAttachSelectedIds([]);
    setAttachSearch("");
    setAttachOpen(false);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Are you sure you want to delete this slug?")) {
      await deleteSlug.mutateAsync({ id, domainId: activeDomainId });
    }
  };

  return (
    <div className="container mx-auto py-10">
      <ListPanel
        header={
          <SectionHeader
            title="Slugs"
            actions={
              <>
                <div className="flex items-center gap-2 rounded-md border border-border/60 bg-background/40 px-2 py-1">
                  <Switch
                    id="cms-domain-zoning"
                    checked={zoningToggleValue}
                    onCheckedChange={handleZoningToggle}
                    disabled={updateSetting.isPending}
                  />
                  <Label htmlFor="cms-domain-zoning" className="text-xs text-muted-foreground">
                    Domain zoning
                  </Label>
                </div>
                {zoningEnabled ? (
                  <Select value={activeDomainId} onValueChange={handleDomainChange}>
                    <SelectTrigger className="h-9 w-[220px]">
                      <SelectValue placeholder="Current domain" />
                    </SelectTrigger>
                    <SelectContent>
                      {domains.map((item) => (
                        <SelectItem key={item.id} value={item.id}>
                          {item.domain}
                          {hostDomainId === item.id ? " (current)" : ""}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                ) : (
                  <span className="text-xs text-muted-foreground">Simple routing</span>
                )}
                <Dialog
                  open={attachOpen}
                  onOpenChange={(open) => {
                    setAttachOpen(open);
                    if (!open) {
                      setAttachSelectedIds([]);
                      setAttachSearch("");
                      setAttachError("");
                    }
                  }}
                >
                  {zoningEnabled ? (
                    <DialogTrigger asChild>
                      <Button variant="secondary">Attach Existing</Button>
                    </DialogTrigger>
                  ) : null}
                  <DialogContent>
                    <DialogHeader>
                      <DialogTitle>Attach Existing Slug</DialogTitle>
                      <DialogDescription>
                        Link an existing slug to this zone without creating a new one.
                      </DialogDescription>
                    </DialogHeader>
                    <div className="space-y-3">
                      <div className="space-y-1">
                        <Label htmlFor="attach-search">Search</Label>
                        <Input
                          id="attach-search"
                          value={attachSearch}
                          onChange={(event) => setAttachSearch(event.target.value)}
                          placeholder="Search slugs..."
                        />
                      </div>
                      <div className="space-y-2">
                        <div className="flex items-center justify-between">
                          <Label>Available slugs</Label>
                          <div className="flex items-center gap-2 text-xs text-muted-foreground">
                            <button
                              type="button"
                              className="hover:text-foreground"
                              onClick={selectAllVisible}
                            >
                              Select all
                            </button>
                            <span>•</span>
                            <button
                              type="button"
                              className="hover:text-foreground"
                              onClick={clearSelection}
                            >
                              Clear
                            </button>
                          </div>
                        </div>
                        <div className="max-h-56 overflow-y-auto rounded-md border border-border/60 bg-background/40 p-2">
                          {allSlugsQuery.isLoading ? (
                            <p className="py-6 text-center text-sm text-muted-foreground">
                              Loading slugs…
                            </p>
                          ) : availableAttachSlugs.length === 0 ? (
                            <p className="py-6 text-center text-sm text-muted-foreground">
                              No available slugs to attach.
                            </p>
                          ) : (
                            <ul className="space-y-2">
                              {availableAttachSlugs.map((slug) => (
                                <li key={slug.id} className="flex items-center gap-2">
                                  <Checkbox
                                    checked={attachSelectedIds.includes(slug.id)}
                                    onCheckedChange={() => toggleAttachSelection(slug.id)}
                                  />
                                  <span className="text-sm">/{slug.slug}</span>
                                </li>
                              ))}
                            </ul>
                          )}
                        </div>
                        <p className="text-xs text-muted-foreground">
                          {selectedAttachCount} selected
                        </p>
                        {attachError ? (
                          <p className="text-sm text-red-500">{attachError}</p>
                        ) : null}
                      </div>
                    </div>
                    <DialogFooter>
                      <Button
                        variant="secondary"
                        onClick={() => {
                          setAttachOpen(false);
                          setAttachSelectedIds([]);
                          setAttachSearch("");
                          setAttachError("");
                        }}
                      >
                        Cancel
                      </Button>
                      <Button
                        onClick={() => { void handleAttach(); }}
                        disabled={selectedAttachCount === 0}
                      >
                        Attach
                      </Button>
                    </DialogFooter>
                  </DialogContent>
                </Dialog>
                <Button asChild>
                  <Link href={buildDomainHref("/admin/cms/slugs/create")}>Create Slug</Link>
                </Button>
              </>
            }
          />
        }
      >
        <ul>
          {slugs.map((slug) => (
            <li
              key={slug.id}
              className="flex justify-between items-center py-2 border-b border"
            >
              <Link href={buildDomainHref(`/admin/cms/slugs/${slug.id}/edit`)} className="flex flex-col">
                <span className="hover:underline">
                  /{slug.slug} {slug.isDefault && "(Default)"}
                  {(canonicalDomain || sharedWithDomains.length > 0) ? (
                    <span className="ml-2 rounded-full bg-foreground/10 px-2 py-0.5 text-[11px] text-foreground/70">
                      Shared
                    </span>
                  ) : null}
                </span>
                {canonicalDomain ? (
                  <span className="text-xs text-muted-foreground">
                    Shared from {canonicalDomain.domain}
                  </span>
                ) : sharedWithDomains.length > 0 ? (
                  <span className="text-xs text-muted-foreground">
                    Shared with {sharedWithDomains.map((item) => item.domain).join(", ")}
                  </span>
                ) : null}
              </Link>
              <Button
                variant="destructive"
                onClick={() => void handleDelete(slug.id)}
              >
                Delete
              </Button>
            </li>
          ))}
        </ul>
      </ListPanel>
    </div>
  );
}

"use client";

import { useState } from "react";
import {
  Button,
  Input,
  Label,
  ListPanel,
  SectionHeader,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/shared/ui";
import {
  useCmsDomains,
  useCreateCmsDomain,
  useDeleteCmsDomain,
  useUpdateCmsDomain,
} from "@/features/cms/hooks/useCmsQueries";

export default function ZonesPage() {
  const domainsQuery = useCmsDomains();
  const createDomain = useCreateCmsDomain();
  const deleteDomain = useDeleteCmsDomain();
  const updateDomain = useUpdateCmsDomain();
  const domains = domainsQuery.data ?? [];
  const [domain, setDomain] = useState("");
  const [error, setError] = useState("");

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const value = domain.trim();
    if (!value) {
      setError("Enter a domain or hostname.");
      return;
    }
    setError("");
    try {
      await createDomain.mutateAsync({ domain: value });
      setDomain("");
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to create domain.");
    }
  };

  const handleDelete = async (id: string): Promise<void> => {
    if (!confirm("Remove this domain and its slug assignments?")) return;
    await deleteDomain.mutateAsync(id);
  };

  const handleAliasChange = async (id: string, aliasOfValue: string) => {
    const aliasOf = aliasOfValue === "none" ? null : aliasOfValue;
    await updateDomain.mutateAsync({ id, input: { aliasOf } });
  };

  return (
    <div className="container mx-auto py-10">
      <ListPanel
        header={
          <SectionHeader
            title="Zones (Domains)"
            description="Zones scope CMS slugs per hostname. Domains are auto-created on first request; add here to pre-provision or share slug sets."
          />
        }
      >
        <form
          onSubmit={(event) => { void handleSubmit(event); }}
          className="flex flex-col gap-3 border-b border-border px-4 py-4 sm:flex-row sm:items-end"
        >
          <div className="flex-1">
            <Label htmlFor="domain">Domain</Label>
            <Input
              id="domain"
              value={domain}
              onChange={(event) => setDomain(event.target.value)}
              placeholder="milkbar.com"
              autoComplete="off"
            />
            {error ? <p className="mt-1 text-sm text-red-500">{error}</p> : null}
          </div>
          <Button type="submit" size="sm">
            Add Zone
          </Button>
        </form>

        {domains.length === 0 ? (
          <p className="py-8 text-center text-sm text-gray-500">
            No zones yet. Create one or visit a domain to auto-register it.
          </p>
        ) : (
          <ul className="divide-y divide-border">
            {domains.map((item) => (
              <li key={item.id} className="flex items-center justify-between px-4 py-3">
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-medium">{item.domain}</span>
                  {item.aliasOf ? (
                    <span className="text-xs text-muted-foreground">
                      Shares slugs with {domains.find((d) => d.id === item.aliasOf)?.domain ?? "another zone"}
                    </span>
                  ) : (
                    <span className="text-xs text-muted-foreground">Independent zone</span>
                  )}
                </div>
                <div className="flex items-center gap-2">
                  <Select
                    value={item.aliasOf ?? "none"}
                    onValueChange={(value) => { void handleAliasChange(item.id, value); }}
                  >
                    <SelectTrigger className="h-8 w-[220px]">
                      <SelectValue placeholder="Independent zone" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="none">Independent zone</SelectItem>
                      {domains
                        .filter((domainOption) => domainOption.id !== item.id)
                        .map((domainOption) => (
                          <SelectItem key={domainOption.id} value={domainOption.id}>
                            Share with {domainOption.domain}
                          </SelectItem>
                        ))}
                    </SelectContent>
                  </Select>
                  <Button
                    size="sm"
                    variant="destructive"
                    onClick={() => { void handleDelete(item.id); }}
                  >
                    Delete
                  </Button>
                </div>
              </li>
            ))}
          </ul>
        )}
      </ListPanel>
    </div>
  );
}

import "server-only";

import type { NextRequest } from "next/server";
import { randomUUID } from "crypto";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import prisma from "@/shared/lib/db/prisma";
import type { CmsRepository } from "@/features/cms/types/services/cms-repository";
import type { CmsDomain, Slug } from "@/features/cms/types";
import { getCmsDataProvider } from "@/features/cms/services/cms-provider";
import { getCmsDomainSettings } from "@/features/cms/services/cms-domain-settings";

type CmsDomainRecord = {
  id: string;
  domain: string;
  aliasOf?: string | null;
  createdAt: Date;
  updatedAt: Date;
};

export type CmsDomainResponse = {
  id: string;
  domain: string;
  aliasOf?: string | null;
  createdAt?: string;
  updatedAt?: string;
};

type CmsDomainSlugLink = {
  domainId: string;
  slugId: string;
  isDefault?: boolean;
  assignedAt: Date;
  updatedAt?: Date;
};

const DOMAIN_COLLECTION = "cms_domains";
const DOMAIN_SLUGS_COLLECTION = "cms_domain_slugs";
const SLUGS_COLLECTION = "cms_slugs";

type SlugDocument = {
  id: string;
  isDefault?: boolean;
  updatedAt?: Date;
};

const getFallbackDomain = (): string => {
  const url =
    process.env.NEXT_PUBLIC_APP_URL ||
    process.env.NEXTAUTH_URL ||
    "http://localhost";
  try {
    return new URL(url).hostname.toLowerCase();
  } catch {
    return "default";
  }
};

const buildDefaultDomain = (hostHeader: string | null): CmsDomain => ({
  id: "default-domain",
  domain: normalizeHost(hostHeader),
  createdAt: new Date(),
  updatedAt: new Date(),
});

const normalizeHost = (hostHeader: string | null): string => {
  if (!hostHeader) return getFallbackDomain();
  const raw = hostHeader.split(",")[0]?.trim() ?? "";
  if (!raw) return getFallbackDomain();
  try {
    return new URL(`http://${raw}`).hostname.toLowerCase();
  } catch {
    return raw.toLowerCase();
  }
};

const getHostFromRequest = (req: NextRequest): string | null =>
  req.headers.get("x-forwarded-host") ?? req.headers.get("host");

const getHostFromHeaders = (headers: Headers): string | null =>
  headers.get("x-forwarded-host") ?? headers.get("host");

const canUsePrismaSlugs = (): boolean =>
  Boolean(process.env.DATABASE_URL) && "slug" in prisma;

export async function isDomainZoningEnabled(): Promise<boolean> {
  if (!process.env.MONGODB_URI) return false;
  const settings = await getCmsDomainSettings();
  return settings.zoningEnabled;
}

export async function setGlobalDefaultSlug(slugId: string | null): Promise<void> {
  const provider = await getCmsDataProvider();
  if (provider === "mongodb") {
    if (!process.env.MONGODB_URI) return;
    const db = await getMongoDb();
    const now = new Date();
    await db.collection<SlugDocument>(SLUGS_COLLECTION).updateMany(
      {},
      { $set: { isDefault: false, updatedAt: now } }
    );
    if (!slugId) return;
    await db.collection<SlugDocument>(SLUGS_COLLECTION).updateOne(
      { id: slugId },
      { $set: { isDefault: true, updatedAt: now } }
    );
    return;
  }
  if (!canUsePrismaSlugs()) return;
  await prisma.slug.updateMany({ data: { isDefault: false } });
  if (!slugId) return;
  try {
    await prisma.slug.update({ where: { id: slugId }, data: { isDefault: true } });
  } catch {
    // Ignore missing slug
  }
}

export async function resolveCmsDomainFromRequest(req: NextRequest): Promise<CmsDomain> {
  const host = getHostFromRequest(req);
  return resolveCmsDomainByHost(host);
}

export async function resolveCmsDomainFromHeaders(headers: Headers): Promise<CmsDomain> {
  const host = getHostFromHeaders(headers);
  return resolveCmsDomainByHost(host);
}

const getDomainRecordById = async (domainId: string): Promise<CmsDomainRecord | null> => {
  if (!process.env.MONGODB_URI) return null;
  const db = await getMongoDb();
  return db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .findOne({ id: domainId });
};

export async function resolveCmsDomainScopeById(domainId: string): Promise<CmsDomain | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return buildDefaultDomain(null);
  }
  let current = await getDomainRecordById(domainId);
  if (!current) return null;
  const visited = new Set<string>([current.id]);
  while (current.aliasOf) {
    if (visited.has(current.aliasOf)) break;
    const next = await getDomainRecordById(current.aliasOf);
    if (!next) break;
    visited.add(next.id);
    current = next;
  }
  return current;
}

export async function resolveCmsDomainByHost(hostHeader: string | null): Promise<CmsDomain> {
  const domain = normalizeHost(hostHeader);
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return buildDefaultDomain(hostHeader);
  }

  const db = await getMongoDb();
  const existing = await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .findOne({ domain });
  if (existing) {
    const scoped = await resolveCmsDomainScopeById(existing.id);
    return scoped ?? existing;
  }

  const now = new Date();
  const doc: CmsDomainRecord = {
    id: randomUUID(),
    domain,
    aliasOf: null,
    createdAt: now,
    updatedAt: now,
  };
  await db.collection<CmsDomainRecord>(DOMAIN_COLLECTION).insertOne(doc);
  return doc;
}

export async function getCmsDomainById(domainId: string): Promise<CmsDomain | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return buildDefaultDomain(null);
  }
  const doc = await getDomainRecordById(domainId);
  return doc ?? null;
}

export async function getDomainSlugLinks(domainId: string): Promise<CmsDomainSlugLink[]> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return [];
  const db = await getMongoDb();
  return db
    .collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION)
    .find({ domainId })
    .toArray();
}

const toDomainResponse = (doc: CmsDomainRecord): CmsDomainResponse => ({
  id: doc.id,
  domain: doc.domain,
  aliasOf: doc.aliasOf ?? undefined,
  createdAt: doc.createdAt?.toISOString?.() ?? undefined,
  updatedAt: doc.updatedAt?.toISOString?.() ?? undefined,
});

export async function listCmsDomains(): Promise<CmsDomainResponse[]> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return [];
  const db = await getMongoDb();
  const docs = await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .find()
    .sort({ domain: 1 })
    .toArray();
  return docs.map((doc) => toDomainResponse(doc));
}

export async function createCmsDomain(domain: string): Promise<CmsDomainResponse> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return { id: "default-domain", domain: normalizeHost(domain) };
  }
  const db = await getMongoDb();
  const normalized = normalizeHost(domain);
  const existing = await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .findOne({ domain: normalized });
  if (existing) return toDomainResponse(existing);
  const now = new Date();
  const doc: CmsDomainRecord = {
    id: randomUUID(),
    domain: normalized,
    aliasOf: null,
    createdAt: now,
    updatedAt: now,
  };
  await db.collection<CmsDomainRecord>(DOMAIN_COLLECTION).insertOne(doc);
  return toDomainResponse(doc);
}

export async function deleteCmsDomain(domainId: string): Promise<void> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return;
  const db = await getMongoDb();
  await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .updateMany(
      { aliasOf: domainId },
      { $set: { aliasOf: null, updatedAt: new Date() } }
    );
  await db.collection<CmsDomainRecord>(DOMAIN_COLLECTION).deleteOne({ id: domainId });
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).deleteMany({ domainId });
}

export async function setCmsDomainAlias(domainId: string, aliasOf: string | null): Promise<CmsDomainResponse | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return null;
  if (aliasOf === domainId) aliasOf = null;
  const db = await getMongoDb();
  const domain = await getDomainRecordById(domainId);
  if (!domain) return null;

  let targetId: string | null = aliasOf;
  if (aliasOf) {
    const canonical = await resolveCmsDomainScopeById(aliasOf);
    targetId = canonical?.id ?? null;
  }

  // Keep existing links so removing the alias restores the previous slug set.

  const updatedAt = new Date();
  await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .updateOne(
      { id: domainId },
      { $set: { aliasOf: targetId ?? null, updatedAt } }
    );
  return toDomainResponse({
    ...domain,
    aliasOf: targetId ?? null,
    updatedAt,
  });
}

export async function isSlugAssignedToDomain(domainId: string, slugId: string): Promise<boolean> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return true;
  const db = await getMongoDb();
  const doc = await db
    .collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION)
    .findOne({ domainId, slugId });
  return Boolean(doc);
}

export async function ensureDomainSlug(domainId: string, slugId: string): Promise<void> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return;
  const db = await getMongoDb();
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).updateOne(
    { domainId, slugId },
    {
      $setOnInsert: {
        domainId,
        slugId,
        isDefault: false,
        assignedAt: new Date(),
      },
      $set: { updatedAt: new Date() },
    },
    { upsert: true }
  );
}

export async function removeDomainSlug(domainId: string, slugId: string): Promise<void> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return;
  const db = await getMongoDb();
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).deleteOne({ domainId, slugId });
}

export async function setDomainDefaultSlug(domainId: string, slugId: string | null): Promise<void> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return;
  const db = await getMongoDb();
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).updateMany(
    { domainId },
    { $set: { isDefault: false, updatedAt: new Date() } }
  );
  if (!slugId) return;
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).updateOne(
    { domainId, slugId },
    {
      $set: { isDefault: true, updatedAt: new Date() },
      $setOnInsert: { domainId, slugId, assignedAt: new Date() },
    },
    { upsert: true }
  );
}

export async function isSlugLinkedToAnyDomain(slugId: string): Promise<boolean> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return false;
  const db = await getMongoDb();
  const count = await db
    .collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION)
    .countDocuments({ slugId }, { limit: 1 });
  return count > 0;
}

export async function getSlugsForDomain(domainId: string, repo: CmsRepository): Promise<Slug[]> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return repo.getSlugs();
  }
  const links = await getDomainSlugLinks(domainId);
  if (!links.length) return [];
  const map = new Map(links.map((link) => [link.slugId, link]));
  const slugs = await repo.getSlugs();
  return slugs
    .filter((slug) => map.has(slug.id))
    .map((slug) => ({
      ...slug,
      isDefault: map.get(slug.id)?.isDefault ?? false,
    }));
}

export async function getSlugForDomainById(
  domainId: string,
  slugId: string,
  repo: CmsRepository
): Promise<Slug | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return repo.getSlugById(slugId);
  }
  const slug = await repo.getSlugById(slugId);
  if (!slug) return null;
  const links = await getDomainSlugLinks(domainId);
  const link = links.find((item) => item.slugId === slugId);
  if (!link && process.env.MONGODB_URI) return null;
  return {
    ...slug,
    isDefault: link?.isDefault ?? false,
  };
}

export async function getSlugForDomainByValue(
  domainId: string,
  slugValue: string,
  repo: CmsRepository
): Promise<Slug | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return repo.getSlugByValue(slugValue);
  }
  const slug = await repo.getSlugByValue(slugValue);
  if (!slug) return null;
  const isAllowed = await isSlugAssignedToDomain(domainId, slug.id);
  if (!isAllowed) return null;
  const links = await getDomainSlugLinks(domainId);
  const link = links.find((item) => item.slugId === slug.id);
  return {
    ...slug,
    isDefault: link?.isDefault ?? false,
  };
}

import "server-only";

import { randomUUID } from "crypto";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import type { Filter } from "mongodb";
import { ObjectId } from "mongodb";
import type { CmsRepository, PageUpdateData } from "../../types/services/cms-repository";
import type { Page, Slug, PageComponent, CmsTheme, CmsThemeCreateInput, CmsThemeUpdateInput } from "../../types";

const pagesCollection = "cms_pages";
const slugsCollection = "cms_slugs";
const themesCollection = "cms_themes";

interface PageDocument {
  id: string;
  name: string;
  status: string;
  publishedAt?: Date | null;
  seoTitle?: string | null;
  seoDescription?: string | null;
  seoOgImage?: string | null;
  seoCanonical?: string | null;
  robotsMeta?: string | null;
  themeId?: string | null;
  showMenu?: boolean;
  components: PageComponent[];
  createdAt: Date;
  updatedAt: Date;
}

interface ThemeDocument {
  id: string;
  name: string;
  colors: Record<string, string>;
  typography: Record<string, unknown>;
  spacing: Record<string, string>;
  customCss?: string | null;
  createdAt: Date;
  updatedAt: Date;
}

interface SlugDocument {
  id: string;
  slug: string;
  isDefault: boolean;
  createdAt: Date;
  updatedAt: Date;
}

interface PageSlugDocument {
  pageId: string;
  slugId: string;
  assignedAt: Date;
}

// Helper to remove undefined keys for exactOptionalPropertyTypes compliance
function removeUndefined<T extends object>(obj: T): T {
  const newObj = { ...obj };
  Object.keys(newObj).forEach((key) => {
    if (newObj[key as keyof T] === undefined) {
      delete newObj[key as keyof T];
    }
  });
  return newObj;
}

function buildIdFilter<T extends { id: string }>(id: string): Filter<T> {
  const orFilters: Filter<T>[] = [{ id } as Filter<T>];

  if (ObjectId.isValid(id)) {
    orFilters.push({ _id: new ObjectId(id) } as Filter<T>);
  }

  return { $or: orFilters } as Filter<T>;
}

function normalizeShowMenu(value: unknown): boolean {
  if (value === false) return false;
  if (value === true) return true;
  if (typeof value === "string") {
    const normalized = value.trim().toLowerCase();
    if (["false", "0", "no", "off"].includes(normalized)) return false;
    if (["true", "1", "yes", "on"].includes(normalized)) return true;
  }
  return true;
}

export const mongoCmsRepository: CmsRepository = {
  // Pages
  async getPages(): Promise<Page[]> {
    const db = await getMongoDb();
    const docs = await db.collection<PageDocument>(pagesCollection).find().sort({ createdAt: -1 }).toArray();

    return Promise.all(docs.map(async doc => {
      const pageId = doc.id;
      const slugLinks = await db.collection<PageSlugDocument>("cms_page_slugs").find({ pageId }).toArray();
      const slugIds = slugLinks.map(link => link.slugId);
      const slugs = await db.collection<SlugDocument>(slugsCollection).find({ id: { $in: slugIds } }).toArray();

      return {
        id: pageId,
        name: doc.name,
        status: doc.status || "draft",
        publishedAt: doc.publishedAt?.toISOString(),
        seoTitle: doc.seoTitle ?? undefined,
        seoDescription: doc.seoDescription ?? undefined,
        seoOgImage: doc.seoOgImage ?? undefined,
        seoCanonical: doc.seoCanonical ?? undefined,
        robotsMeta: doc.robotsMeta ?? "index,follow",
        showMenu: normalizeShowMenu(doc.showMenu),
        components: doc.components || [],
        slugs: slugs.map(s => ({ slug: { slug: s.slug } })),
      } as Page;
    }));
  },

  async getPageById(id: string): Promise<Page | null> {
    const db = await getMongoDb();
    const doc = await db.collection<PageDocument>(pagesCollection).findOne(buildIdFilter<PageDocument>(id));
    if (!doc) return null;

    const pageId = doc.id;
    const slugLinks = await db.collection<PageSlugDocument>("cms_page_slugs").find({ pageId }).toArray();
    const slugIds = slugLinks.map(link => link.slugId);
    const slugs = await db.collection<SlugDocument>(slugsCollection).find({ id: { $in: slugIds } }).toArray();

    return {
      id: pageId,
      name: doc.name,
      status: doc.status || "draft",
      publishedAt: doc.publishedAt?.toISOString(),
      seoTitle: doc.seoTitle ?? undefined,
      seoDescription: doc.seoDescription ?? undefined,
      seoOgImage: doc.seoOgImage ?? undefined,
      seoCanonical: doc.seoCanonical ?? undefined,
      robotsMeta: doc.robotsMeta ?? "index,follow",
      showMenu: normalizeShowMenu(doc.showMenu),
      components: doc.components || [],
      slugs: slugs.map(s => ({ slug: { slug: s.slug } })),
    } as Page;
  },

  async getPageBySlug(slugValue: string): Promise<Page | null> {
    const db = await getMongoDb();
    const slugDoc = await db.collection<SlugDocument>(slugsCollection).findOne({ slug: slugValue });
    if (!slugDoc) return null;
    const pageSlug = await db.collection<PageSlugDocument>("cms_page_slugs").findOne({ slugId: slugDoc.id });
    if (!pageSlug) return null;
    return this.getPageById(pageSlug.pageId);
  },

  async createPage(data: { name: string }): Promise<Page> {
    const db = await getMongoDb();
    const id = randomUUID();
    const doc: PageDocument = {
      id,
      name: data.name,
      status: "draft",
      showMenu: true,
      components: [],
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    await db.collection<PageDocument>(pagesCollection).insertOne(doc);
    return { id, name: doc.name, status: "draft", showMenu: true, components: [] } as Page;
  },

  async updatePage(id: string, data: PageUpdateData): Promise<Page | null> {
    const db = await getMongoDb();
    const update = removeUndefined({
      name: data.name,
      status: data.status,
      publishedAt: data.publishedAt !== undefined ? (data.publishedAt ? new Date(data.publishedAt) : null) : undefined,
      seoTitle: data.seoTitle,
      seoDescription: data.seoDescription,
      seoOgImage: data.seoOgImage,
      seoCanonical: data.seoCanonical,
      robotsMeta: data.robotsMeta,
      themeId: data.themeId,
      showMenu: data.showMenu,
      components: data.components,
      updatedAt: new Date(),
    }) as Partial<PageDocument>;

    const result = await db.collection<PageDocument>(pagesCollection).findOneAndUpdate(
      buildIdFilter<PageDocument>(id),
      { $set: update },
      { returnDocument: "after" }
    );
    if (!result) return null;
    return this.getPageById(id);
  },

  async deletePage(id: string): Promise<Page | null> {
    const db = await getMongoDb();
    const doc = await db.collection<PageDocument>(pagesCollection).findOneAndDelete(buildIdFilter<PageDocument>(id));
    if (!doc) return null;
    const deleted = doc;

    // Also cleanup relationships
    await db.collection("cms_page_slugs").deleteMany({ pageId: id });

    return {
      id: deleted.id,
      name: deleted.name,
      components: deleted.components || [],
    } as Page;
  },

  async replacePageSlugs(pageId: string, slugIds: string[]): Promise<void> {
    const db = await getMongoDb();
    await db.collection("cms_page_slugs").deleteMany({ pageId });
    if (slugIds.length === 0) return;
    await db.collection<PageSlugDocument>("cms_page_slugs").insertMany(
      slugIds.map((slugId) => ({ pageId, slugId, assignedAt: new Date() }))
    );
  },

  async replacePageComponents(pageId: string, components: PageComponent[]): Promise<void> {
    const db = await getMongoDb();
    await db.collection<PageDocument>(pagesCollection).updateOne(
      buildIdFilter<PageDocument>(pageId),
      { $set: { components, updatedAt: new Date() } }
    );
  },

  // Slugs
  async getSlugs(): Promise<Slug[]> {
    const db = await getMongoDb();
    const docs = await db.collection<SlugDocument>(slugsCollection).find().sort({ createdAt: -1 }).toArray();
    return docs.map(doc => ({
      id: doc.id,
      slug: doc.slug,
      isDefault: doc.isDefault,
      createdAt: doc.createdAt.toISOString(),
    })) as Slug[];
  },

  async getSlugById(id: string): Promise<Slug | null> {
    const db = await getMongoDb();
    const doc = await db.collection<SlugDocument>(slugsCollection).findOne(buildIdFilter<SlugDocument>(id));
    if (!doc) return null;
    return {
      id: doc.id,
      slug: doc.slug,
      isDefault: doc.isDefault,
      createdAt: doc.createdAt.toISOString(),
    } as Slug;
  },

  async getSlugByValue(slugValue: string): Promise<Slug | null> {
    const db = await getMongoDb();
    const doc = await db.collection<SlugDocument>(slugsCollection).findOne({ slug: slugValue });
    if (!doc) return null;
    return {
      id: doc.id,
      slug: doc.slug,
      isDefault: doc.isDefault,
      createdAt: doc.createdAt.toISOString(),
    } as Slug;
  },

  async createSlug(data: { slug: string; isDefault?: boolean | undefined }): Promise<Slug> {
    const db = await getMongoDb();
    const id = randomUUID();
    const doc: SlugDocument = {
      id,
      slug: data.slug,
      isDefault: data.isDefault || false,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    await db.collection<SlugDocument>(slugsCollection).insertOne(doc);
    return {
      id,
      slug: doc.slug,
      isDefault: doc.isDefault,
      createdAt: doc.createdAt.toISOString(),
    } as Slug;
  },

  async updateSlug(id: string, data: { slug?: string | undefined; isDefault?: boolean | undefined }): Promise<Slug | null> {
    const db = await getMongoDb();
    const update = removeUndefined({
      slug: data.slug,
      isDefault: data.isDefault,
      updatedAt: new Date(),
    }) as Partial<SlugDocument>;

    const result = await db.collection<SlugDocument>(slugsCollection).findOneAndUpdate(
      buildIdFilter<SlugDocument>(id),
      { $set: update },
      { returnDocument: "after" }
    );
    if (!result) return null;
    const doc = result;
    return {
      id: doc.id,
      slug: doc.slug,
      isDefault: doc.isDefault,
      createdAt: doc.createdAt.toISOString(),
    } as Slug;
  },

  async deleteSlug(id: string): Promise<Slug | null> {
    const db = await getMongoDb();
    const doc = await db.collection<SlugDocument>(slugsCollection).findOneAndDelete(buildIdFilter<SlugDocument>(id));
    if (!doc) return null;
    const deleted = doc;

    // Cleanup relationships
    await db.collection("cms_page_slugs").deleteMany({ slugId: id });

    return {
      id: deleted.id,
      slug: deleted.slug,
      isDefault: deleted.isDefault,
      createdAt: deleted.createdAt.toISOString(),
    } as Slug;
  },

  // Relationships
  async addSlugToPage(pageId: string, slugId: string): Promise<void> {
    const db = await getMongoDb();
    await db.collection("cms_page_slugs").updateOne(
      { pageId, slugId },
      { $set: { pageId, slugId, assignedAt: new Date() } },
      { upsert: true }
    );
  },

  async removeSlugFromPage(pageId: string, slugId: string): Promise<void> {
    const db = await getMongoDb();
    await db.collection("cms_page_slugs").deleteOne({ pageId, slugId });
  },

  // Themes
  async getThemes(): Promise<CmsTheme[]> {
    const db = await getMongoDb();
    const docs = await db.collection<ThemeDocument>(themesCollection).find().sort({ createdAt: -1 }).toArray();
    return docs.map((doc: ThemeDocument) => ({
      id: doc.id,
      name: doc.name,
      colors: doc.colors,
      typography: doc.typography,
      spacing: doc.spacing,
      customCss: doc.customCss ?? undefined,
      createdAt: doc.createdAt.toISOString(),
      updatedAt: doc.updatedAt.toISOString(),
    })) as CmsTheme[];
  },

  async getThemeById(id: string): Promise<CmsTheme | null> {
    const db = await getMongoDb();
    const doc = await db.collection<ThemeDocument>(themesCollection).findOne(buildIdFilter<ThemeDocument>(id));
    if (!doc) return null;
    return {
      id: doc.id,
      name: doc.name,
      colors: doc.colors,
      typography: doc.typography,
      spacing: doc.spacing,
      customCss: doc.customCss ?? undefined,
      createdAt: doc.createdAt.toISOString(),
      updatedAt: doc.updatedAt.toISOString(),
    } as CmsTheme;
  },

  async createTheme(data: CmsThemeCreateInput): Promise<CmsTheme> {
    const db = await getMongoDb();
    const id = randomUUID();
    const doc: ThemeDocument = {
      id,
      name: data.name,
      colors: data.colors as Record<string, string>,
      typography: data.typography as Record<string, unknown>,
      spacing: data.spacing as Record<string, string>,
      customCss: data.customCss ?? null,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    await db.collection<ThemeDocument>(themesCollection).insertOne(doc);
    return {
      id,
      name: doc.name,
      colors: doc.colors,
      typography: doc.typography,
      spacing: doc.spacing,
      customCss: doc.customCss ?? undefined,
    } as CmsTheme;
  },

  async updateTheme(id: string, data: CmsThemeUpdateInput): Promise<CmsTheme | null> {
    const db = await getMongoDb();
    const update = removeUndefined({
      name: data.name,
      colors: data.colors as Record<string, string> | undefined,
      typography: data.typography as Record<string, unknown> | undefined,
      spacing: data.spacing as Record<string, string> | undefined,
      customCss: data.customCss,
      updatedAt: new Date(),
    }) as Partial<ThemeDocument>;

    const result = await db.collection<ThemeDocument>(themesCollection).findOneAndUpdate(
      buildIdFilter<ThemeDocument>(id),
      { $set: update },
      { returnDocument: "after" }
    );
    if (!result) return null;
    return {
      id: result.id,
      name: result.name,
      colors: result.colors,
      typography: result.typography,
      spacing: result.spacing,
      customCss: result.customCss ?? undefined,
      createdAt: result.createdAt.toISOString(),
      updatedAt: result.updatedAt.toISOString(),
    } as CmsTheme;
  },

  async deleteTheme(id: string): Promise<CmsTheme | null> {
    const db = await getMongoDb();
    const doc = await db.collection<ThemeDocument>(themesCollection).findOneAndDelete(buildIdFilter<ThemeDocument>(id));
    if (!doc) return null;
    return {
      id: doc.id,
      name: doc.name,
      colors: doc.colors,
      typography: doc.typography,
      spacing: doc.spacing,
      customCss: doc.customCss ?? undefined,
    } as CmsTheme;
  },
};

import "server-only";

import prisma from "@/shared/lib/db/prisma";
import type { Prisma } from "@prisma/client";
import type { CmsRepository, PageUpdateData } from "../../types/services/cms-repository";
import type { Page, Slug, PageComponent, CmsTheme, CmsThemeCreateInput, CmsThemeUpdateInput } from "../../types";

// Helper to remove undefined keys for exactOptionalPropertyTypes compliance
function removeUndefined<T extends object>(obj: T): T {
  const newObj = { ...obj };
  Object.keys(newObj).forEach((key) => {
    if (newObj[key as keyof T] === undefined) {
      delete newObj[key as keyof T];
    }
  });
  return newObj;
}

export const prismaCmsRepository: CmsRepository = {
  // Pages
  async getPages(): Promise<Page[]> {
    const pages = await prisma.page.findMany({
      include: {
        slugs: {
          include: {
            slug: true,
          },
        },
      },
      orderBy: { createdAt: "desc" },
    });
    return pages as unknown as Page[];
  },

  async getPageById(id: string): Promise<Page | null> {
    const page = await prisma.page.findUnique({
      where: { id },
      include: {
        slugs: {
          include: {
            slug: true,
          },
        },
        components: true,
      },
    });
    return page as unknown as Page | null;
  },

  async createPage(data: { name: string }): Promise<Page> {
    const page = await prisma.page.create({
      data: { name: data.name },
    });
    return page as unknown as Page;
  },

  async getPageBySlug(slugValue: string): Promise<Page | null> {
    const slug = await prisma.slug.findUnique({ where: { slug: slugValue } });
    if (!slug) return null;
    const pageSlug = await prisma.pageSlug.findFirst({ where: { slugId: slug.id } });
    if (!pageSlug) return null;
    return this.getPageById(pageSlug.pageId);
  },

  async updatePage(id: string, data: PageUpdateData): Promise<Page | null> {
    const cleanData = removeUndefined({
      name: data.name,
      status: data.status,
      publishedAt: data.publishedAt !== undefined ? (data.publishedAt ? new Date(data.publishedAt) : null) : undefined,
      seoTitle: data.seoTitle,
      seoDescription: data.seoDescription,
      seoOgImage: data.seoOgImage,
      seoCanonical: data.seoCanonical,
      robotsMeta: data.robotsMeta,
      themeId: data.themeId,
      showMenu: data.showMenu,
    });

    if (Object.keys(cleanData).length > 0) {
      await prisma.page.update({
        where: { id },
        data: cleanData as Prisma.PageUpdateInput,
      });
    }

    if (data.components) {
      await this.replacePageComponents(id, data.components);
    }

    return this.getPageById(id);
  },

  async deletePage(id: string): Promise<Page | null> {
    const page = await prisma.page.delete({ where: { id } });
    return page as unknown as Page | null;
  },

  async replacePageSlugs(pageId: string, slugIds: string[]): Promise<void> {
    await prisma.pageSlug.deleteMany({ where: { pageId } });
    if (slugIds.length === 0) return;
    await prisma.pageSlug.createMany({
      data: slugIds.map((slugId) => ({ pageId, slugId })),
    });
  },

  async replacePageComponents(pageId: string, components: PageComponent[]): Promise<void> {
    await prisma.pageComponent.deleteMany({ where: { pageId } });
    if (components.length === 0) return;
    await prisma.pageComponent.createMany({
      data: components.map((component, index) => ({
        pageId,
        type: component.type,
        content: component.content as Prisma.InputJsonValue,
        order: index,
      })),
    });
  },

  // Slugs
  async getSlugs(): Promise<Slug[]> {
    const slugs = await prisma.slug.findMany({
      orderBy: { createdAt: "desc" },
    });
    return slugs as unknown as Slug[];
  },

  async getSlugById(id: string): Promise<Slug | null> {
    const slug = await prisma.slug.findUnique({ where: { id } });
    return slug as unknown as Slug | null;
  },

  async getSlugByValue(slugValue: string): Promise<Slug | null> {
    const slug = await prisma.slug.findUnique({ where: { slug: slugValue } });
    return slug as unknown as Slug | null;
  },

  async createSlug(data: { slug: string; isDefault?: boolean | undefined }): Promise<Slug> {
    const cleanData = removeUndefined(data);
    const slug = await prisma.slug.create({
      data: cleanData as Prisma.SlugCreateInput,
    });
    return slug as unknown as Slug;
  },

  async updateSlug(id: string, data: { slug?: string | undefined; isDefault?: boolean | undefined }): Promise<Slug | null> {
    const cleanData = removeUndefined(data);
    const slug = await prisma.slug.update({
      where: { id },
      data: cleanData as Prisma.SlugUpdateInput,
    });
    return slug as unknown as Slug | null;
  },

  async deleteSlug(id: string): Promise<Slug | null> {
    const slug = await prisma.slug.delete({ where: { id } });
    return slug as unknown as Slug | null;
  },

  // Relationships
  async addSlugToPage(pageId: string, slugId: string): Promise<void> {
    await prisma.pageSlug.create({
      data: {
        pageId,
        slugId,
      },
    });
  },

  async removeSlugFromPage(pageId: string, slugId: string): Promise<void> {
    await prisma.pageSlug.delete({
      where: {
        pageId_slugId: {
          pageId,
          slugId,
        },
      },
    });
  },

  // Themes
  async getThemes(): Promise<CmsTheme[]> {
    const themes = await prisma.cmsTheme.findMany({
      orderBy: { createdAt: "desc" },
    });
    return themes as unknown as CmsTheme[];
  },

  async getThemeById(id: string): Promise<CmsTheme | null> {
    const theme = await prisma.cmsTheme.findUnique({ where: { id } });
    return theme as unknown as CmsTheme | null;
  },

  async createTheme(data: CmsThemeCreateInput): Promise<CmsTheme> {
    const theme = await prisma.cmsTheme.create({
      data: {
        name: data.name,
        colors: data.colors as Prisma.InputJsonValue,
        typography: data.typography as Prisma.InputJsonValue,
        spacing: data.spacing as Prisma.InputJsonValue,
        customCss: data.customCss ?? null,
      },
    });
    return theme as unknown as CmsTheme;
  },

  async updateTheme(id: string, data: CmsThemeUpdateInput): Promise<CmsTheme | null> {
    const cleanData = removeUndefined({
      name: data.name,
      colors: data.colors as Prisma.InputJsonValue | undefined,
      typography: data.typography as Prisma.InputJsonValue | undefined,
      spacing: data.spacing as Prisma.InputJsonValue | undefined,
      customCss: data.customCss,
    });
    const theme = await prisma.cmsTheme.update({
      where: { id },
      data: cleanData as Prisma.CmsThemeUpdateInput,
    });
    return theme as unknown as CmsTheme | null;
  },

  async deleteTheme(id: string): Promise<CmsTheme | null> {
    const theme = await prisma.cmsTheme.delete({ where: { id } });
    return theme as unknown as CmsTheme | null;
  },
};

