import { Button, Input } from "@/shared/ui";
import { useEffect, useState } from "react";
import { IntegrationConnection } from "@/features/integrations/types/integrations-ui";


type BaselinkerSettingsProps = {
  activeConnection: IntegrationConnection | null;
  onTest: () => void;
  isTesting: boolean;
};

export function BaselinkerSettings({
  activeConnection,
  onTest,
  isTesting,
}: BaselinkerSettingsProps) {
  const baselinkerConnected = Boolean(activeConnection?.hasBaseApiToken);
  const baseTokenUpdatedAt = activeConnection?.baseTokenUpdatedAt
    ? new Date(activeConnection.baseTokenUpdatedAt).toLocaleString()
    : "—";
  const [syncIntervalMinutes, setSyncIntervalMinutes] = useState("10");
  const [loadingSyncInterval, setLoadingSyncInterval] = useState(true);
  const [savingSyncInterval, setSavingSyncInterval] = useState(false);
  const [syncMessage, setSyncMessage] = useState<string | null>(null);

  useEffect(() => {
    const loadSyncInterval = async () => {
      try {
        setLoadingSyncInterval(true);
        const res = await fetch("/api/settings");
        if (!res.ok) return;
        const settings = (await res.json()) as Array<{ key: string; value: string }>;
        const found = settings.find((setting) => setting.key === "base_sync_poll_interval_minutes");
        if (found?.value) {
          setSyncIntervalMinutes(found.value);
        }
      } catch {
        // Ignore load errors
      } finally {
        setLoadingSyncInterval(false);
      }
    };
    void loadSyncInterval();
  }, []);

  const handleSaveSyncInterval = async () => {
    const parsed = Number(syncIntervalMinutes);
    if (!Number.isFinite(parsed) || parsed <= 0) {
      setSyncMessage("Enter a valid number of minutes.");
      return;
    }
    setSavingSyncInterval(true);
    setSyncMessage(null);
    try {
      const res = await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          key: "base_sync_poll_interval_minutes",
          value: String(parsed),
        }),
      });
      if (!res.ok) {
        setSyncMessage("Failed to save sync interval.");
        return;
      }
      setSyncMessage("Sync interval saved.");
    } catch {
      setSyncMessage("Failed to save sync interval.");
    } finally {
      setSavingSyncInterval(false);
    }
  };

  return (
    <div className="space-y-4 rounded-lg border border-border bg-card/60 p-4 text-sm text-gray-200">
      <div>
        <h3 className="text-sm font-semibold text-white">Baselinker API</h3>
        <p className="mt-1 text-xs text-gray-400">
          Enter your Baselinker API token in the connection fields, then test the
          connection to verify it works.
        </p>
      </div>
      {!activeConnection ? (
        <div className="rounded-md border border-dashed border-border p-4 text-xs text-gray-400">
          Add a connection first to enable Baselinker API access.
        </div>
      ) : (
        <div className="space-y-3">
          <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-300">
            <div className="flex items-center justify-between">
              <span>Connection status</span>
              <span
                className={`rounded-full px-2 py-0.5 text-[10px] font-semibold ${
                  baselinkerConnected
                    ? "bg-emerald-500/20 text-emerald-200"
                    : "bg-amber-500/20 text-amber-200"
                }`}
              >
                {baselinkerConnected ? "Connected" : "Not tested"}
              </span>
            </div>
            <p className="mt-2">
              <span className="text-gray-400">Last verified:</span>{" "}
              {baseTokenUpdatedAt}
            </p>
            {activeConnection.baseLastInventoryId && (
              <p className="mt-1">
                <span className="text-gray-400">Last inventory:</span>{" "}
                {activeConnection.baseLastInventoryId}
              </p>
            )}
          </div>
          <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-300">
            <div className="flex items-center justify-between">
              <span>Listing sync interval</span>
              {loadingSyncInterval ? (
                <span className="text-[10px] text-gray-500">Loading...</span>
              ) : (
                <span className="text-[10px] text-gray-500">Minutes</span>
              )}
            </div>
            <div className="mt-2 flex flex-wrap items-center gap-2">
              <Input
                type="number"
                min="1"
                value={syncIntervalMinutes}
                onChange={(event) => setSyncIntervalMinutes(event.target.value)}
                className="w-32 rounded-md border border-border bg-gray-900 px-2 py-1 text-xs text-white"
              />
              <Button
                type="button"
                onClick={() => { void handleSaveSyncInterval(); }}
                disabled={savingSyncInterval}
                className="rounded-md bg-white px-3 py-1.5 text-xs font-semibold text-gray-900 hover:bg-gray-200 disabled:opacity-50"
              >
                {savingSyncInterval ? "Saving..." : "Save"}
              </Button>
            </div>
            <p className="mt-2 text-[10px] text-gray-400">
              Controls how often Base.com is checked for listing status updates.
            </p>
            {syncMessage && (
              <p className="mt-2 text-[10px] text-gray-400">{syncMessage}</p>
            )}
          </div>
          <div className="flex flex-wrap items-center gap-3">
            <Button
              type="button"
              onClick={onTest}
              disabled={isTesting}
              className="rounded-md bg-white px-3 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-200 disabled:opacity-50"
            >
              {isTesting
                ? "Testing..."
                : baselinkerConnected
                ? "Re-test Connection"
                : "Test Connection"}
            </Button>
          </div>
          <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-400">
            <p>
              To get your API token, log in to{" "}
              <a
                href="https://baselinker.com"
                target="_blank"
                rel="noopener noreferrer"
                className="text-purple-300 hover:text-purple-200"
              >
                Baselinker
              </a>{" "}
              → My Account → API.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { Button, Input, Label } from "@/shared/ui";
import { Dispatch, SetStateAction } from "react";
import { Integration, IntegrationConnection, TestLogEntry } from "@/features/integrations/types/integrations-ui";



type ConnectionManagerProps = {
  activeIntegration: Integration;
  connections: IntegrationConnection[];
  editingConnectionId: string | null;
  setEditingConnectionId: (id: string | null) => void;
  connectionForm: { name: string; username: string; password: string };
  setConnectionForm: Dispatch<
    SetStateAction<{ name: string; username: string; password: string }>
  >;
  onSave: () => void;
  onDelete: (connection: IntegrationConnection) => void;
  onTest: (connection: IntegrationConnection) => void;
  isTesting: boolean;
  testLog: TestLogEntry[];
  onShowLog: (step: TestLogEntry) => void;
};

export function ConnectionManager({
  activeIntegration,
  connections,
  editingConnectionId,
  connectionForm,
  setConnectionForm,
  onSave,
  onDelete,
  onTest,
  isTesting,
  testLog,
  onShowLog,
}: ConnectionManagerProps) {
  const integrationSlug = activeIntegration.slug;
  const isTradera = integrationSlug === "tradera";
  const isAllegro = integrationSlug === "allegro";
  const isBaselinker = integrationSlug === "baselinker";
  const showPlaywright = isTradera;

  const connectionNamePlaceholder = isAllegro
    ? "Integration name (e.g. Allegro Main)"
    : isBaselinker
    ? "Integration name (e.g. Main Baselinker)"
    : "Integration name (e.g. John's Tradera)";

  const usernameLabel = isAllegro
    ? "Allegro client ID"
    : isBaselinker
    ? "Account name (optional)"
    : "Tradera username";

  const usernamePlaceholder = isAllegro
    ? "Allegro client ID"
    : isBaselinker
    ? "Account name (for reference)"
    : "Tradera username";

  const passwordLabel = isAllegro
    ? "Allegro client secret"
    : isBaselinker
    ? "Baselinker API token"
    : "Tradera password";

  return (
    <div className="grid gap-4 md:grid-cols-2">
      <div className="rounded-lg border border-border bg-card/60 p-4">
        <h3 className="text-sm font-semibold text-white">
          {editingConnectionId ? "Connection details" : "Add connection"}
        </h3>
        <div className="mt-3 space-y-3">
          <div>
            <Label className="text-xs text-gray-400">Connection name</Label>
            <Input
              className="w-full rounded-md border border-border bg-card px-3 py-2 text-sm text-white"
              placeholder={connectionNamePlaceholder}
              value={connectionForm.name}
              onChange={(event) =>
                setConnectionForm((prev) => ({
                  ...prev,
                  name: event.target.value,
                }))
              }
            />
          </div>
          <div>
            <Label className="text-xs text-gray-400">{usernameLabel}</Label>
            <Input
              className="w-full rounded-md border border-border bg-card px-3 py-2 text-sm text-white"
              placeholder={usernamePlaceholder}
              value={connectionForm.username}
              onChange={(event) =>
                setConnectionForm((prev) => ({
                  ...prev,
                  username: event.target.value,
                }))
              }
            />
          </div>
          <div>
            <Label className="text-xs text-gray-400">{passwordLabel}</Label>
            <Input
              className="w-full rounded-md border border-border bg-card px-3 py-2 text-sm text-white"
              type="password"
              placeholder={
                editingConnectionId
                  ? isAllegro
                    ? "New client secret (leave blank to keep)"
                    : "New password (leave blank to keep)"
                  : isAllegro
                  ? "Allegro client secret"
                  : "Tradera password"
              }
              value={connectionForm.password}
              onChange={(event) =>
                setConnectionForm((prev) => ({
                  ...prev,
                  password: event.target.value,
                }))
              }
            />
          </div>
          <Button
            className="w-full rounded-md bg-white px-3 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-200"
            type="button"
            onClick={onSave}
          >
            {editingConnectionId ? "Update connection" : "Save connection"}
          </Button>
        </div>
      </div>

      <div className="rounded-lg border border-border bg-card/60 p-4">
        <h3 className="text-sm font-semibold text-white">Existing connection</h3>
        {connections.length === 0 ? (
          <p className="mt-3 text-sm text-gray-400">No connections yet.</p>
        ) : (
          <div className="mt-3 space-y-3">
            {connections.slice(0, 1).map((connection) => (
              <div
                key={connection.id}
                className="flex items-center justify-between rounded-md border border-border bg-card/70 px-3 py-2"
              >
                <div>
                  <p className="text-sm font-semibold text-white">
                    {connection.name}
                  </p>
                  <p className="text-xs text-gray-400">{connection.username}</p>
                </div>
                <div className="flex items-center gap-3">
                  <Button
                    className={`text-xs ${
                      isBaselinker
                        ? "text-purple-300 hover:text-purple-200"
                        : isAllegro
                        ? "text-amber-300 hover:text-amber-200"
                        : "text-sky-300 hover:text-sky-200"
                    }`}
                    type="button"
                    onClick={() => onTest(connection)}
                    disabled={isTesting}
                  >
                    {isTesting ? "Testing..." : "Test"}
                  </Button>
                  <Button
                    className="text-xs text-red-400 hover:text-red-300"
                    type="button"
                    onClick={() => onDelete(connection)}
                  >
                    Remove
                  </Button>
                </div>
              </div>
            ))}
          </div>
        )}
        {showPlaywright && (
          <div className="mt-4 rounded-md border border-border bg-card/60 p-3">
            <div className="flex items-center justify-between">
              <p className="text-xs font-semibold text-gray-300">
                Playwright live update
              </p>
              <span className="text-xs text-gray-500">
                {isTesting ? "Running..." : "Idle"}
              </span>
            </div>

            {testLog.length === 0 ? (
              <p className="mt-2 text-xs text-gray-500">
                Run a connection test to see live updates.
              </p>
            ) : (
              <div className="mt-2 max-h-40 space-y-2 overflow-y-auto text-xs text-gray-400">
                {testLog.map((entry, index) => (
                  <div
                    key={`${entry.step}-${index}`}
                    className="flex items-center justify-between gap-3"
                  >
                    <p>{entry.step}</p>
                    {entry.status !== "pending" && (
                      <Button
                        type="button"
                        className={`rounded-full px-2 py-0.5 text-[10px] font-semibold ${
                          entry.status === "ok"
                            ? "bg-emerald-500/20 text-emerald-200"
                            : "bg-red-500/20 text-red-200"
                        }`}
                        onClick={() => onShowLog(entry)}
                      >
                        {entry.status === "ok" ? "OK" : "FAILED"}
                      </Button>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

