            <Select
              value={selectedIntegrationId}
              onValueChange={setSelectedIntegrationId}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select an integration..." />
              </SelectTrigger>
              <SelectContent>
                {integrations
