            >
              <div className="flex items-center gap-2">
                {field.hasValue ? (
                  <Check className="size-3 text-emerald-400" />
                ) : (
                  <X className="size-3 text-gray-600" />
                )}
                <span className={field.hasValue ? "text-gray-200" : "text-gray-500"}>
                  {field.name}
                </span>
              </div>
              <div className="flex items-center gap-3">
                <span className="max-w-[120px] truncate text-gray-400" title={field.value}>
                  {field.value}
                </span>
                <div className="flex items-center gap-1" title={getSyncDirectionLabel(field.syncDirection)}>
                  {getSyncDirectionIcon(field.hasValue ? field.syncDirection : "none")}
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-3 border-t border-border pt-2">
          <div className="flex items-center justify-between text-[10px] text-gray-500">
            <span>{activeFields.length} of {syncFields.length} fields will be synced</span>
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-1">
                <ArrowRight className="size-2.5 text-blue-400" />
                <span>To Base</span>
              </div>
              <div className="flex items-center gap-1 opacity-40">
                <ArrowLeft className="size-2.5 text-purple-400" />
                <span>From Base</span>
              </div>
              <div className="flex items-center gap-1 opacity-40">
                <ArrowLeftRight className="size-2.5 text-emerald-400" />
                <span>Both</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const handleDeleteFromBase = async (listingId: string): Promise<void> => {
    const listing: ProductListingWithDetails | undefined = listings.find((item: ProductListingWithDetails): boolean => item.id === listingId);
    if (!listing) return;
    if (!window.confirm("Delete this product from Base.com? This cannot be undone.")) {
      return;
    }

    try {
      setDeletingFromBase(listingId);
      // Send inventoryId if available, but let the backend handle fallback logic
      const inventoryId: string = (inventoryOverrides[listingId] || listing.inventoryId || "").trim();
      const body: { inventoryId?: string } = inventoryId ? { inventoryId } : {};
      const res: Response = await fetch(
        `/api/integrations/products/${product.id}/listings/${listingId}/delete-from-base`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(body),
        }
      );
      if (!res.ok) {
        const payload: { error?: string } = (await res.json().catch((): Record<string, never> => ({}))) as { error?: string };
        throw new Error(payload.error || "Failed to delete from Base.com");
      }
      queryClient.setQueryData<ProductListingWithDetails[]>(
        ["integrations", "product-listings", product.id],
        (prev: ProductListingWithDetails[] | undefined = []): ProductListingWithDetails[] =>
          prev.map((item: ProductListingWithDetails): ProductListingWithDetails =>
            item.id === listingId
              ? { ...item, status: "removed", updatedAt: new Date() }
              : item
          )
      );
      onListingsUpdated?.();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to delete from Base.com");
    } finally {
      setDeletingFromBase(null);
    }
  };

  const handlePurgeListing = async (listingId: string): Promise<void> => {
    const listing: ProductListingWithDetails | undefined = listings.find((item: ProductListingWithDetails): boolean => item.id === listingId);
    if (!listing) return;
    if (!window.confirm("Remove this integration connection and its history?")) {
      return;
    }

    try {
      setPurgingListing(listingId);
      const res: Response = await fetch(
        `/api/integrations/products/${product.id}/listings/${listingId}/purge`,
        { method: "DELETE" }
      );
      if (!res.ok) {
        throw new Error("Failed to remove listing history");
      }
      queryClient.setQueryData<ProductListingWithDetails[]>(
        ["integrations", "product-listings", product.id],
        (prev: ProductListingWithDetails[] | undefined = []): ProductListingWithDetails[] => prev.filter((item: ProductListingWithDetails): boolean => item.id !== listingId)
      );
      onListingsUpdated?.();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to remove listing history");
    } finally {
      setPurgingListing(null);
    }
  };

  const handleSaveInventoryId = async (listingId: string): Promise<void> => {
    const value: string = (inventoryOverrides[listingId] ?? "").trim();
    if (!value) {
      setError("Inventory ID is required.");
      return;
    }

    try {
      setSavingInventoryId(listingId);
      const res: Response = await fetch(
        `/api/integrations/products/${product.id}/listings/${listingId}`,
        {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ inventoryId: value }),
        }
      );
      if (!res.ok) {
        const payload: { error?: string } = (await res.json().catch((): Record<string, never> => ({}))) as { error?: string };
        throw new Error(payload.error || "Failed to save inventory ID");
      }
      queryClient.setQueryData<ProductListingWithDetails[]>(
        ["integrations", "product-listings", product.id],
        (prev: ProductListingWithDetails[] | undefined = []): ProductListingWithDetails[] =>
          prev.map((item: ProductListingWithDetails): ProductListingWithDetails =>
            item.id === listingId
              ? { ...item, inventoryId: value, updatedAt: new Date() }
              : item
          )
      );
      setInventoryOverrides((prev: Record<string, string>): Record<string, string> => {
        const next: Record<string, string> = { ...prev };
        delete next[listingId];
        return next;
      });
      onListingsUpdated?.();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to save inventory ID");
    } finally {
      setSavingInventoryId(null);
    }
  };

  const exportListingToBase = async (
    listingId: string,
    options?: {
      imageBase64Mode?: "base-only" | "full-data-uri";
      imageTransform?: ImageTransformOptions | null;
    }
  ): Promise<void> => {
    const listing: ProductListingWithDetails | undefined = listings.find((item: ProductListingWithDetails): boolean => item.id === listingId);
    if (!listing) return;
    const inventoryId: string = (inventoryOverrides[listingId] || listing.inventoryId || "").trim();
    if (!inventoryId) {
      throw new Error("Inventory ID is required.");
    }
    const templateId: string | undefined = getLatestTemplateId(listing) ?? undefined;
    const payload: Record<string, unknown> = {
      connectionId: listing.connectionId,
      inventoryId,
      templateId,
    };
    if (options?.imageBase64Mode) {
      payload.imageBase64Mode = options.imageBase64Mode;
      payload.exportImagesAsBase64 = true;
    }
    if (options?.imageTransform) {
      payload.imageTransform = options.imageTransform;
      payload.exportImagesAsBase64 = true;
    }

    const res: Response = await fetch(`/api/integrations/products/${product.id}/export-to-base`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    const payloadRes: { logs?: CapturedLog[]; error?: string } = (await res.json().catch((): Record<string, never> => ({}))) as { logs?: CapturedLog[]; error?: string };
    if (payloadRes.logs) {
      setExportLogs(payloadRes.logs);
    }
    if (!res.ok) {
      throw new Error(payloadRes.error || "Failed to export product");
    }
  };

  const exportListingImagesOnly = async (
    listingId: string,
    options?: {
      imageBase64Mode?: "base-only" | "full-data-uri";
      imageTransform?: ImageTransformOptions | null;
    }
  ): Promise<void> => {
    const listing: ProductListingWithDetails | undefined = listings.find((item: ProductListingWithDetails): boolean => item.id === listingId);
    if (!listing) return;
    const inventoryId: string = (inventoryOverrides[listingId] || listing.inventoryId || "").trim();
    if (!inventoryId) {
      throw new Error("Inventory ID is required.");
    }
    if (!listing.externalListingId) {
      throw new Error("External Base.com product ID is missing.");
    }
    const payload: Record<string, unknown> = {
      connectionId: listing.connectionId,
      inventoryId,
      imagesOnly: true,
      listingId: listing.id,
      externalListingId: listing.externalListingId,
      allowDuplicateSku: true,
      exportImagesAsBase64: true,
    };
    if (options?.imageBase64Mode) {
      payload.imageBase64Mode = options.imageBase64Mode;
    }
    if (options?.imageTransform) {
      payload.imageTransform = options.imageTransform;
    }

    const res: Response = await fetch(`/api/integrations/products/${product.id}/export-to-base`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    const payloadRes: { logs?: CapturedLog[]; error?: string } = (await res.json().catch((): Record<string, never> => ({}))) as { logs?: CapturedLog[]; error?: string };
    if (payloadRes.logs) {
      setExportLogs(payloadRes.logs);
    }
    if (!res.ok) {
      throw new Error(payloadRes.error || "Failed to export product images");
    }
  };

  const handleExportAgain = async (listingId: string): Promise<void> => {
    const listing: ProductListingWithDetails | undefined = listings.find((item: ProductListingWithDetails): boolean => item.id === listingId);
    if (!listing) return;
    const inventoryId: string = (inventoryOverrides[listingId] || listing.inventoryId || "").trim();
    if (!inventoryId) {
      setError("Inventory ID is required.");
      return;
    }

    try {
      setExportingListing(listingId);
      setLastExportListingId(listingId);
      setExportLogs([]);
      setLogsOpen(true);
      await exportListingToBase(listingId);
      await queryClient.invalidateQueries({
        queryKey: ["integrations", "product-listings", product.id],
      });
      onListingsUpdated?.();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to export product");
    } finally {
      setExportingListing(null);
    }
  };

  const handleExportImagesOnly = async (
    listingId: string,
    preset?: ImageRetryPreset
  ): Promise<void> => {
    try {
      setExportingListing(listingId);
      setLastExportListingId(listingId);
      setError(null);
      setExportLogs([]);
      setLogsOpen(true);
      await exportListingImagesOnly(listingId, preset ? {
        imageBase64Mode: preset.imageBase64Mode,
        imageTransform: preset.transform,
      } : undefined);
      await queryClient.invalidateQueries({
        queryKey: ["integrations", "product-listings", product.id],
      });
      onListingsUpdated?.();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to export product images");
    } finally {
      setExportingListing(null);
    }
  };

  const handleImageRetry = async (preset: ImageRetryPreset): Promise<void> => {
    if (!lastExportListingId) return;
    try {
      setExportingListing(lastExportListingId);
      setError(null);
      setExportLogs([]);
      setLogsOpen(true);
      await exportListingToBase(lastExportListingId, {
        imageBase64Mode: preset.imageBase64Mode,
        imageTransform: preset.transform,
      });
      await queryClient.invalidateQueries({
        queryKey: ["integrations", "product-listings", product.id],
      });
      onListingsUpdated?.();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to export product");
    } finally {
      setExportingListing(null);
    }
  };

  const loading: boolean = loadingListings;

  return (
    <ModalShell
      title={`Integrations - ${productName}`}
      onClose={onClose}
      size="md"
    >
      <div className="space-y-4">
        {loading ? (
          <p className="text-sm text-gray-400">Loading listings...</p>
        ) : combinedError ? (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-200">
            <div className="flex flex-col gap-3">
              <span>{combinedError}</span>
              {isImageExportError(combinedError) && lastExportListingId ? (
                <div className="flex flex-wrap items-center gap-2">
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="secondary"
                        size="sm"
                        className="bg-red-500/20 text-red-100 hover:bg-red-500/30"
                        disabled={Boolean(exportingListing)}
                      >
                        Retry image export
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="start" className="bg-card border-border">
                      {imageRetryPresets.map((preset: ImageRetryPreset): React.JSX.Element => (
                        <DropdownMenuItem
                          key={preset.id}
                          onSelect={(): void => { void handleImageRetry(preset); }}
                          className="text-gray-200 focus:bg-gray-800/70"
                        >
                          <div className="flex flex-col">
                            <span className="text-sm">{preset.label}</span>
                            <span className="text-xs text-gray-400">
                              {preset.description}
                            </span>
                          </div>
                        </DropdownMenuItem>
                      ))}
                    </DropdownMenuContent>
                  </DropdownMenu>
                  <span className="text-xs text-red-200/80">
                    Applies JPEG resize/compression and retries automatically.
                  </span>
                </div>
              ) : null}
            </div>
          </div>
        ) : (
          <div className="space-y-3">
            {canStartListing && <StartListingPanel />}
            {filteredListings.length === 0 ? (
              <div className="rounded-md border bg-card/50 px-4 py-8 text-center">
                {filterIntegrationSlug ? (
                  <div className="space-y-3">
                    <div className="text-sm text-gray-300">
                      {statusTargetLabel} status
                    </div>
                    <div className="rounded-md border border-border bg-card/60 px-3 py-2 text-xs text-gray-400">
                      Not connected.
                    </div>
                    {filterIntegrationSlug === "baselinker" && <SyncConfigurationPanel />}
                  </div>
                ) : (
                  <div className="space-y-4">
                    <div className="border-t border-border pt-3">
                      <p className="text-sm text-gray-400">
                        This product is not listed on any marketplace yet.
                      </p>
                      <p className="mt-2 text-xs text-gray-500">
                        Use the + button in the header to list products on a marketplace.
                      </p>
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <div className="space-y-3">
                {filterIntegrationSlug && (
                  <div className="rounded-md border border-border bg-card/60 px-3 py-2 text-xs text-gray-300">
                    {statusTargetLabel} status: {filteredListings[0]?.status ?? "Unknown"}
                  </div>
                )}
                {filterIntegrationSlug === "baselinker" && <SyncConfigurationPanel />}
                {filteredListings.map((listing: ProductListingWithDetails): React.JSX.Element => (
                  <div
                    key={listing.id}
                    className="flex items-center justify-between rounded-md border bg-card/50 px-4 py-3"
                  >
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <span className="font-medium text-white">
                          {listing.integration.name}
                        </span>
                        <span
                          className={`rounded border px-2 py-0.5 text-xs ${statusColors[listing.status] || statusColors.pending}`}
                        >
                          {listing.status}
                        </span>
                      </div>
                      <p className="mt-1 text-xs text-gray-400">
                        Account: {listing.connection.name}
                      </p>
                      {listing.externalListingId && (
                        <p className="text-xs text-gray-500">
                          External ID: {listing.externalListingId}
                        </p>
                      )}
                      {listing.inventoryId && (
                        <p className="text-xs text-gray-500">
                          Inventory ID: {listing.inventoryId}
                        </p>
                      )}
                      <div className="mt-2 space-y-1 text-xs text-gray-500">
                        <p>Last export: {formatTimestamp(listing.listedAt)}</p>
                        <p>Created: {formatTimestamp(listing.createdAt)}</p>
                        <p>Updated: {formatTimestamp(listing.updatedAt)}</p>
                        {["baselinker", "base-com"].includes(listing.integration.slug) && (
                          <p>Exported fields: {getExportFieldsLabel()}</p>
                        )}
                      </div>
                      {listing.exportHistory && listing.exportHistory.length > 0 ? (
                        <div className="mt-3 rounded border border-border bg-card/50 p-2">
                          <div className="flex items-center justify-between">
                            <p className="text-[10px] uppercase tracking-wide text-gray-500">
                              Export history
                            </p>
                            <Button
                              type="button"
                              onClick={(): void =>
                                setHistoryOpenByListing((prev: Record<string, boolean>): Record<string, boolean> => ({
                                  ...prev,
                                  [listing.id]: !(prev[listing.id] ?? false),
                                }))
                              }
                              className="text-[10px] uppercase tracking-wide text-gray-400 hover:text-gray-200"
                            >
                              {(historyOpenByListing[listing.id] ?? false)
                                ? "Hide"
                                : "Show"}
                            </Button>
                          </div>
                          {(historyOpenByListing[listing.id] ?? false) ? (
                            <div className="mt-2 space-y-2 text-xs text-gray-400">
                              {listing.exportHistory.slice(0, 5).map((event: ProductListingExportEvent, index: number): React.JSX.Element => (
                                <div key={`${listing.id}-export-${index}`} className="grid gap-1">
                                  <div className="flex items-center justify-between text-gray-300">
                                    <span>{formatTimestamp(event.exportedAt)}</span>
                                    <span className="uppercase text-[10px] text-gray-500">
                                      {event.status ?? "success"}
                                    </span>
                                  </div>
                                  <div className="grid gap-1">
                                    <span>Inventory: {formatListValue(event.inventoryId)}</span>
                                    <span>Template: {formatListValue(event.templateId)}</span>
                                    <span>Warehouse: {formatListValue(event.warehouseId)}</span>
                                    {event.externalListingId && (
                                      <span>External ID: {event.externalListingId}</span>
                                    )}
                                    {event.fields && event.fields.length > 0 ? (
                                      <span>Fields: {event.fields.join(", ")}</span>
                                    ) : (
                                      <span>Fields: —</span>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                          ) : null}
                        </div>
                      ) : (
                        <p className="mt-2 text-xs text-gray-600">No export history recorded.</p>
                      )}
                    </div>
                    <div className="ml-4 flex flex-col gap-2">
                      {["baselinker", "base-com"].includes(listing.integration.slug) && (
                        <>
                          {listing.status === "failed" && (
                            <Button
                              type="button"
                              variant="outline"
                              size="sm"
                              onClick={(): void => { void handleExportAgain(listing.id); }}
                              disabled={exportingListing === listing.id}
                              className="border-emerald-500/40 text-emerald-200 hover:bg-emerald-500/10"
                            >
                              Export again
                            </Button>
                          )}
                          {listing.status !== "removed" && (
                            <DropdownMenu>
                              <DropdownMenuTrigger asChild>
                                <Button
                                  type="button"
                                  variant="outline"
                                  size="sm"
                                  disabled={
                                    exportingListing === listing.id ||
                                    !listing.externalListingId
                                  }
                                  className="border-sky-500/40 text-sky-200 hover:bg-sky-500/10"
                                >
                                  Re-export images only
                                </Button>
                              </DropdownMenuTrigger>
                              <DropdownMenuContent
                                align="start"
                                className="bg-card border-border"
                              >
                                <DropdownMenuItem
                                  onSelect={(): void => { void handleExportImagesOnly(listing.id); }}
                                  className="text-gray-200 focus:bg-gray-800/70"
                                >
                                  <div className="flex flex-col">
                                    <span className="text-sm">No resize (base-only)</span>
                                    <span className="text-xs text-gray-400">
                                      Re-send images without extra compression.
                                    </span>
                                  </div>
                                </DropdownMenuItem>
                                {imageRetryPresets.map((preset: ImageRetryPreset): React.JSX.Element => (
                                  <DropdownMenuItem
                                    key={preset.id}
                                    onSelect={(): void => {
                                      void handleExportImagesOnly(listing.id, preset);
                                    }}
                                    className="text-gray-200 focus:bg-gray-800/70"
                                  >
                                    <div className="flex flex-col">
                                      <span className="text-sm">{preset.label}</span>
                                      <span className="text-xs text-gray-400">
                                        {preset.description}
                                      </span>
                                    </div>
                                  </DropdownMenuItem>
                                ))}
                              </DropdownMenuContent>
                            </DropdownMenu>
                          )}
                          {!listing.inventoryId && (
                            <div className="space-y-1 text-xs text-gray-400">
                              <Label htmlFor={`inventory-${listing.id}`}>
                                Inventory ID
                              </Label>
                              <Input
                                id={`inventory-${listing.id}`}
                                value={inventoryOverrides[listing.id] ?? ""}
                                onChange={(e: React.ChangeEvent<HTMLInputElement>): void =>
                                  setInventoryOverrides((prev: Record<string, string>): Record<string, string> => ({
                                    ...prev,
                                    [listing.id]: e.target.value,
                                  }))
                                }
                                placeholder="Enter inventory ID"
                                className="h-7 border bg-card/60 text-gray-200"
                              />
                              <Button
                                type="button"
                                variant="outline"
                                size="sm"
                                onClick={(): void => { void handleSaveInventoryId(listing.id); }}
                                disabled={savingInventoryId === listing.id}
                                className="h-7 border text-gray-200 hover:bg-muted/50"
                              >
                                Save inventory ID
                              </Button>
                            </div>
                          )}
                          {listing.status !== "removed" && (
                            <Button
                              type="button"
                              variant="outline"
                              size="sm"
                              onClick={(): void => { void handleDeleteFromBase(listing.id); }}
                              disabled={deletingFromBase === listing.id}
                              className="border-red-500/40 text-red-300 hover:bg-red-500/10"
                            >
                              Delete from Base.com
                            </Button>
                          )}
                        </>
                      )}
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        onClick={(): void => { void handlePurgeListing(listing.id); }}
                        disabled={purgingListing === listing.id}
                        className="text-gray-400 hover:bg-muted/50 hover:text-red-400"
                      >
                        <Trash2 className="mr-1 size-3" />
                        Remove history
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
        {exportLogs.length > 0 && (
          <div className="mt-4 border-t border pt-4">
            <ExportLogViewer
              logs={exportLogs}
              isOpen={logsOpen}
              onToggle={setLogsOpen}
            />
          </div>
        )}
      </div>
    </ModalShell>
  );
}

"use client";

import { AppModal, ModalShell, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, Button, Label } from "@/shared/ui";
import { useIntegrationSelection } from "./hooks/useIntegrationSelection";





type SelectIntegrationModalProps = {
  onClose: () => void;
  onSelect: (integrationId: string, connectionId: string) => void;
};

export default function SelectIntegrationModal({
  onClose,
  onSelect,
}: SelectIntegrationModalProps) {
  const {
    integrations,
    loading,
    selectedIntegrationId,
    selectedConnectionId,
    selectedIntegration,
    setSelectedIntegrationId,
    setSelectedConnectionId,
  } = useIntegrationSelection();

  // Note: We don't auto-select the integration on initial load
  // The user should manually select the integration, and then we auto-select the connection

  const handleContinue = () => {
    if (selectedIntegrationId && selectedConnectionId) {
      onSelect(selectedIntegrationId, selectedConnectionId);
    }
  };

  return (
    <AppModal
      open={true}
      onOpenChange={(open) => !open && onClose()}
      title="Select Marketplace / Integration"
    >
      <ModalShell title="Select Marketplace / Integration" onClose={onClose} size="md">
        <div className="space-y-4">
        {loading ? (
          <p className="text-sm text-gray-400">Loading integrations...</p>
        ) : integrations.length === 0 ? (
          <div className="rounded-md border border-yellow-500/40 bg-yellow-500/10 px-4 py-6 text-center">
            <p className="text-sm text-yellow-200">No connected integrations</p>
            <p className="mt-2 text-xs text-yellow-300/70">
              <a href="/admin/integrations" className="underline hover:text-yellow-100">
                Set up an integration first
              </a>
            </p>
          </div>
        ) : (
          <>
            <div>
              <Label className="mb-2 block text-sm font-medium text-gray-300">
                Integration
              </Label>
              <Select
                value={selectedIntegrationId}
                onValueChange={(value) => setSelectedIntegrationId(value)}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select an integration..." />
                </SelectTrigger>
                <SelectContent>
                  {integrations
                    .filter((integration) => integration.id)
                    .map((integration) => (
                      <SelectItem key={integration.id} value={integration.id}>
                        {integration.name}
                      </SelectItem>
                    ))}
                </SelectContent>
              </Select>
            </div>

            {selectedIntegration && selectedIntegration.connections.length > 0 && (
              <div>
                <Label className="mb-2 block text-sm font-medium text-gray-300">
                  Account / Connection
                </Label>
                <Select
                  value={selectedConnectionId}
                  onValueChange={setSelectedConnectionId}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select an account..." />
                  </SelectTrigger>
                  <SelectContent>
                    {selectedIntegration.connections
                      .filter((connection) => connection.id)
                      .map((connection) => (
                        <SelectItem key={connection.id} value={connection.id}>
                          {connection.name}
                        </SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>
            )}

            <div className="flex justify-end gap-3 pt-4">
              <Button
                type="button"
                onClick={onClose}
                className="rounded-md px-4 py-2 text-sm text-gray-400 hover:text-white transition-colors"
              >
                Cancel
              </Button>
              <Button
                type="button"
                onClick={handleContinue}
                disabled={!selectedIntegrationId || !selectedConnectionId}
                className="rounded-md bg-primary px-4 py-2 text-sm font-semibold text-primary-foreground hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                Continue
              </Button>
            </div>
          </>
        )}
        </div>
      </ModalShell>
    </AppModal>
  );
}

"use client";
import { Button, Label, DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, ModalShell, Checkbox } from "@/shared/ui";
import { useEffect, useState } from "react";





import type { ProductWithImages } from "@/features/products";
import type {
  ImageRetryPreset,
  ImageTransformOptions,
} from "@/features/data-import-export";
import { ExportLogViewer } from "./ExportLogViewer";
import type { CapturedLog } from "@/features/integrations/services/exports/log-capture";
import { useImageRetryPresets } from "./useImageRetryPresets";

import { useIntegrationSelection } from "./hooks/useIntegrationSelection";
import { useBaseComSettings } from "./hooks/useBaseComSettings";
import { isImageExportError } from "./utils";

type SelectProductForListingModalProps = {
  integrationId: string;
  connectionId: string;
  onClose: () => void;
  onSuccess: () => void;
};

export default function SelectProductForListingModal({
  integrationId: initialIntegrationId,
  connectionId: initialConnectionId,
  onClose,
  onSuccess,
}: SelectProductForListingModalProps) {
  const [products, setProducts] = useState<ProductWithImages[]>([]);
  const [loadingProducts, setLoadingProducts] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedProductId, setSelectedProductId] = useState<string>("");
  const [submitting, setSubmitting] = useState(false);

  // Integration & connection selection
  const {
    loading: loadingIntegrations,
    selectedIntegrationId,
    selectedConnectionId,
    selectedIntegration,
    isBaseComIntegration,
  } = useIntegrationSelection(initialIntegrationId, initialConnectionId);

  // Base.com specific settings
  const {
    templates,
    selectedTemplateId,
    setSelectedTemplateId,
    inventories,
    selectedInventoryId,
    setSelectedInventoryId,
    loadingInventories,
    allowDuplicateSku,
    setAllowDuplicateSku,
  } = useBaseComSettings(isBaseComIntegration, selectedConnectionId);

  // Export logging
  const [exportLogs, setExportLogs] = useState<CapturedLog[]>([]);
  const [logsOpen, setLogsOpen] = useState(false);
  const imageRetryPresets = useImageRetryPresets();

  const connectionName = selectedIntegration?.connections.find(
    (c) => c.id === selectedConnectionId
  )?.name || "";

  // Load products
  useEffect(() => {
    const fetchProducts = async () => {
      try {
        setLoadingProducts(true);
        const res = await fetch("/api/products");
        if (!res.ok) throw new Error("Failed to fetch products");
        const data = (await res.json()) as ProductWithImages[];
        setProducts(data);
      } catch (err) {
        setError(err instanceof Error ? err.message : "Failed to load products");
      } finally {
        setLoadingProducts(false);
      }
    };
    void fetchProducts();
  }, []);

  const exportToBase = async (options?: {
    imageBase64Mode?: "base-only" | "full-data-uri";
    imageTransform?: ImageTransformOptions | null;
  }) => {
    const payload: Record<string, unknown> = {
      connectionId: selectedConnectionId,
      inventoryId: selectedInventoryId,
      templateId: selectedTemplateId !== "none" ? selectedTemplateId : undefined,
      allowDuplicateSku,
    };

    if (options?.imageBase64Mode) {
      payload.imageBase64Mode = options.imageBase64Mode;
      payload.exportImagesAsBase64 = true;
    }
    if (options?.imageTransform) {
      payload.imageTransform = options.imageTransform;
      payload.exportImagesAsBase64 = true;
    }

    const res = await fetch(`/api/integrations/products/${selectedProductId}/export-to-base`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    const data = (await res.json().catch(() => ({}))) as { 
      logs?: CapturedLog[]; 
      skuExists?: boolean; 
      error?: string 
    };
    if (data.logs) {
      setExportLogs(data.logs);
    }

    if (!res.ok) {
      if (data.skuExists) {
        throw new Error(data.error || "SKU already exists in Base.com");
      }
      throw new Error(data.error || "Failed to export product to Base.com");
    }
  };

  const handleSubmit = async () => {
    if (!selectedProductId) {
      setError("Please select a product");
      return;
    }

    if (!selectedConnectionId) {
      setError("Please select an account");
      return;
    }

    if (isBaseComIntegration && !selectedInventoryId) {
      setError("Please select a Base.com inventory");
      return;
    }

    try {
      setSubmitting(true);
      setError(null);
      setExportLogs([]);
      setLogsOpen(true);

      if (isBaseComIntegration) {
        await exportToBase();
        onSuccess();
      } else {
        const res = await fetch(`/api/integrations/products/${selectedProductId}/listings`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            integrationId: selectedIntegrationId,
            connectionId: selectedConnectionId,
          }),
        });

        if (!res.ok) {
          const data = (await res.json()) as { error?: string };
          throw new Error(data.error || "Failed to create listing");
        }

        onSuccess();
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to list product");
    } finally {
      setSubmitting(false);
    }
  };

  const handleImageRetry = async (preset: ImageRetryPreset) => {
    if (!selectedProductId || !isBaseComIntegration || !selectedInventoryId) {
      return;
    }
    try {
      setSubmitting(true);
      setError(null);
      setExportLogs([]);
      setLogsOpen(true);
      await exportToBase({
        imageBase64Mode: preset.imageBase64Mode,
        imageTransform: preset.transform,
      });
      onSuccess();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to export product");
    } finally {
      setSubmitting(false);
    }
  };

  const getProductDisplayName = (product: ProductWithImages) => {
    return product.name_en || product.name_pl || product.name_de || product.sku;
  };

  const loading = loadingProducts || loadingIntegrations;

  return (
    <ModalShell
      title={`List Product to ${selectedIntegration?.name || "Marketplace"}`}
      onClose={onClose}
      size="md"
      showClose={false}
      footer={
        <>
          <Button
            variant="outline"
            onClick={onClose}
            className="bg-gray-800 text-white hover:bg-gray-700"
          >
            Cancel
          </Button>
          <Button
            onClick={() => void handleSubmit()}
            disabled={
              submitting ||
              !selectedProductId ||
              (isBaseComIntegration && !selectedInventoryId)
            }
          >
            {submitting
              ? isBaseComIntegration
                ? "Exporting..."
                : "Listing..."
              : isBaseComIntegration
              ? "Export to Base.com"
              : "List Product"}
          </Button>
        </>
      }
    >
      <div className="space-y-6">
        {error && (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-200">
            <div className="flex flex-col gap-3">
              <span>{error}</span>
              {isBaseComIntegration && isImageExportError(error) ? (
                <div className="flex flex-wrap items-center gap-2">
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="secondary"
                        size="sm"
                        className="bg-red-500/20 text-red-100 hover:bg-red-500/30"
                        disabled={submitting}
                      >
                        Retry image export
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="start" className="bg-card border-border">
                      {imageRetryPresets.map((preset: ImageRetryPreset) => (
                        <DropdownMenuItem
                          key={preset.id}
                          onSelect={() => void handleImageRetry(preset)}
                          className="text-gray-200 focus:bg-gray-800/70"
                        >
                          <div className="flex flex-col">
                            <span className="text-sm">{preset.label}</span>
                            <span className="text-xs text-gray-400">
                              {preset.description}
                            </span>
                          </div>
                        </DropdownMenuItem>
                      ))}
                    </DropdownMenuContent>
                  </DropdownMenu>
                  <span className="text-xs text-red-200/80">
                    Applies JPEG resize/compression and retries automatically.
                  </span>
                </div>
              ) : null}
            </div>
          </div>
        )}

        <div className="rounded-md border bg-card/50 px-4 py-3">
          <p className="text-sm text-gray-300">
            <span className="text-gray-500">Integration:</span>{" "}
            <span className="font-medium">{selectedIntegration?.name || "Loading..."}</span>
          </p>
          <p className="text-sm text-gray-300">
            <span className="text-gray-500">Account:</span>{" "}
            <span className="font-medium">{connectionName || "Loading..."}</span>
          </p>
        </div>

        {loading ? (
          <p className="text-sm text-gray-400">Loading products...</p>
        ) : (
          <>
            <div className="space-y-2">
              <Label htmlFor="product">Select Product</Label>
              <Select
                value={selectedProductId}
                onValueChange={setSelectedProductId}
              >
                <SelectTrigger id="product">
                  <SelectValue placeholder="Select a product..." />
                </SelectTrigger>
                <SelectContent>
                  {products.map((product) => (
                    <SelectItem key={product.id} value={product.id}>
                      {getProductDisplayName(product)} ({product.sku})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {isBaseComIntegration && (
              <>
                <div className="space-y-2">
                  <Label htmlFor="inventory">
                    Base.com Inventory {loadingInventories && "(Loading...)"}
                  </Label>
                  <Select
                    value={selectedInventoryId}
                    onValueChange={setSelectedInventoryId}
                    disabled={loadingInventories || inventories.length === 0}
                  >
                    <SelectTrigger id="inventory">
                      <SelectValue placeholder="Select inventory..." />
                    </SelectTrigger>
                    <SelectContent>
                      {inventories
                        .filter((inventory) => inventory.id)
                        .map((inventory) => (
                          <SelectItem key={inventory.id} value={inventory.id}>
                            {inventory.name}
                          </SelectItem>
                        ))}
                    </SelectContent>
                  </Select>
                  {inventories.length === 0 && !loadingInventories && (
                    <p className="text-xs text-red-400">
                      No inventories found. Please check your Base.com account.
                    </p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="template">Template (Optional)</Label>
                  <Select
                    value={selectedTemplateId}
                    onValueChange={setSelectedTemplateId}
                  >
                    <SelectTrigger id="template">
                      <SelectValue placeholder="No template (use defaults)" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="none">No template</SelectItem>
                      {templates
                        .filter((template) => template.id)
                        .map((template) => (
                          <SelectItem key={template.id} value={template.id}>
                            {template.name}
                          </SelectItem>
                        ))}
                    </SelectContent>
                  </Select>
                  <p className="text-xs text-gray-500">
                    Templates define how product fields map to Base.com fields.
                  </p>
                </div>

                <div className="flex items-center gap-2 pt-2">
                  <Checkbox
                    id="allowDuplicateSku"
                    checked={allowDuplicateSku} onCheckedChange={(checked: boolean) => setAllowDuplicateSku(Boolean(checked))}
                    className="h-4 w-4 rounded border bg-gray-900 text-blue-500"
                  />
                  <Label htmlFor="allowDuplicateSku" className="text-sm text-gray-300">
                    Allow duplicate SKUs
                  </Label>
                </div>
                <p className="text-xs text-gray-500">
                  When unchecked, export will fail if the SKU already exists in the Base.com inventory.
                </p>
              </>
            )}
          </>
        )}
        {exportLogs.length > 0 && (
          <div className="mt-4 border-t border pt-4">
            <ExportLogViewer
              logs={exportLogs}
              isOpen={logsOpen}
              onToggle={setLogsOpen}
            />
          </div>
        )}
      </div>
    </ModalShell>
  );
}

import { useEffect, useRef, useState } from "react";
import type { Template, BaseInventory } from "@/features/data-import-export";

// Why: Base.com has complex, interconnected setup:
// - Templates define field mapping
// - Inventories require warehouses to be loaded first
// - Preferences persist across uses
// Isolating this logic makes the modal cleaner and Base-specific code testable.
export function useBaseComSettings(isBaseComIntegration: boolean, connectionId: string) {
  const [templates, setTemplates] = useState<Template[]>([]);
  const [selectedTemplateId, setSelectedTemplateId] = useState<string>("none");
  const [preferredTemplateId, setPreferredTemplateId] = useState<string | null>(null);
  const [inventories, setInventories] = useState<BaseInventory[]>([]);
  const [selectedInventoryId, setSelectedInventoryId] = useState<string>("");
  const [preferredInventoryId, setPreferredInventoryId] = useState<string | null>(null);
  const [loadingInventories, setLoadingInventories] = useState(false);
  const [allowDuplicateSku, setAllowDuplicateSku] = useState(false);
  const previousConnectionId = useRef<string>("");

  // Load templates when connection changes
  useEffect(() => {
    if (!isBaseComIntegration || !connectionId) {
      setTemplates([]);
      return;
    }

    if (previousConnectionId.current === connectionId) return;
    previousConnectionId.current = connectionId;

    void (async () => {
      try {
        const res = await fetch("/api/integrations/export-templates");
        if (!res.ok) throw new Error("Failed to load templates");
        const data = (await res.json()) as Template[];
        setTemplates(Array.isArray(data) ? data : []);
        // Load preferred template
        try {
          const prefRes = await fetch("/api/integrations/exports/base/active-template");
          if (prefRes.ok) {
            const prefData = (await prefRes.json()) as { templateId?: string | null };
            setPreferredTemplateId(prefData.templateId || null);
            setSelectedTemplateId(prefData.templateId || "none");
          }
        } catch {
          // Preference load failed, not critical
        }
      } catch (err) {
        console.error("Failed to load templates:", err);
        setTemplates([]);
      }
    })();
  }, [isBaseComIntegration, connectionId]);

  // Load inventories when connection changes
  useEffect(() => {
    if (!isBaseComIntegration || !connectionId) {
      setInventories([]);
      setLoadingInventories(false);
      return;
    }

    setLoadingInventories(true);
    void (async () => {
      try {
        const res = await fetch("/api/integrations/imports/base", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            action: "inventories",
            connectionId: connectionId,
          }),
        });
        if (!res.ok) {
          const errorText = await res.text();
          console.error(`Failed to load inventories (${res.status}):`, errorText);
          setInventories([]);
          return;
        }
        const data = (await res.json()) as {
          inventories?: BaseInventory[];
          error?: string;
        };
        if (data.error) {
          console.error("Failed to load inventories:", data.error);
          setInventories([]);
          return;
        }
        setInventories(Array.isArray(data.inventories) ? data.inventories : []);

        // Load preferred inventory
        try {
          const prefRes = await fetch("/api/integrations/exports/base/default-inventory");
          if (prefRes.ok) {
            const prefData = (await prefRes.json()) as { inventoryId?: string | null };
            setPreferredInventoryId(prefData.inventoryId || null);
            if (prefData.inventoryId) setSelectedInventoryId(prefData.inventoryId);
          }
        } catch {
          // Preference load failed, not critical
        }
      } catch (err) {
        console.error("Failed to load inventories:", err);
        setInventories([]);
      } finally {
        setLoadingInventories(false);
      }
    })();
  }, [isBaseComIntegration, connectionId]);

  // Auto-select preferred template
  useEffect(() => {
    if (!isBaseComIntegration) return;
    if (!preferredTemplateId) return;
    if (selectedTemplateId !== "none") return;
    setSelectedTemplateId(preferredTemplateId);
  }, [isBaseComIntegration, preferredTemplateId, selectedTemplateId]);

  // Auto-select preferred inventory or first available
  useEffect(() => {
    if (!isBaseComIntegration) return;
    if (selectedInventoryId) return;
    if (!inventories.length) return;
    if (loadingInventories) return;
    if (preferredInventoryId && inventories.some((inv) => inv.id === preferredInventoryId)) {
      setSelectedInventoryId(preferredInventoryId);
      return;
    }
    setSelectedInventoryId(inventories[0]?.id ?? "");
  }, [isBaseComIntegration, inventories, preferredInventoryId, selectedInventoryId, loadingInventories]);

  // Sync template preference when selected changes
  useEffect(() => {
    if (!isBaseComIntegration || !selectedTemplateId || selectedTemplateId === "none") return;
    void (async () => {
      try {
        await fetch("/api/integrations/exports/base/templates/preferred", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ templateId: selectedTemplateId }),
        });
      } catch {
        // Silent failure - preference save shouldn't block UI
      }
    })();
  }, [isBaseComIntegration, selectedTemplateId]);

  // Sync inventory preference when selected changes
  useEffect(() => {
    if (!isBaseComIntegration || !selectedInventoryId) return;
    void (async () => {
      try {
        await fetch("/api/integrations/exports/base/inventories/preferred", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ inventoryId: selectedInventoryId, connectionId }),
        });
      } catch {
        // Silent failure - preference save shouldn't block UI
      }
    })();
  }, [isBaseComIntegration, selectedInventoryId, connectionId]);

  return {
    templates,
    selectedTemplateId,
    setSelectedTemplateId,
    inventories,
    selectedInventoryId,
    setSelectedInventoryId,
    loadingInventories,
    allowDuplicateSku,
    setAllowDuplicateSku,
  };
}

import { useMemo, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import type { IntegrationWithConnections } from "@/features/integrations/types/listings";

// Why: Integration selection has complex side effects:
// - Loading integrations on mount
// - Applying initial selection from props
// - Clearing dependent state when integration changes
// Extracting prevents callback hell and makes logic reusable across modals.
export function useIntegrationSelection(
  initialIntegrationId?: string | null,
  initialConnectionId?: string | null
) {
  const [selectedIntegrationId, setSelectedIntegrationId] = useState<string>("");
  const [selectedConnectionId, setSelectedConnectionId] = useState<string>("");
  const [appliedInitialSelection, setAppliedInitialSelection] = useState(false);

  const preferredConnectionQuery = useQuery({
    queryKey: ["integrations", "base", "default-connection"],
    queryFn: async () => {
      const res = await fetch("/api/integrations/exports/base/default-connection");
      if (!res.ok) {
        throw new Error("Failed to load preferred connection");
      }
      return (await res.json()) as { connectionId?: string | null };
    },
  });

  const integrationsQuery = useQuery({
    queryKey: ["integrations", "with-connections"],
    queryFn: async () => {
      const res = await fetch("/api/integrations/with-connections");
      if (!res.ok) throw new Error("Failed to load integrations");
      return (await res.json()) as IntegrationWithConnections[];
    },
  });

  const loading = integrationsQuery.isPending;
  const integrations = useMemo(() => {
    const data = integrationsQuery.data ?? [];
    return Array.isArray(data) ? data.filter((i) => i.connections.length > 0) : [];
  }, [integrationsQuery.data]);

  const preferredConnectionId = preferredConnectionQuery.data?.connectionId ?? null;

  // Apply initial selection from props OR preferred connection
  // We do this during render to avoid useEffect warnings
  if (!loading && !appliedInitialSelection && integrations.length > 0) {
    setAppliedInitialSelection(true);

    // If explicit initial values are provided, use them (takes precedence)
    if (initialIntegrationId) {
      setSelectedIntegrationId(initialIntegrationId);
      if (initialConnectionId) {
        setSelectedConnectionId(initialConnectionId);
      }
    }
  }

  // Auto-select preferred connection when integration is selected
  // Perform check and update during render
  if (selectedIntegrationId && integrations.length > 0) {
    const integration = integrations.find((i) => i.id === selectedIntegrationId);
    if (integration) {
      const connectionIds = integration.connections?.map((conn) => conn.id) ?? [];
      const selectedIsValid =
        Boolean(selectedConnectionId) && connectionIds.includes(selectedConnectionId);

      if (!selectedIsValid) {
        if (preferredConnectionId && connectionIds.includes(preferredConnectionId)) {
          setSelectedConnectionId(preferredConnectionId);
        } else if (selectedConnectionId) {
          setSelectedConnectionId("");
        }
      }
    }
  }

  const selectedIntegration = (integrations || []).find((i) => i.id === selectedIntegrationId);
  const isBaseComIntegration = ["baselinker", "base-com"].includes(
    selectedIntegration?.slug ?? ""
  );

  return {
    integrations,
    loading,
    selectedIntegrationId,
    selectedConnectionId,
    selectedIntegration,
    isBaseComIntegration,
    setSelectedIntegrationId,
    setSelectedConnectionId,
  };
}

"use client";
import { useEffect, useState } from "react";
import type { ImageRetryPreset } from "@/features/data-import-export";
import {
  getDefaultImageRetryPresets,
  normalizeImageRetryPresets,
} from "@/features/data-import-export";

export const useImageRetryPresets = () => {
  const [presets, setPresets] = useState<ImageRetryPreset[]>(
    getDefaultImageRetryPresets()
  );

  useEffect(() => {
    let active = true;
    const loadPresets = async () => {
      try {
        const res = await fetch("/api/integrations/exports/base/image-retry-presets");
        const payload = (await res.json()) as { presets?: ImageRetryPreset[] };
        if (!res.ok) return;
        if (payload.presets && active) {
          setPresets(normalizeImageRetryPresets(payload.presets));
        }
      } catch (_error) {
        // Keep defaults on failure.
      }
    };
    void loadPresets();
    return () => {
      active = false;
    };
  }, []);

  return presets;
};

/**
 * Common utilities for product listing and export modals.
 */

export const normalizeSearchText = (value: string) =>
  value.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

/**
 * Checks if a marketplace export error message is related to images.
 * Useful for showing retry options with image transforms.
 */
export const isImageExportError = (message: string | null) => {
  if (!message) return false;
  const normalized = normalizeSearchText(message.toLowerCase());
  return (
    normalized.includes("zdjec") ||
    normalized.includes("image") ||
    normalized.includes("photo")
  );
};

"use client";

import { useToast, Button, Label } from "@/shared/ui";
import React, { useCallback, useEffect, useMemo, useState } from "react";
import { Download, RefreshCw, Save, ChevronRight, ChevronDown, Check } from "lucide-react";

import type { ExternalCategory, CategoryMappingWithDetails } from "@/features/integrations/types/category-mapping";
import type { ProductCategory, Catalog } from "@/features/products";


type BaseCategoryMapperProps = {
  connectionId: string;
  connectionName: string;
};

type ExternalCategoryWithState = ExternalCategory & {
  isExpanded?: boolean;
  mappedToId?: string | null;
};

export function BaseCategoryMapper({ connectionId, connectionName }: BaseCategoryMapperProps) {
  const [catalogs, setCatalogs] = useState<Catalog[]>([]);
  const [catalogsLoading, setCatalogsLoading] = useState(true);
  const [selectedCatalogId, setSelectedCatalogId] = useState<string | null>(null);

  const [internalCategories, setInternalCategories] = useState<ProductCategory[]>([]);
  const [internalCategoriesLoading, setInternalCategoriesLoading] = useState(false);

  const [externalCategories, setExternalCategories] = useState<ExternalCategoryWithState[]>([]);
  const [externalCategoriesLoading, setExternalCategoriesLoading] = useState(false);

  const [mappings, setMappings] = useState<CategoryMappingWithDetails[]>([]);
  const [mappingsLoading, setMappingsLoading] = useState(false);

  const [pendingMappings, setPendingMappings] = useState<Map<string, string>>(new Map());
  const [saving, setSaving] = useState(false);
  const [fetching, setFetching] = useState(false);

  const { toast } = useToast();

  // Fetch catalogs
  useEffect(() => {
    const load = async () => {
      try {
        setCatalogsLoading(true);
        const res = await fetch("/api/catalogs");
        if (!res.ok) throw new Error("Failed to fetch catalogs");
        const data = (await res.json()) as Catalog[];
        setCatalogs(data);

        // Auto-select default catalog
        const defaultCatalog = data.find((c) => c.isDefault) ?? data[0];
        if (defaultCatalog) {
          setSelectedCatalogId(defaultCatalog.id);
        }
      } catch (error) {
        console.error("Failed to fetch catalogs:", error);
        toast("Failed to load catalogs", { variant: "error" });
      } finally {
        setCatalogsLoading(false);
      }
    };
    void load();
  }, [toast]);

  // Fetch internal categories when catalog changes
  useEffect(() => {
    if (!selectedCatalogId) {
      setInternalCategories([]);
      return;
    }

    const load = async () => {
      try {
        setInternalCategoriesLoading(true);
        const res = await fetch(`/api/products/categories?catalogId=${selectedCatalogId}`);
        if (!res.ok) throw new Error("Failed to fetch categories");
        const data = (await res.json()) as ProductCategory[];
        setInternalCategories(data);
      } catch (error) {
        console.error("Failed to fetch internal categories:", error);
        toast("Failed to load internal categories", { variant: "error" });
      } finally {
        setInternalCategoriesLoading(false);
      }
    };
    void load();
  }, [selectedCatalogId, toast]);

  // Fetch external categories and mappings when connection changes
  const fetchExternalCategories = useCallback(async () => {
    try {
      setExternalCategoriesLoading(true);
      const res = await fetch(`/api/marketplace/categories?connectionId=${connectionId}`);
      if (!res.ok) throw new Error("Failed to fetch external categories");
      const data = (await res.json()) as ExternalCategory[];
      setExternalCategories(data.map((c) => ({ ...c, isExpanded: c.depth === 0 })));
    } catch (error) {
      console.error("Failed to fetch external categories:", error);
      toast("Failed to load external categories", { variant: "error" });
    } finally {
      setExternalCategoriesLoading(false);
    }
  }, [connectionId, toast]);

  const fetchMappings = useCallback(async () => {
    if (!selectedCatalogId) return;

    try {
      setMappingsLoading(true);
      const res = await fetch(
        `/api/marketplace/mappings?connectionId=${connectionId}&catalogId=${selectedCatalogId}`
      );
      if (!res.ok) throw new Error("Failed to fetch mappings");
      const data = (await res.json()) as CategoryMappingWithDetails[];
      setMappings(data);
    } catch (error) {
      console.error("Failed to fetch mappings:", error);
      toast("Failed to load category mappings", { variant: "error" });
    } finally {
      setMappingsLoading(false);
    }
  }, [connectionId, selectedCatalogId, toast]);

  useEffect(() => {
    void fetchExternalCategories();
  }, [fetchExternalCategories]);

  useEffect(() => {
    void fetchMappings();
    // Reset pending mappings when catalog changes
    setPendingMappings(new Map());
  }, [fetchMappings, selectedCatalogId]);

  // Fetch categories from Base.com API
  const handleFetchFromBase = async () => {
    try {
      setFetching(true);
      const res = await fetch("/api/marketplace/categories/fetch", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ connectionId }),
      });

      if (!res.ok) {
        const error = (await res.json()) as { error?: string };
        throw new Error(error.error || "Failed to fetch categories");
      }

      const result = (await res.json()) as { fetched: number; message: string };
      toast(result.message, { variant: "success" });

      // Refresh the list
      await fetchExternalCategories();
    } catch (error) {
      console.error("Failed to fetch from Base.com:", error);
      const message = error instanceof Error ? error.message : "Failed to fetch categories";
      toast(message, { variant: "error" });
    } finally {
      setFetching(false);
    }
  };

  // Get current mapping for an external category
  const getMappingForExternal = useCallback(
    (externalCategoryId: string): string | null => {
      // Check pending mappings first
      if (pendingMappings.has(externalCategoryId)) {
        return pendingMappings.get(externalCategoryId) ?? null;
      }
      // Check saved mappings
      const mapping = mappings.find((m) => m.externalCategoryId === externalCategoryId);
      return mapping?.internalCategoryId ?? null;
    },
    [mappings, pendingMappings]
  );

  // Handle mapping change
  const handleMappingChange = (externalCategoryId: string, internalCategoryId: string | null) => {
    setPendingMappings((prev) => {
      const next = new Map(prev);
      if (internalCategoryId) {
        next.set(externalCategoryId, internalCategoryId);
      } else {
        next.delete(externalCategoryId);
      }
      return next;
    });
  };

  // Save all pending mappings
  const handleSave = async () => {
    if (pendingMappings.size === 0 || !selectedCatalogId) {
      toast("No changes to save", { variant: "info" });
      return;
    }

    try {
      setSaving(true);
      const mappingsToSave = Array.from(pendingMappings.entries()).map(
        ([externalCategoryId, internalCategoryId]) => ({
          externalCategoryId,
          internalCategoryId,
        })
      );

      const res = await fetch("/api/marketplace/mappings/bulk", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          connectionId,
          catalogId: selectedCatalogId,
          mappings: mappingsToSave,
        }),
      });

      if (!res.ok) {
        const error = (await res.json()) as { error?: string };
        throw new Error(error.error || "Failed to save mappings");
      }

      const result = (await res.json()) as { upserted: number; message: string };
      toast(result.message, { variant: "success" });

      // Refresh mappings and clear pending
      await fetchMappings();
      setPendingMappings(new Map());
    } catch (error) {
      console.error("Failed to save mappings:", error);
      const message = error instanceof Error ? error.message : "Failed to save mappings";
      toast(message, { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  // Toggle category expansion
  const toggleExpand = (categoryId: string) => {
    setExternalCategories((prev) =>
      prev.map((c) => (c.id === categoryId ? { ...c, isExpanded: !c.isExpanded } : c))
    );
  };

  // Build tree structure for display
  const categoryTree = useMemo(() => {
    const buildLevel = (parentExternalId: string | null): ExternalCategoryWithState[] => {
      return externalCategories
        .filter((c) => c.parentExternalId === parentExternalId)
        .sort((a, b) => a.name.localeCompare(b.name));
    };

    return buildLevel(null);
  }, [externalCategories]);

  // Count statistics
  const stats = useMemo(() => {
    const total = externalCategories.length;
    const mapped = externalCategories.filter((c) => getMappingForExternal(c.id) !== null).length;
    const pending = pendingMappings.size;
    return { total, mapped, pending };
  }, [externalCategories, getMappingForExternal, pendingMappings.size]);

  // Render category row with children
  const renderCategory = (category: ExternalCategoryWithState, depth: number = 0) => {
    const children = externalCategories.filter((c) => c.parentExternalId === category.externalId);
    const hasChildren = children.length > 0;
    const isExpanded = category.isExpanded ?? false;
    const currentMapping = getMappingForExternal(category.id);
    const hasPendingChange = pendingMappings.has(category.id);

    return (
      <React.Fragment key={category.id}>
        <tr className={`border-b border-border ${hasPendingChange ? "bg-yellow-500/5" : ""}`}>
          <td className="px-4 py-2">
            <div className="flex items-center" style={{ paddingLeft: `${depth * 20}px` }}>
              {hasChildren ? (
                <Button
                  onClick={() => toggleExpand(category.id)}
                  className="mr-2 rounded p-0.5 text-gray-400 hover:bg-muted/50 hover:text-white"
                >
                  {isExpanded ? (
                    <ChevronDown className="h-4 w-4" />
                  ) : (
                    <ChevronRight className="h-4 w-4" />
                  )}
                </Button>
              ) : (
                <span className="mr-2 w-5" />
              )}
              <span className="text-sm text-gray-200">{category.name}</span>
              {currentMapping && (
                <Check className="ml-2 h-3 w-3 text-emerald-400" />
              )}
            </div>
          </td>
          <td className="px-4 py-2">
            <select
              value={currentMapping ?? ""}
              onChange={(e) =>
                handleMappingChange(category.id, e.target.value || null)
              }
              className="w-full rounded border bg-gray-800 px-2 py-1 text-sm text-white"
              disabled={internalCategoriesLoading || !selectedCatalogId}
            >
              <option value="">— Not mapped —</option>
              {internalCategories.map((ic) => (
                <option key={ic.id} value={ic.id}>
                  {ic.name}
                </option>
              ))}
            </select>
          </td>
        </tr>
        {hasChildren && isExpanded && (
          <>
            {children
              .sort((a, b) => a.name.localeCompare(b.name))
              .map((child) => renderCategory(child, depth + 1))}
          </>
        )}
      </React.Fragment>
    );
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-semibold text-white">
            Base.com Categories
          </h2>
          <p className="text-sm text-gray-400">
            Connection: {connectionName}
          </p>
        </div>

        <div className="flex items-center gap-3">
          <Button
            onClick={() => void handleFetchFromBase()}
            disabled={fetching}
            className="flex items-center gap-2 rounded-md border bg-gray-800 px-4 py-2 text-sm text-white hover:bg-gray-700 disabled:opacity-50"
          >
            {fetching ? (
              <RefreshCw className="h-4 w-4 animate-spin" />
            ) : (
              <Download className="h-4 w-4" />
            )}
            {fetching ? "Fetching..." : "Fetch Categories"}
          </Button>

          <Button
            onClick={() => void handleSave()}
            disabled={saving || pendingMappings.size === 0}
            className="flex items-center gap-2 rounded-md bg-emerald-600 px-4 py-2 text-sm font-medium text-white hover:bg-emerald-500 disabled:opacity-50"
          >
            {saving ? (
              <RefreshCw className="h-4 w-4 animate-spin" />
            ) : (
              <Save className="h-4 w-4" />
            )}
            {saving ? "Saving..." : `Save (${pendingMappings.size})`}
          </Button>
        </div>
      </div>

      {/* Catalog Selector */}
      <div className="flex items-center gap-4">
        <Label className="text-sm text-gray-400">Target Catalog:</Label>
        <select
          value={selectedCatalogId ?? ""}
          onChange={(e) => setSelectedCatalogId(e.target.value || null)}
          disabled={catalogsLoading}
          className="rounded border bg-gray-800 px-3 py-2 text-sm text-white"
        >
          {catalogsLoading && <option value="">Loading...</option>}
          {!catalogsLoading && catalogs.length === 0 && (
            <option value="">No catalogs available</option>
          )}
          {catalogs.map((catalog) => (
            <option key={catalog.id} value={catalog.id}>
              {catalog.name}
            </option>
          ))}
        </select>

        {selectedCatalogId && (
          <span className="text-xs text-gray-500">
            {internalCategories.length} internal categories
          </span>
        )}
      </div>

      {/* Stats */}
      <div className="flex gap-6 text-sm">
        <div className="text-gray-400">
          Total: <span className="text-white">{stats.total}</span>
        </div>
        <div className="text-gray-400">
          Mapped: <span className="text-emerald-400">{stats.mapped}</span>
        </div>
        {stats.pending > 0 && (
          <div className="text-gray-400">
            Unsaved changes: <span className="text-yellow-400">{stats.pending}</span>
          </div>
        )}
      </div>

      {/* Category Table */}
      <div className="overflow-hidden rounded-md border border-border">
        <table className="w-full">
          <thead>
            <tr className="border-b border-border bg-card/50">
              <th className="px-4 py-3 text-left text-xs font-medium uppercase text-gray-400">
                External Category
              </th>
              <th className="px-4 py-3 text-left text-xs font-medium uppercase text-gray-400">
                Internal Category
              </th>
            </tr>
          </thead>
          <tbody>
            {externalCategoriesLoading || mappingsLoading ? (
              <tr>
                <td colSpan={2} className="px-4 py-8 text-center text-gray-500">
                  Loading categories...
                </td>
              </tr>
            ) : externalCategories.length === 0 ? (
              <tr>
                <td colSpan={2} className="px-4 py-8 text-center text-gray-500">
                  No external categories found. Click &quot;Fetch Categories&quot; to load from Base.com.
                </td>
              </tr>
            ) : (
              categoryTree.map((category) => renderCategory(category, 0))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

"use client";

import { Button } from "@/shared/ui";
import { Store } from "lucide-react";

type Integration = {
  id: string;
  name: string;
  slug: string;
};

type Connection = {
  id: string;
  integrationId: string;
  name: string;
};

type IntegrationWithConnections = Integration & {
  connections: Connection[];
};

type MarketplaceSelectorProps = {
  integrations: IntegrationWithConnections[];
  loading: boolean;
  selectedConnectionId: string | null;
  onSelectConnection: (connectionId: string) => void;
};

export function MarketplaceSelector({
  integrations,
  loading,
  selectedConnectionId,
  onSelectConnection,
}: MarketplaceSelectorProps) {
  if (loading) {
    return (
      <div className="space-y-2">
        <h2 className="mb-4 text-sm font-semibold text-gray-300">Connections</h2>
        <div className="animate-pulse space-y-2">
          <div className="h-8 rounded bg-gray-800" />
          <div className="h-8 rounded bg-gray-800" />
        </div>
      </div>
    );
  }

  if (integrations.length === 0) {
    return (
      <div className="space-y-2">
        <h2 className="mb-4 text-sm font-semibold text-gray-300">Connections</h2>
        <p className="text-sm text-gray-500">
          No marketplace connections found. Configure a Base.com connection in{" "}
          <a href="/admin/integrations" className="text-blue-400 hover:underline">
            Integrations
          </a>{" "}
          first.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <h2 className="text-sm font-semibold text-gray-300">Connections</h2>

      {integrations.map((integration) => (
        <div key={integration.id} className="space-y-1">
