import "server-only";

import prisma from "@/shared/lib/db/prisma";
import { randomUUID } from "crypto";
import { logAgentAudit, runAgentControlLoop } from "@/features/agent-runtime/server";

type AgentQueueState = {
  running: boolean;
  timer: NodeJS.Timeout | null;
};

const globalState = globalThis as typeof globalThis & {
  __agentQueueState?: AgentQueueState;
};

const getState = (): AgentQueueState => {
  if (!globalState.__agentQueueState) {
    globalState.__agentQueueState = { running: false, timer: null };
  }
  return globalState.__agentQueueState;
};

const STUCK_RUN_THRESHOLD_MS = 10 * 60 * 1000;

export function startAgentQueue() {
  const state = getState();
  if (state.timer) return;
  void processAgentQueue();
  state.timer = setInterval(() => {
    void processAgentQueue();
  }, 2000);
}

export function stopAgentQueue() {
  const state = getState();
  if (state.timer) {
    clearInterval(state.timer);
    state.timer = null;
  }
  state.running = false;
}

export async function processAgentQueue() {
  const state = getState();
  if (state.running) return;
  state.running = true;
  const debugEnabled = process.env.DEBUG_CHATBOT === "true";
  try {
    if (!("chatbotAgentRun" in prisma)) {
      if (debugEnabled) {
        console.warn("[chatbot][agent][queue] Agent tables not initialized.");
      }
      return;
    }
    await recoverStuckRuns();
    const nextRun = await prisma.chatbotAgentRun.findFirst({
      where: { status: "queued" },
      orderBy: { createdAt: "asc" },
    });

    if (!nextRun) {
      return;
    }

    await prisma.chatbotAgentRun.update({
      where: { id: nextRun.id },
      data: {
        status: "running",
        startedAt: new Date(),
        logLines: {
          push: `[${new Date().toISOString()}] Started agent run.`,
        },
      },
    });

    try {
      await runAgentControlLoop(nextRun.id);
    } catch (error) {
      await logAgentFailure(nextRun.id, error);
    }
  } catch (error) {
    const errorId = randomUUID();
    if (debugEnabled) {
      console.error("[chatbot][agent][queue] Failed to process queue", {
        errorId,
        error,
      });
    }
  } finally {
    state.running = false;
  }
}

async function recoverStuckRuns() {
  if (!("chatbotAgentRun" in prisma)) return;
  const cutoff = new Date(Date.now() - STUCK_RUN_THRESHOLD_MS);
  const stuckRuns = await prisma.chatbotAgentRun.findMany({
    where: {
      status: "running",
      updatedAt: { lt: cutoff },
    },
    select: { id: true, planState: true },
  });
  if (stuckRuns.length === 0) return;
  for (const run of stuckRuns) {
    const resumePlanState =
      run.planState && typeof run.planState === "object"
        ? {
            ...(run.planState as Record<string, unknown>),
            resumeRequestedAt: new Date().toISOString(),
          }
        : { resumeRequestedAt: new Date().toISOString() };
    await prisma.chatbotAgentRun.update({
      where: { id: run.id },
      data: {
        status: "queued",
        requiresHumanIntervention: false,
        errorMessage: null,
        finishedAt: null,
        checkpointedAt: new Date(),
        planState: resumePlanState,
        logLines: {
          push: `[${new Date().toISOString()}] Auto-resume queued for stuck run.`,
        },
      },
    });
    await logAgentAudit(run.id, "warning", "Auto-resume queued for stuck run.", {
      reason: "stale-running",
      thresholdMs: STUCK_RUN_THRESHOLD_MS,
    });
  }
}

async function logAgentFailure(runId: string, error: unknown) {
  const errorId = randomUUID();
  await logAgentAudit(
    runId,
    "error",
    "Agent run failed while processing queue.",
    {
      errorId,
      message: error instanceof Error ? error.message : "Unknown error",
    }
  );
  await prisma.chatbotAgentRun.update({
    where: { id: runId },
    data: {
      status: "failed",
      errorMessage: error instanceof Error ? error.message : "Unknown error",
      finishedAt: new Date(),
      logLines: {
        push: `[${new Date().toISOString()}] Agent failed (${errorId}).`,
      },
    },
  });
}

import "server-only";

import type { AiPathRunRecord } from "@/shared/types/ai-paths";
import { executePathRun } from "@/features/ai-paths/services/path-run-executor";
import { getPathRunRepository } from "@/features/ai-paths/services/path-run-repository";
import { ErrorSystem } from "@/features/observability/services/error-system";

let intervalId: NodeJS.Timeout | null = null;
let activeRuns = 0;
let lastPollTime = 0;

const MAX_IDLE_MS = 120_000;
const DEFAULT_CONCURRENCY = Number(process.env.AI_PATHS_RUN_CONCURRENCY ?? "1");
const DEFAULT_MAX_ATTEMPTS = Number(process.env.AI_PATHS_RUN_MAX_ATTEMPTS ?? "3");
const DEFAULT_BACKOFF_MS = Number(process.env.AI_PATHS_RUN_BACKOFF_MS ?? "5000");
const DEFAULT_BACKOFF_MAX_MS = Number(process.env.AI_PATHS_RUN_BACKOFF_MAX_MS ?? "60000");

const isQueueHealthy = () => {
  if (!intervalId) return false;
  return Date.now() - lastPollTime < MAX_IDLE_MS;
};

const normalizeNumber = (value: number, fallback: number, min = 0) => {
  if (!Number.isFinite(value)) return fallback;
  return Math.max(min, value);
};

export const computeBackoffMs = (retryCount: number, meta?: Record<string, unknown>) => {
  const base =
    typeof meta?.backoffMs === "number" ? meta.backoffMs : DEFAULT_BACKOFF_MS;
  const max =
    typeof meta?.backoffMaxMs === "number"
      ? meta.backoffMaxMs
      : DEFAULT_BACKOFF_MAX_MS;
  const exponent = Math.max(0, retryCount);
  const raw = normalizeNumber(base * Math.pow(2, exponent), DEFAULT_BACKOFF_MS, 0);
  const capped = Math.min(raw, normalizeNumber(max, DEFAULT_BACKOFF_MAX_MS, 0));
  const jitter = Math.min(1000, Math.round(capped * 0.1));
  const withJitter = capped + (jitter > 0 ? Math.floor(Math.random() * jitter) : 0);
  return Math.max(0, withJitter);
};

export const processRun = async (run: AiPathRunRecord) => {
  console.log(`[aiPathRunQueue] Processing run ${run.id}`);
  try {
    await executePathRun(run);
    console.log(`[aiPathRunQueue] Run ${run.id} completed`);
  } catch (error) {
    const message = error instanceof Error ? error.message : "Run failed.";
    await ErrorSystem.captureException(error, {
      service: "ai-paths-queue",
      pathRunId: run.id,
      pathId: run.pathId,
    });
    const maxAttempts =
      typeof run.maxAttempts === "number" && run.maxAttempts > 0
        ? run.maxAttempts
        : DEFAULT_MAX_ATTEMPTS;
    const retryCount = (run.retryCount ?? 0) + 1;
    if (retryCount < maxAttempts) {
      const delayMs = computeBackoffMs(retryCount - 1, run.meta ?? undefined);
      const nextRetryAt = new Date(Date.now() + delayMs);
      await (getPathRunRepository()).updateRun(run.id, {
        status: "queued",
        retryCount,
        nextRetryAt,
        errorMessage: message,
        startedAt: null,
        finishedAt: null,
      });
      await (getPathRunRepository()).createRunEvent({
        runId: run.id,
        level: "warning",
        message: `Run failed. Retrying in ${Math.round(delayMs / 1000)}s.`,
        metadata: { retryCount, nextRetryAt },
      });
    } else {
      await (getPathRunRepository()).updateRun(run.id, {
        status: "dead_lettered",
        retryCount,
        finishedAt: new Date(),
        deadLetteredAt: new Date(),
        errorMessage: message,
      });
      await (getPathRunRepository()).createRunEvent({
        runId: run.id,
        level: "error",
        message: "Run moved to dead-letter after max retries.",
        metadata: { retryCount, maxAttempts },
      });
    }
  }
};

const pollQueue = async () => {
  lastPollTime = Date.now();
  const concurrency = normalizeNumber(DEFAULT_CONCURRENCY, 1, 1);
  if (activeRuns >= concurrency) return;
  const repo = getPathRunRepository();
  while (activeRuns < concurrency) {
    const run = await repo.claimNextQueuedRun();
    if (!run) break;
    activeRuns += 1;
    void processRun(run).finally(() => {
      activeRuns = Math.max(0, activeRuns - 1);
    });
  }
};

export const startAiPathRunQueue = () => {
  if (intervalId && isQueueHealthy()) {
    console.log("[aiPathRunQueue] Queue worker already running");
    return;
  }
  if (intervalId) {
    clearInterval(intervalId);
  }
  intervalId = setInterval(() => {
    void pollQueue();
  }, 1000);
  lastPollTime = Date.now();
  console.log("[aiPathRunQueue] Queue worker started");
  void pollQueue();
};

export const getAiPathRunQueueStatus = () => ({
  running: !!intervalId,
  healthy: isQueueHealthy(),
  processing: activeRuns > 0,
  activeRuns,
  concurrency: normalizeNumber(DEFAULT_CONCURRENCY, 1, 1),
  lastPollTime,
  timeSinceLastPoll: Date.now() - lastPollTime,
});

export const processSingleRun = async (runId: string) => {
  const repo = getPathRunRepository();
  const run = await repo.findRunById(runId);
  if (!run) {
    throw new Error("Run not found");
  }
  if (run.status !== "queued") {
    return;
  }
  await repo.updateRun(run.id, {
    status: "running",
    startedAt: new Date(),
  });
  await executePathRun({ ...run, status: "running" });
};

import { chatbotJobRepository } from "@/features/chatbot/services/chatbot-job-repository";
import { chatbotSessionRepository } from "@/features/chatbot/services/chatbot-session-repository";

const OLLAMA_BASE_URL = process.env.OLLAMA_BASE_URL || "http://localhost:11434";
const DEBUG_CHATBOT = process.env.NODE_ENV !== "production";

let intervalId: NodeJS.Timeout | null = null;
let isProcessing = false;

const logDebug = (message: string, meta?: Record<string, unknown>) => {
  if (!DEBUG_CHATBOT) return;
  console.info(`[chatbot][jobs] ${message}`, meta || {});
};

const fetchWithTimeout = async (url: string, init: RequestInit, timeoutMs: number) => {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(url, { ...init, signal: controller.signal });
  } finally {
    clearTimeout(timer);
  }
};

const processJob = async (jobId: string) => {
  const job = await chatbotJobRepository.findById(jobId);
  if (!job || job.status !== "running") return;

  const payload = job.payload;
  if (!payload?.model || !Array.isArray(payload?.messages)) {
    throw new Error("Invalid job payload.");
  }

  const res = await fetchWithTimeout(
    `${OLLAMA_BASE_URL}/api/chat`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        model: payload.model,
        messages: payload.messages,
        stream: false,
      }),
    },
    60000
  );

  if (!res.ok) {
    const detail = await res.text();
    throw new Error(detail || res.statusText);
  }

  const data = (await res.json()) as {
    message?: { content?: string };
    response?: string;
  };
  const reply = data.message?.content || data.response || "No response from model.";

  await chatbotSessionRepository.addMessage(job.sessionId, {
    role: "assistant",
    content: reply,
    timestamp: new Date(),
  });

  await chatbotJobRepository.update(job.id, {
    status: "completed",
    finishedAt: new Date(),
    resultText: reply.slice(0, 2000),
  });
};

export const pollQueue = async () => {
  if (isProcessing) return;
  isProcessing = true;
  try {
    const nextJob = await chatbotJobRepository.findNextPending();

    if (!nextJob) return;

    await chatbotJobRepository.update(nextJob.id, {
      status: "running",
      startedAt: new Date(),
    });

    logDebug("Processing job", { jobId: nextJob.id });

    try {
      await processJob(nextJob.id);
      logDebug("Job completed", { jobId: nextJob.id });
    } catch (error) {
      const message = error instanceof Error ? error.message : "Job failed.";
      await chatbotJobRepository.update(nextJob.id, {
        status: "failed",
        finishedAt: new Date(),
        errorMessage: message,
      });
      logDebug("Job failed", { jobId: nextJob.id, message });
    }
  } finally {
    isProcessing = false;
  }
};

export const startChatbotJobQueue = () => {

  if (intervalId) return;

  intervalId = setInterval(() => {

    void pollQueue();

  }, 2000);

  logDebug("Job queue started");

};



export const stopChatbotJobQueue = () => {

  if (intervalId) {

    clearInterval(intervalId);

    intervalId = null;

  }

  isProcessing = false;

};

