type LanguageRecord = {
  id: string;
  code: string;
  name: string;
};

type JobPayload = {
  isTest?: boolean;
  productData?: ProductFormData;
  imageUrls?: string[];
  visionOutputEnabled?: boolean;
  generationOutputEnabled?: boolean;
  languageIds?: string[];
  prompt?: string;
