import type { ThemeRecord } from "@/shared/types/notes";
import type { NoteCardProps } from "@/features/notesapp/types/notes-ui";

import { darkenColor, renderMarkdownToHtml } from "../utils";

// Hardcoded dark mode fallback theme - consistent with page styling
const FALLBACK_THEME: Omit<ThemeRecord, "id" | "createdAt" | "updatedAt" | "name" | "notebookId"> = {
  textColor: "#e5e7eb",                // gray-200
  backgroundColor: "#111827",          // gray-900
  markdownHeadingColor: "#ffffff",     // white
  markdownLinkColor: "#60a5fa",        // blue-400
  markdownCodeBackground: "#1f2937",   // gray-800
  markdownCodeText: "#e5e7eb",         // gray-200
  relatedNoteBorderWidth: 1,
  relatedNoteBorderColor: "#374151",   // gray-700
  relatedNoteBackgroundColor: "#1f2937", // gray-800
  relatedNoteTextColor: "#e5e7eb",     // gray-200
};

function NoteCardBase({
  note,
  folderTree,
  showTimestamps,
  showBreadcrumbs,
  showRelatedNotes,
  enableDrag = true,
  onSelectNote,
  onSelectFolder,
  onToggleFavorite,
  onDragStart,
  onDragEnd,
  buildBreadcrumbPath,
  theme,
}: NoteCardProps) {
  // Use provided theme or fall back to dark mode theme
  const effectiveTheme = theme ?? FALLBACK_THEME;
  const [isCopied, setIsCopied] = React.useState(false);
  const isCodeNote = note.editorType === "code";

  const contentHtml = React.useMemo(
    () => {
      let html = note.editorType === "wysiwyg"
        ? note.content
        : renderMarkdownToHtml(note.content);
      // Remove image tags from preview to avoid duplication with thumbnail
      html = html.replace(/<img[^>]*>/g, '');
      // Also remove image paragraphs (markdown renders images in <p> tags)
      html = html.replace(/<p>\s*<\/p>/g, '');
      return html;
    },
    [note.content, note.editorType]
  );
  const normalizedColor = note.color?.toLowerCase().trim();
  // Only use note's custom color if it's not white (default)
  const hasCustomColor = normalizedColor && normalizedColor !== "#ffffff";
  const backgroundColor = hasCustomColor
    ? normalizedColor
    : effectiveTheme.backgroundColor;
  const getReadableTextColor = (hexColor: string) => {
    const normalized = hexColor.replace("#", "");
    if (!/^[0-9a-fA-F]{6}$/.test(normalized)) {
      return "#111827";
    }
    const r = parseInt(normalized.slice(0, 2), 16);
    const g = parseInt(normalized.slice(2, 4), 16);
    const b = parseInt(normalized.slice(4, 6), 16);
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
    return luminance > 0.7 ? "#111827" : "#f8fafc";
  };
  const textColor = hasCustomColor
    ? getReadableTextColor(backgroundColor)
    : effectiveTheme.textColor;
  const relatedNoteStyle = {
    borderWidth: `${effectiveTheme.relatedNoteBorderWidth ?? 1}px`,
    borderColor: effectiveTheme.relatedNoteBorderColor,
    backgroundColor: effectiveTheme.relatedNoteBackgroundColor,
    color: effectiveTheme.relatedNoteTextColor,
  } as const;
  const relatedNotes = (() => {
    if (note.relations && note.relations.length > 0) {
      return note.relations;
    }

    const build = (
      id: string | undefined,
      title: string | undefined,
      color: string | null | undefined
    ) => (id ? { id, title: title ?? "Untitled note", color: color ?? null } : null);

    const fromRelations = (note.relationsFrom ?? [])
      .map((relation) =>
        build(
          relation.targetNote?.id ?? (relation as { targetNoteId?: string }).targetNoteId,
          relation.targetNote?.title,
          relation.targetNote?.color
        )
      )
      .filter((item): item is NonNullable<typeof item> => Boolean(item));

    const toRelations = (note.relationsTo ?? [])
      .map((relation) =>
        build(
          relation.sourceNote?.id ?? (relation as { sourceNoteId?: string }).sourceNoteId,
          relation.sourceNote?.title,
          relation.sourceNote?.color
        )
      )
      .filter((item): item is NonNullable<typeof item> => Boolean(item));

    return [...fromRelations, ...toRelations];
  })();
  const thumbnailFile = note.files?.find(
    (file) => file.mimetype?.startsWith("image/") && file.filepath
  );

  const handleCopyCode = async (e: React.MouseEvent) => {
    e.stopPropagation();
    try {
      await navigator.clipboard.writeText(note.content);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    } catch (err) {
      console.error("Failed to copy code:", err);
    }
  };

  return (
    <div
      key={note.id}
      draggable={enableDrag}
      onDragStart={
        enableDrag
          ? (e) => {
              e.dataTransfer.setData("noteId", note.id);
              e.dataTransfer.setData("text/plain", note.id);
              e.dataTransfer.effectAllowed = "linkMove";
              const target = e.currentTarget as HTMLElement;
              target.style.opacity = "0.5";
              onDragStart(note.id);
            }
          : undefined
      }
      onDragEnd={
        enableDrag
          ? (e) => {
              const target = e.currentTarget as HTMLElement;
              target.style.opacity = "1";
              onDragEnd();
            }
          : undefined
      }
      onClick={() => onSelectNote(note)}
      style={{
        backgroundColor,
        color: textColor,
        ["--tw-prose-body" as never]: textColor,
        ["--tw-prose-headings" as never]:
          effectiveTheme.markdownHeadingColor ?? textColor,
        ["--note-link-color" as never]: effectiveTheme.markdownLinkColor ?? "#38bdf8",
        ["--note-code-bg" as never]: effectiveTheme.markdownCodeBackground ?? "#0f172a",
        ["--note-code-text" as never]: effectiveTheme.markdownCodeText ?? "#e2e8f0",
        ["--note-inline-code-bg" as never]:
          effectiveTheme.markdownCodeBackground ?? "rgba(15, 23, 42, 0.12)",
      }}
      className={`rounded-lg border p-4 shadow-sm transition ${
        enableDrag
          ? "cursor-grab active:cursor-grabbing hover:shadow-md"
          : "cursor-pointer hover:shadow-md hover:brightness-90"
      }`}
    >
      <div className="mb-2 flex items-start justify-between gap-2">
        <div className="flex items-center gap-2">
          <h3 className="font-semibold">{note.title}</h3>
          {isCodeNote && (
            <span className="rounded bg-green-600/20 px-1.5 py-0.5 text-[10px] font-medium text-green-400 border border-green-500/30">
              CODE
            </span>
          )}
        </div>
        <div className="flex items-center gap-2">
          {isCodeNote && (
                          <Button
                            type="button"
                            onMouseDown={(event) => event.preventDefault()}
                            onClick={(e) => { void handleCopyCode(e); }}
                            className={`transition-colors ${                isCopied
                  ? "text-green-500"
                  : "text-gray-500 hover:text-blue-500"
              }`}
              aria-label={isCopied ? "Copied!" : "Copy code"}
              title={isCopied ? "Copied!" : "Copy code snippet"}
            >
              {isCopied ? <Check size={16} /> : <Copy size={16} />}
            </Button>
          )}
          <Button
            type="button"
            onMouseDown={(event) => event.preventDefault()}
            onClick={(event) => {
              event.stopPropagation();
              onToggleFavorite(note);
            }}
            className="text-gray-500 hover:text-yellow-500"
            aria-label={note.isFavorite ? "Unfavorite note" : "Favorite note"}
            title={note.isFavorite ? "Remove favorite" : "Add favorite"}
          >
            <Star
              size={16}
              className={note.isFavorite ? "fill-yellow-400 text-yellow-500" : ""}
            />
          </Button>
          {note.isPinned && <Pin size={16} className="text-blue-600" />}
        </div>
      </div>
      {thumbnailFile && (
        <div className="mb-3 overflow-hidden rounded-md border border">
          <Image
            src={thumbnailFile.filepath}
            alt={thumbnailFile.filename}
            width={320}
            height={180}
            className="h-28 w-full object-cover"
            sizes="(min-width: 1024px) 240px, 100vw"
          />
        </div>
      )}
      <div
        className="mb-3 max-h-36 overflow-hidden text-sm prose prose-sm"
        dangerouslySetInnerHTML={{ __html: contentHtml }}
      />
      <div className="flex flex-wrap gap-2">
        {note.tags.map((nt) => (
          <span
            key={nt.tagId}
            style={{ backgroundColor: nt.tag.color || "#3b82f6" }}
            className="rounded-full px-2 py-1 text-xs text-white"
          >
            {nt.tag.name}
          </span>
        ))}
      </div>
      {showTimestamps && (
        <div className="mt-3 flex flex-col gap-0.5 text-[10px] text-gray-500">
          <span>Created: {new Date(note.createdAt).toLocaleString()}</span>
          <span>Modified: {new Date(note.updatedAt).toLocaleString()}</span>
        </div>
      )}
      {showBreadcrumbs && (
        <div className={showTimestamps ? "mt-3" : "mt-2"}>
          <BreadcrumbScroller backgroundColor={darkenColor(backgroundColor, 20)}>
            {buildBreadcrumbPath(
              note.categories[0]?.categoryId || null,
              null,
              folderTree
            ).map((crumb, index, array) => (
              <React.Fragment key={index}>
                <Button
                  onClick={(e) => {
                    e.stopPropagation();
                    onSelectFolder(crumb.id);
                  }}
                  className="cursor-pointer hover:underline whitespace-nowrap"
                >
                  {crumb.name}
                </Button>
                {index < array.length - 1 && (
                  <ChevronRight size={10} className="flex-shrink-0" />
                )}
              </React.Fragment>
            ))}
          </BreadcrumbScroller>
        </div>
      )}
      {showRelatedNotes &&
        relatedNotes.length > 0 && (
          <div className="mt-2">
            <div className="flex flex-wrap gap-2">
              {relatedNotes
                .filter((item, index, array) => array.findIndex((entry) => entry.id === item.id) === index)
                .slice(0, 4)
                .map((related) => (
                  <div
                    key={related.id}
                    className="w-24 cursor-pointer rounded-md px-2 py-1 text-[10px]"
                    style={relatedNoteStyle}
                  >
                    <div className="truncate font-semibold">{related.title}</div>
                    <div className="line-clamp-2 text-[9px] opacity-80">No content</div>
                  </div>
                ))}
            </div>
          </div>
        )}
    </div>
  );
}

export const NoteCard = React.memo(NoteCardBase);
NoteCard.displayName = "NoteCard";

import { Button, useToast } from "@/shared/ui";
import React, { useState, useEffect, useMemo } from "react";
import { ChevronLeft, ChevronRight, Star, X } from "lucide-react";

import { NoteForm } from "./NoteForm";
import { buildBreadcrumbPath, renderMarkdownToHtml } from "../utils";
import type { NoteWithRelations } from "@/shared/types/notes";
import type { NoteDetailViewProps } from "@/features/notesapp/types/notes-ui";

export function NoteDetailView({
  selectedNote,
  folderTree,
  selectedFolderId,
  isFolderTreeCollapsed,
  onExpandFolderTree,
  setSelectedFolderId,
  setSelectedNote,
  isEditing,
  setIsEditing,
  onToggleFavorite,
  onDeleteNote,
  tags,
  selectedNotebookId,
  onUpdateSuccess,
  fetchTags,
  selectedNoteTheme,
  onSelectRelatedNote,
  onFilterByTag,
  onUnlinkRelatedNote,
}: NoteDetailViewProps) {
  const { toast } = useToast();
  const [relatedPreviewNotes, setRelatedPreviewNotes] = useState<Record<string, NoteWithRelations>>({});

  const relatedNotes = useMemo(() => {
    if (!selectedNote) return [];
    if (selectedNote.relations && selectedNote.relations.length > 0) {
      return selectedNote.relations;
    }

    const build = (
      id: string | undefined,
      title: string | undefined,
      color: string | null | undefined
    ) => (id ? { id, title: title ?? "Untitled note", color: color ?? null } : null);

    const fromRelations = (selectedNote.relationsFrom ?? [])
      .map((relation) =>
        build(
          relation.targetNote?.id ?? (relation as { targetNoteId?: string }).targetNoteId,
          relation.targetNote?.title,
          relation.targetNote?.color
        )
      )
      .filter((item): item is NonNullable<typeof item> => Boolean(item));

    const toRelations = (selectedNote.relationsTo ?? [])
      .map((relation) =>
        build(
          relation.sourceNote?.id ?? (relation as { sourceNoteId?: string }).sourceNoteId,
          relation.sourceNote?.title,
          relation.sourceNote?.color
        )
      )
      .filter((item): item is NonNullable<typeof item> => Boolean(item));

    return [...fromRelations, ...toRelations];
  }, [selectedNote]);

  const relationIds = useMemo(
    () =>
      relatedNotes
        .map((rel) => rel.id)
        .filter(
          (id, index, array) => array.findIndex((entry) => entry === id) === index
        ),
    [relatedNotes]
  );

  useEffect(() => {
    if (!selectedNote || relationIds.length === 0) return;
    let isActive = true;
    const fetchRelated = async () => {
      try {
        const notes = await Promise.all(
          relationIds.map(async (id) => {
            try {
              const res = await fetch(`/api/notes/${id}`, { cache: "no-store" });
              if (!res.ok) return null;
              return (await res.json()) as NoteWithRelations;
            } catch {
              return null;
            }
          })
        );
        if (!isActive) return;
        const nextMap: Record<string, NoteWithRelations> = {};
        notes.filter(Boolean).forEach((note) => {
          if (note) nextMap[note.id] = note;
        });
        setRelatedPreviewNotes(nextMap);
      } catch (error) {
        console.error("Failed to load related notes:", error);
      }
    };

    void fetchRelated();
    return () => {
      isActive = false;
    };
  }, [selectedNote, relationIds]);

  const getReadableTextColor = (hexColor: string) => {
    const normalized = hexColor.replace("#", "");
    if (!/^[0-9a-fA-F]{6}$/.test(normalized)) {
      return "#f8fafc";
    }
    const r = parseInt(normalized.slice(0, 2), 16);
    const g = parseInt(normalized.slice(2, 4), 16);
    const b = parseInt(normalized.slice(4, 6), 16);
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
    return luminance > 0.7 ? "#0f172a" : "#f8fafc";
  };

  const fallbackTheme = useMemo(
    () => ({
      textColor: "#e5e7eb",
      backgroundColor: "#111827",
      markdownHeadingColor: "#f9fafb",
      markdownLinkColor: "#93c5fd",
      markdownCodeBackground: "#1f2937",
      markdownCodeText: "#e5e7eb",
      relatedNoteBorderWidth: 1,
      relatedNoteBorderColor: "#374151",
      relatedNoteBackgroundColor: "#1f2937",
      relatedNoteTextColor: "#e5e7eb",
    }),
    []
  );

  const effectivePreviewTheme = selectedNoteTheme ?? fallbackTheme;

  const previewStyle = (() => {
    const normalizedColor = selectedNote?.color?.toLowerCase().trim();
    const isDefaultColor = !normalizedColor || normalizedColor === "#ffffff";
    const color =
      !isDefaultColor
        ? normalizedColor ?? selectedNote?.color ?? effectivePreviewTheme.backgroundColor
        : effectivePreviewTheme.backgroundColor ||
          normalizedColor ||
          selectedNote?.color ||
          "#1f2937";
    const hex = color.replace("#", "");
    if (!/^[0-9a-fA-F]{6}$/.test(hex)) {
      return { backgroundColor: color };
    }
    const r = parseInt(hex.slice(0, 2), 16);
    const g = parseInt(hex.slice(2, 4), 16);
    const b = parseInt(hex.slice(4, 6), 16);
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
    const borderColor = luminance > 0.78 ? "rgba(15, 23, 42, 0.35)" : "rgba(148, 163, 184, 0.2)";
    return {
      backgroundColor: color,
      borderColor,
      boxShadow: luminance > 0.78 ? "0 0 0 1px rgba(15, 23, 42, 0.12)" : undefined,
    };
  })();

  const previewTextColor = (() => {
    const normalizedColor = selectedNote?.color?.toLowerCase().trim();
    const isDefaultColor = !normalizedColor || normalizedColor === "#ffffff";
    const background =
      !isDefaultColor
        ? normalizedColor ?? selectedNote?.color ?? effectivePreviewTheme.backgroundColor
        : effectivePreviewTheme.backgroundColor ||
          normalizedColor ||
          selectedNote?.color ||
          "#1f2937";
    if (effectivePreviewTheme.textColor && !isDefaultColor) {
      return getReadableTextColor(background);
    }
    return effectivePreviewTheme.textColor ?? getReadableTextColor(background);
  })();

  const previewTypographyStyle = useMemo(
    () => ({
      color: previewTextColor,
      ["--tw-prose-body" as never]: previewTextColor,
      ["--tw-prose-headings" as never]:
        effectivePreviewTheme.markdownHeadingColor ?? previewTextColor,
      ["--tw-prose-lead" as never]: previewTextColor,
      ["--tw-prose-bold" as never]: previewTextColor,
      ["--tw-prose-counters" as never]: previewTextColor,
      ["--tw-prose-bullets" as never]: previewTextColor,
      ["--tw-prose-quotes" as never]: previewTextColor,
      ["--tw-prose-quote-borders" as never]: "rgba(148, 163, 184, 0.35)",
      ["--tw-prose-hr" as never]: "rgba(148, 163, 184, 0.35)",
      ["--note-link-color" as never]:
        effectivePreviewTheme.markdownLinkColor ?? "#38bdf8",
      ["--note-code-bg" as never]:
        effectivePreviewTheme.markdownCodeBackground ?? "#0f172a",
      ["--note-code-text" as never]:
        effectivePreviewTheme.markdownCodeText ?? "#e2e8f0",
      ["--note-inline-code-bg" as never]:
        effectivePreviewTheme.markdownCodeBackground ?? "rgba(15, 23, 42, 0.12)",
    }),
    [
      previewTextColor,
      effectivePreviewTheme,
    ]
  );

  const relatedPreviewStyle = useMemo(
    () => ({
      borderWidth: `${effectivePreviewTheme.relatedNoteBorderWidth ?? 1}px`,
      borderColor:
        effectivePreviewTheme.relatedNoteBorderColor ?? "rgba(15, 23, 42, 0.2)",
      backgroundColor:
        effectivePreviewTheme.relatedNoteBackgroundColor ??
        "rgba(15, 23, 42, 0.05)",
      color: effectivePreviewTheme.relatedNoteTextColor ?? "#f8fafc",
    }),
    [
      effectivePreviewTheme,
    ]
  );

  return (
    <div className="flex h-full flex-col">
      {/* Breadcrumb for selected note */}
      <div className="mb-4 flex items-center gap-2 text-sm text-gray-400">
        {isFolderTreeCollapsed && (
          <Button
            onClick={onExpandFolderTree}
            variant="outline"
            className="border text-gray-300 hover:bg-muted/50 hover:text-white"
          >
            <ChevronLeft className="-scale-x-100" size={16} />
            <span className="ml-2">Show Folders</span>
          </Button>
        )}
        {buildBreadcrumbPath(
          selectedNote.categories[0]?.categoryId || null,
          selectedNote.title,
          folderTree
        ).map((crumb, index, array) => (
          <React.Fragment key={index}>
            {crumb.isNote ? (
              <span className="text-gray-300">{crumb.name}</span>
            ) : (
              <Button
                variant="link"
                onClick={() => {
                  setSelectedFolderId(crumb.id);
                  setSelectedNote(null);
                  setIsEditing(false);
                }}
                className="h-auto p-0 text-gray-400 hover:text-blue-400 transition"
              >
                {crumb.name}
              </Button>
            )}
            {index < array.length - 1 && (
              <ChevronRight size={16} className="text-gray-600" />
            )}
          </React.Fragment>
        ))}
      </div>

      <div className="mb-4 flex items-center gap-4">
        <Button
          onClick={() => {
            if (isEditing) {
              setIsEditing(false);
            } else {
              setSelectedNote(null);
            }
          }}
          className="min-w-[80px] border border-white/20 hover:border-white/40"
        >
          Back
        </Button>
        <Button
          type="button"
          onClick={() => onToggleFavorite(selectedNote)}
          className="flex items-center gap-2 border border-white/20 hover:border-white/40"
        >
          <Star
            size={16}
            className={selectedNote.isFavorite ? "fill-yellow-400 text-yellow-500" : ""}
          />
          <span className="text-sm">
            {selectedNote.isFavorite ? "Favorited" : "Favorite"}
          </span>
        </Button>
        {!isEditing ? (
          <Button
            onClick={() => setIsEditing(true)}
            className="min-w-[80px] border border-white/20 hover:border-white/40"
          >
            Edit
          </Button>
        ) : (
          <>
            <Button
              type="button"
              form="note-edit-form"
              onClick={() => {
                const form = document.getElementById("note-edit-form") as HTMLFormElement;
                form?.requestSubmit();
              }}
              className="min-w-[80px] border border-white/20 hover:border-white/40"
            >
              Update
            </Button>
            <Button
              type="button"
              onClick={() => setIsEditing(false)}
              className="min-w-[80px] border border-white/20 hover:border-white/40"
            >
              Cancel
            </Button>
            <Button
              type="button"
              onClick={() => { void onDeleteNote(); }}
              className="min-w-[80px] border border-red-500/20 hover:border-red-500/40 text-red-400"
            >
              Delete
            </Button>
          </>
        )}
      </div>

      {isEditing ? (
        <div className="flex-1 overflow-y-auto">
          <NoteForm
            note={selectedNote}
            folderTree={folderTree}
            defaultFolderId={selectedFolderId}
            availableTags={tags}
            notebookId={selectedNotebookId}
            onSuccess={onUpdateSuccess}
            onTagCreated={fetchTags}
            folderTheme={selectedNoteTheme}
            onSelectRelatedNote={onSelectRelatedNote}
            onTagClick={onFilterByTag}
          />
        </div>
      ) : (
        <div
          className="flex-1 overflow-y-auto rounded-lg border border-border bg-gray-900 p-6 cursor-text"
          onDoubleClick={() => setIsEditing(true)}
          style={previewStyle}
        >
          <h1
            className="mb-4 text-3xl font-bold"
            style={{ color: previewTextColor }}
          >
            {selectedNote.title}
          </h1>
          <div
            className="prose max-w-none"
            style={previewTypographyStyle}
            dangerouslySetInnerHTML={{
              __html:
                selectedNote.editorType === "wysiwyg"
                  ? selectedNote.content
                  : renderMarkdownToHtml(selectedNote.content),
            }}
            onMouseOver={(e) => {
              const target = e.target;
              if (!(target instanceof HTMLElement)) return;
              const wrapper = target.closest("[data-code]");
              const button = wrapper?.querySelector("[data-copy-code]");
              if (button instanceof HTMLElement) button.style.opacity = "1";
            }}
            onMouseOut={(e) => {
              const target = e.target;
              if (!(target instanceof HTMLElement)) return;
              const wrapper = target.closest("[data-code]");
              const button = wrapper?.querySelector("[data-copy-code]");
              if (button instanceof HTMLElement) button.style.opacity = "0";
            }}
            onClick={(e) => {
              const target = e.target;
              if (!(target instanceof HTMLElement)) return;
              const copyButton = target.closest("[data-copy-code]");
              if (!(copyButton instanceof HTMLButtonElement)) return;
              const wrapper = copyButton.closest("[data-code]");
              const encoded = wrapper?.getAttribute("data-code");
              if (!encoded) return;
              const originalLabel = copyButton.textContent;
              navigator.clipboard
                .writeText(decodeURIComponent(encoded))
                .then(() => {
                  copyButton.textContent = "Copied";
                  window.setTimeout(() => {
                    copyButton.textContent = originalLabel ?? "Copy";
                  }, 1500);
                })
                .catch(() => toast("Failed to copy code", { variant: "error" }));
            }}
          />
          {relatedNotes.length > 0 && (
            <div className="mt-6 space-y-4">
              <div className="space-y-2">
                <div className="text-xs uppercase tracking-wide text-gray-400">
                  Related Notes
                </div>
                <div className="flex flex-wrap gap-2">
                  {relatedNotes
                    .filter(
                      (noteItem, index, array) =>
                        array.findIndex((item) => item.id === noteItem.id) === index
                    )
                    .map((related) => {
                      const relatedNote = relatedPreviewNotes[related.id];
                      return (
                        <div
                          key={related.id}
                          className="relative w-40 cursor-pointer rounded-md border px-3 py-2 text-left text-xs transition"
                          style={relatedPreviewStyle}
                          role="button"
                          tabIndex={0}
                          onClick={() => onSelectRelatedNote(related.id)}
                          onKeyDown={(event) => {
                            if (event.key === "Enter" || event.key === " ") {
                              event.preventDefault();
                              onSelectRelatedNote(related.id);
                            }
                          }}
                        >
                          <div className="truncate font-semibold">
                            {relatedNote?.title ?? related.title}
                          </div>
                          <div className="line-clamp-2 text-[11px] opacity-80">
                            {relatedNote?.content ?? "No content"}
                          </div>
                          <Button
                            type="button"
                            onClick={(event) => {
                              event.stopPropagation();
                              void onUnlinkRelatedNote(related.id);
                            }}
                            className="absolute right-2 top-2 opacity-70 hover:opacity-100"
                            aria-label="Unlink related note"
                          >
                            <X size={12} />
                          </Button>
                        </div>
                      );
                    })}
                </div>
              </div>
            </div>
          )}
          <div className="mt-8 pt-4 border-t border-border flex gap-6 text-sm text-gray-500">
            <span>Created: {new Date(selectedNote.createdAt).toLocaleString()}</span>
            <span>Modified: {new Date(selectedNote.updatedAt).toLocaleString()}</span>
          </div>
        </div>
      )}
    </div>
  );
}

import React from "react";
import { Button, ListPanel } from "@/shared/ui";

import { Plus, Pin, Archive, ChevronLeft, ChevronRight } from "lucide-react";


import { NotesFilters } from "./NotesFilters";
import { NoteCard } from "./NoteCard";
import { buildBreadcrumbPath } from "../utils";
import type { NoteListViewProps } from "@/features/notesapp/types/notes-ui";

export function NoteListView({
  loading,
  sortedNotes,
  pagedNotes,
  page,
  totalPages,
  setPage,
  pageSize,
  setPageSize,
  selectedFolderId,
  folderTree,
  isFolderTreeCollapsed,
  onExpandFolderTree,
  onCreateNote,
  selectedFolderThemeId,
  themes,
  onThemeChange,
  availableTagsInScope,
  filterTagIds,
  setFilterTagIds,
  searchQuery,
  setSearchQuery,
  searchScope,
  updateSettings,
  sortBy,
  sortOrder,
  showTimestamps,
  showBreadcrumbs,
  showRelatedNotes,
  viewMode,
  gridDensity,
  highlightTagId,
  filterPinned,
  setFilterPinned,
  filterArchived,
  setFilterArchived,
  noteLayoutClassName,
  getThemeForNote,
  onSelectNote,
  onSelectFolderFromCard,
  onToggleFavorite,
  onDragStart,
  onDragEnd,
  setSelectedFolderId,
  setSelectedNote,
  setIsEditing,
}: NoteListViewProps) {
  return (
    <ListPanel
      variant="flat"
      className="flex min-h-0 flex-1 flex-col"
      header={
        <div className="flex items-center gap-3">
          {isFolderTreeCollapsed && (
            <Button
              onClick={onExpandFolderTree}
              variant="outline"
              className="border text-gray-300 hover:bg-muted/50 hover:text-white"
            >
              <ChevronLeft className="-scale-x-100" size={16} />
              <span className="ml-2">Show Folders</span>
            </Button>
          )}
          <Button
            onClick={onCreateNote}
            className="size-11 rounded-full bg-primary p-0 text-primary-foreground hover:bg-primary/90"
            aria-label="Create note"
          >
            <Plus className="size-5" />
          </Button>
          <h1 className="text-3xl font-bold text-white">
            {selectedFolderId
              ? buildBreadcrumbPath(selectedFolderId, null, folderTree).slice(-1)[0]?.name
              : "Notes"}
          </h1>
          <div className="flex items-center gap-2">
            <span className="text-xs text-gray-500">Theme</span>
            <select
              value={selectedFolderThemeId}
              onChange={(e) => onThemeChange(e.target.value || null)}
              className="rounded border bg-gray-800 px-2 py-1 text-xs text-gray-300"
            >
              <option value="">Default</option>
              {themes.map((theme) => (
                <option key={theme.id} value={theme.id}>
                  {theme.name}
                </option>
              ))}
            </select>
          </div>
          <div className="ml-auto flex items-center gap-2">
            <span className="text-xs text-gray-500">Page</span>
            <Button
              type="button"
              onClick={() => setPage(Math.max(1, page - 1))}
              disabled={page <= 1}
              className="rounded px-2 py-1 text-xs bg-gray-800 text-gray-400 hover:bg-gray-700 transition disabled:opacity-50"
            >
              Prev
            </Button>
            <span className="text-xs text-gray-300">
              {page} / {totalPages}
            </span>
            <Button
              type="button"
              onClick={() => setPage(Math.min(totalPages, page + 1))}
              disabled={page >= totalPages}
              className="rounded px-2 py-1 text-xs bg-gray-800 text-gray-400 hover:bg-gray-700 transition disabled:opacity-50"
            >
              Next
            </Button>
            <select
              value={pageSize}
              onChange={(e) => {
                setPageSize(Number(e.target.value));
                setPage(1);
              }}
              className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-300 border border"
              aria-label="Notes per page"
            >
              {[12, 24, 48].map((size) => (
                <option key={size} value={size}>
                  {size} / page
                </option>
              ))}
            </select>
          </div>
        </div>
      }
      filters={
        <div className="flex gap-4">
          <NotesFilters
            selectedFolderId={selectedFolderId}
            folderTree={folderTree}
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            tags={availableTagsInScope}
            filterTagIds={filterTagIds}
            setFilterTagIds={setFilterTagIds}
            searchScope={searchScope}
            updateSettings={updateSettings}
            sortBy={sortBy}
            sortOrder={sortOrder}
            showTimestamps={showTimestamps}
            showBreadcrumbs={showBreadcrumbs}
            showRelatedNotes={showRelatedNotes}
            viewMode={viewMode}
            gridDensity={gridDensity}
            highlightTagId={highlightTagId}
            buildBreadcrumbPath={buildBreadcrumbPath}
          />
          <Button
            onClick={() => setFilterPinned(filterPinned === true ? undefined : true)}
            className={`rounded-lg border px-4 py-2 ${
              filterPinned === true
                ? "border-blue-500 bg-blue-600 text-white"
                : "border bg-gray-800 text-gray-300"
            }`}
          >
            <Pin size={20} />
          </Button>
          <Button
            onClick={() => setFilterArchived(filterArchived === true ? undefined : true)}
            className={`rounded-lg border px-4 py-2 ${
              filterArchived === true
                ? "border-gray-500 bg-gray-700 text-white"
                : "border bg-gray-800 text-gray-300"
            }`}
          >
            <Archive size={20} />
          </Button>
        </div>
      }
      contentClassName="flex min-h-0 flex-1 flex-col overflow-y-auto pr-1"
    >
        {/* Breadcrumb */}
        {selectedFolderId && (
          <div className="mb-6 flex items-center gap-2 text-sm text-gray-400">
            {buildBreadcrumbPath(selectedFolderId, null, folderTree).map((crumb, index, array) => (
              <React.Fragment key={index}>
                <Button
                  onClick={() => {
                    setSelectedFolderId(crumb.id);
                    setSelectedNote(null);
                    setIsEditing(false);
                  }}
                  className="hover:text-blue-400 transition"
                >
                  {crumb.name}
                </Button>
                {index < array.length - 1 && (
                  <ChevronRight size={16} className="text-gray-600" />
                )}
              </React.Fragment>
            ))}
          </div>
        )}

        {/* Notes Grid */}
        {loading ? (
          <div className="text-center text-gray-400">Loading...</div>
        ) : sortedNotes.length === 0 ? (
          <div className="rounded-lg border border-dashed border p-12 text-center text-gray-400">
            No notes found. Create your first note!
          </div>
        ) : (
          <div className={noteLayoutClassName}>
            {pagedNotes.map((note) => (
              <NoteCard
                key={note.id}
                note={note}
                theme={getThemeForNote(note)}
                folderTree={folderTree}
                showTimestamps={showTimestamps}
                showBreadcrumbs={showBreadcrumbs}
                showRelatedNotes={showRelatedNotes}
                enableDrag={!isFolderTreeCollapsed}
                onSelectNote={onSelectNote}
                onSelectFolder={onSelectFolderFromCard}
                onToggleFavorite={onToggleFavorite}
                onDragStart={onDragStart}
                onDragEnd={onDragEnd}
                buildBreadcrumbPath={buildBreadcrumbPath}
              />
            ))}
          </div>
        )}
        {sortedNotes.length > pageSize && (
          <div className="mt-6 flex items-center justify-center gap-3 text-sm text-gray-300">
            <Button
              type="button"
              onClick={() => setPage(Math.max(1, page - 1))}
              disabled={page <= 1}
              className="rounded border px-3 py-1.5 text-gray-300 hover:bg-muted/50 disabled:opacity-50"
            >
              Previous
            </Button>
            <span>
              Page {page} of {totalPages}
            </span>
            <Button
              type="button"
              onClick={() => setPage(Math.min(totalPages, page + 1))}
              disabled={page >= totalPages}
              className="rounded border px-3 py-1.5 text-gray-300 hover:bg-muted/50 disabled:opacity-50"
            >
              Next
            </Button>
          </div>
        )}
    </ListPanel>
  );
}

"use client";

import React from "react";
import { Button, Input } from "@/shared/ui";

import { Search, FileText, Heading, X, ArrowUp, ArrowDown, Eye, EyeOff, LayoutGrid, List, ChevronDown, Check } from "lucide-react";
import type { NotesFiltersProps } from "@/features/notesapp/types/notes-ui";


export function NotesFilters({
  selectedFolderId,
  folderTree,
  searchQuery,
  setSearchQuery,
  tags,
  filterTagIds,
  setFilterTagIds,
  searchScope,
  updateSettings,
  sortBy,
  sortOrder,
  showTimestamps,
  showBreadcrumbs,
  showRelatedNotes,
  viewMode,
  gridDensity,
  highlightTagId,
  buildBreadcrumbPath,
