  REDACTED_VALUE,
  truncateString,
} from "@/shared/lib/observability/log-redaction";

type ClientErrorContext = Record<string, unknown>;

export type ClientErrorPayload = {
  message: string;
  name?: string;
  stack?: string | null;
  digest?: string;
  url?: string;
  userAgent?: string;
  componentStack?: string | null;
  context?: ClientErrorContext | null;
  timestamp?: string;
};

const MAX_CONTEXT_SIZE = 6000;
const MAX_VALUE_LENGTH = 2000;
let baseContext: ClientErrorContext = {};

export const setClientErrorBaseContext = (context: ClientErrorContext) => {
  baseContext = { ...baseContext, ...context };
};

const safeSerialize = (value: unknown) => {
  try {
    const seen = new WeakSet();
    const json = JSON.stringify(value, (_key, val: unknown) => {
      if (_key && isSensitiveKey(_key)) return REDACTED_VALUE;
      if (typeof val === "object" && val !== null) {
        if (seen.has(val)) return "[Circular]";
        seen.add(val);
      }
      if (typeof val === "function") return "[Function]";
      if (typeof val === "bigint") return val.toString();
      if (typeof val === "string") return truncateString(val, MAX_VALUE_LENGTH);
      return val;
    });
    if (!json) return null;
    if (json.length > MAX_CONTEXT_SIZE) {
      return { truncated: true, preview: json.slice(0, MAX_CONTEXT_SIZE) };
    }
    return JSON.parse(json) as Record<string, unknown>;
  } catch {
    return { error: "Failed to serialize context." };
  }
};

const buildPayload = (
  error: unknown,
  extra?: {
    digest?: string;
    componentStack?: string | null;
    context?: ClientErrorContext | null;
  }
): ClientErrorPayload => {
  const payload: ClientErrorPayload = {
    message: "Unknown client error",
    timestamp: new Date().toISOString(),
    ...(typeof window !== "undefined"
      ? { url: window.location.href, userAgent: navigator.userAgent }
      : {}),
    ...(extra?.digest ? { digest: extra.digest } : {}),
    ...(extra?.componentStack ? { componentStack: extra.componentStack } : {}),
  };

  if (error instanceof Error) {
    payload.message = error.message;
    payload.name = error.name;
    payload.stack = error.stack ?? null;
  } else if (typeof error === "string") {
    payload.message = error;
  } else if (error && typeof error === "object") {
    payload.message =
      (error as { message?: string }).message ?? "Unknown client error";
    const errorName = (error as { name?: string }).name;
    if (errorName) payload.name = errorName;
  }

  const mergedContext =
    extra?.context || Object.keys(baseContext).length > 0
      ? { ...baseContext, ...(extra?.context ?? {}) }
      : null;
  if (mergedContext) {
    const serialized = safeSerialize(mergedContext);
    if (serialized) payload.context = serialized as ClientErrorContext;
  }

  return payload;
};

export const logClientError = (
  error: unknown,
  extra?: {
    digest?: string;
    componentStack?: string | null;
    context?: ClientErrorContext | null;
  }
) => {
  if (typeof window === "undefined") return;
  const payload = buildPayload(error, extra);
  const body = JSON.stringify(payload);

  try {
    if (navigator.sendBeacon) {
      const blob = new Blob([body], { type: "application/json" });
      navigator.sendBeacon("/api/client-errors", blob);
      return;
    }
  } catch {
    // fall back to fetch
  }

  void fetch("/api/client-errors", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body,
    keepalive: true,
  });
};

let handlerAttached = false;

export const initClientErrorReporting = () => {
  if (handlerAttached || typeof window === "undefined") return;
  handlerAttached = true;

  // Expose for Playwright tests in non-production environments
  if (process.env.NODE_ENV !== 'production') {
    (window as any)._logClientError = logClientError;
  }

  window.addEventListener("error", (event) => {
    logClientError(event.error ?? event.message, {
      context: {
        source: "window.error",
        filename: event.filename,
        lineno: event.lineno,
        colno: event.colno,
      },
    });
  });

  window.addEventListener("unhandledrejection", (event) => {
    logClientError(event.reason ?? "Unhandled promise rejection", {
      context: { source: "window.unhandledrejection" },
    });
  });
};

"use client";

import { Button, AppModal, Input, Label, ModalShell, Textarea, useToast, SectionHeader, SectionPanel, Card } from "@/shared/ui";
import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import { Pencil, Plus, Trash2 } from "lucide-react";








import { serializeSetting } from "@/shared/utils/settings-json";


import { PlaywrightSettingsForm } from "@/features/playwright/components/PlaywrightSettingsForm";
import { PLAYWRIGHT_PERSONA_SETTINGS_KEY } from "@/features/playwright/constants/playwright";
import type {
  PlaywrightPersona,
  PlaywrightSettings,
} from "@/features/playwright/types";
import {
  buildPlaywrightSettings,
  createPlaywrightPersonaId,
  fetchPlaywrightPersonas,
} from "@/features/playwright/utils/personas";

const formatTimestamp = (value?: string) => {
  if (!value) return "Not set";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "Not set";
  return date.toLocaleString();
};

const buildSummaryTags = (settings: PlaywrightSettings) => {
  const tags = [
    settings.headless ? "Headless" : "Headful",
    settings.emulateDevice ? `Device: ${settings.deviceName}` : "Device: default",
    `Timeout: ${settings.timeout}ms`,
    settings.proxyEnabled ? "Proxy: on" : "Proxy: off",
  ];
  if (settings.slowMo > 0) {
    tags.push(`SlowMo: ${settings.slowMo}ms`);
  }
  return tags;
};

export function PlaywrightPersonasPage() {
  const { toast } = useToast();
  const [personas, setPersonas] = useState<PlaywrightPersona[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [draftName, setDraftName] = useState("");
  const [draftDescription, setDraftDescription] = useState("");
  const [draftSettings, setDraftSettings] = useState<PlaywrightSettings>(
    buildPlaywrightSettings()
  );

  const sortedPersonas = useMemo(() => {
    return [...personas].sort((a, b) => {
      const left = a.updatedAt ?? a.createdAt ?? "";
      const right = b.updatedAt ?? b.createdAt ?? "";
      return right.localeCompare(left);
    });
  }, [personas]);

  useEffect(() => {
    let active = true;
    const loadPersonas = async () => {
      try {
        const stored = await fetchPlaywrightPersonas();
        if (!active) return;
        setPersonas(stored);
      } catch (error) {
        if (active) {
          const message =
            error instanceof Error ? error.message : "Failed to load personas.";
          toast(message, { variant: "error" });
        }
      } finally {
        if (active) setLoading(false);
      }
    };
    void loadPersonas();
    return () => {
      active = false;
    };
  }, [toast]);

  const resetDraft = () => {
    setEditingId(null);
    setDraftName("");
    setDraftDescription("");
    setDraftSettings(buildPlaywrightSettings());
  };

  const openCreate = () => {
    resetDraft();
    setModalOpen(true);
  };

  const openEdit = (persona: PlaywrightPersona) => {
    setEditingId(persona.id);
    setDraftName(persona.name);
    setDraftDescription(persona.description ?? "");
    setDraftSettings(buildPlaywrightSettings(persona.settings));
    setModalOpen(true);
  };

  const closeModal = () => {
    setModalOpen(false);
    resetDraft();
  };

  const persistPersonas = async (next: PlaywrightPersona[], message: string) => {
    try {
      setSaving(true);
      const res = await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          key: PLAYWRIGHT_PERSONA_SETTINGS_KEY,
          value: serializeSetting(next),
        }),
      });
      if (!res.ok) {
        const payload = (await res.json().catch(() => null)) as {
          error?: string;
        } | null;
        throw new Error(payload?.error || "Failed to save personas.");
      }
      setPersonas(next);
      toast(message, { variant: "success" });
      return true;
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : "Failed to save personas.";
      toast(errorMessage, { variant: "error" });
      return false;
    } finally {
      setSaving(false);
    }
  };

  const handleSavePersona = async () => {
    const name = draftName.trim();
    if (!name) {
      toast("Persona name is required.", { variant: "error" });
      return;
    }

    const now = new Date().toISOString();
    const existing = personas.find((persona) => persona.id === editingId);
    const nextPersona: PlaywrightPersona = {
      id: existing?.id ?? createPlaywrightPersonaId(),
      name,
      description: draftDescription.trim() || null,
      settings: buildPlaywrightSettings(draftSettings),
      createdAt: existing?.createdAt ?? now,
      updatedAt: now,
    };

    const next = existing
      ? personas.map((persona) =>
          persona.id === existing.id ? nextPersona : persona
        )
      : [...personas, nextPersona];

    const saved = await persistPersonas(
      next,
      existing ? "Persona updated." : "Persona created."
    );
    if (saved) closeModal();
  };

  const handleDeletePersona = async (persona: PlaywrightPersona) => {
    const confirmed = window.confirm(`Delete persona "${persona.name}"?`);
    if (!confirmed) return;
    const next = personas.filter((item) => item.id !== persona.id);
    await persistPersonas(next, "Persona deleted.");
  };

  return (
    <div className="container mx-auto py-10 space-y-6">
      <SectionHeader
        title="Playwright Personas"
        description="Centralize browser automation settings to reuse across integrations and chatbot flows."
        eyebrow={(
          <Link href="/admin/settings" className="text-blue-300 hover:text-blue-200">
            ← Back to settings
          </Link>
        )}
        actions={
          <Button onClick={openCreate} className="gap-2">
            <Plus className="size-4" />
            New Persona
          </Button>
        }
      />

      <SectionPanel className="p-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-sm font-semibold text-white">Persona library</p>
            <p className="mt-1 text-xs text-gray-400">
              Assign these presets wherever Playwright is used.
            </p>
          </div>
          <div className="text-xs text-gray-500">
            {loading ? "Loading..." : `${personas.length} persona(s)`}
          </div>
        </div>
      </SectionPanel>

      {loading ? (
        <div className="rounded-md border border-dashed border-border p-6 text-center text-sm text-gray-400">
          Loading personas...
        </div>
      ) : sortedPersonas.length === 0 ? (
        <div className="rounded-md border border-dashed border-border p-6 text-center text-sm text-gray-400">
          No personas yet. Create your first Playwright profile.
        </div>
      ) : (
        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
          {sortedPersonas.map((persona) => {
            const tags = buildSummaryTags(persona.settings);
            return (
              <Card
                key={persona.id}
                className="border-border bg-card/70 p-4"
              >
                <div className="flex items-start justify-between gap-3">
                  <div className="min-w-0">
                    <p className="text-sm font-semibold text-white">
                      {persona.name}
                    </p>
                    {persona.description ? (
                      <p className="mt-1 text-xs text-gray-400">
                        {persona.description}
                      </p>
                    ) : (
                      <p className="mt-1 text-xs text-gray-500">
                        No description provided.
                      </p>
                    )}
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => openEdit(persona)}
                      disabled={saving}
                    >
                      <Pencil className="mr-1 size-3" />
                      Edit
                    </Button>
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => void handleDeletePersona(persona)}
                      disabled={saving}
                    >
                      <Trash2 className="mr-1 size-3" />
                      Delete
                    </Button>
                  </div>
                </div>
                <div className="mt-3 flex flex-wrap gap-2">
                  {tags.map((tag) => (
                    <span
                      key={tag}
                      className="rounded-full border px-2 py-1 text-[11px] text-gray-300"
                    >
                      {tag}
                    </span>
                  ))}
                </div>
                <div className="mt-4 flex flex-wrap items-center gap-3 text-[11px] text-gray-500">
                  <span>Updated: {formatTimestamp(persona.updatedAt)}</span>
                  <span>Created: {formatTimestamp(persona.createdAt)}</span>
                </div>
              </Card>
            );
          })}
        </div>
      )}

      <AppModal
        open={modalOpen}
        onOpenChange={(open) => !open && closeModal()}
        title={editingId ? "Edit persona" : "New persona"}
      >
        <ModalShell
          title={editingId ? "Edit persona" : "New persona"}
          onClose={closeModal}
          footer={
            <>
              <Button
                type="button"
                variant="outline"
                onClick={closeModal}
                disabled={saving}
              >
                Cancel
              </Button>
              <Button
                type="button"
                onClick={() => void handleSavePersona()}
                disabled={saving}
              >
                {saving ? "Saving..." : "Save persona"}
              </Button>
            </>
          }
        >
          <div className="space-y-6">
            <div className="grid gap-4 md:grid-cols-2">
              <div>
                <Label className="mb-2 block text-sm font-medium text-gray-200">
                  Persona name
                </Label>
                <Input
                  value={draftName}
                  onChange={(event) => setDraftName(event.target.value)}
                  placeholder="Example: Safe desktop headless"
                />
              </div>
              <div>
                <Label className="mb-2 block text-sm font-medium text-gray-200">
                  Description
                </Label>
                <Textarea
                  value={draftDescription}
                  onChange={(event) =>
                    setDraftDescription(event.target.value)
                  }
                  placeholder="Optional notes for this persona"
                  className="min-h-[90px]"
                />
              </div>
            </div>

            <PlaywrightSettingsForm
              settings={draftSettings}
              setSettings={setDraftSettings}
              showSave={false}
              title="Persona settings"
              description="Tune browser behavior, timeouts, and automation pacing."
            />
          </div>
        </ModalShell>
      </AppModal>
    </div>
  );
}

"use client";

import { parseJsonSetting } from "@/shared/utils/settings-json";
import {
  defaultPlaywrightSettings,
  PLAYWRIGHT_PERSONA_SETTINGS_KEY,
} from "@/features/playwright/constants/playwright";
import type { PlaywrightPersona, PlaywrightSettings } from "@/features/playwright/types";

export const createPlaywrightPersonaId = () => {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
    return crypto.randomUUID();
  }
  return `persona-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
};

export const buildPlaywrightSettings = (
  settings?: Partial<PlaywrightSettings> | null
): PlaywrightSettings => ({
  ...defaultPlaywrightSettings,
  ...(settings ?? {}),
});

export const normalizePlaywrightPersonas = (
  value: unknown
): PlaywrightPersona[] => {
  if (!Array.isArray(value)) return [];

  return value
    .map((item) => {
      if (!item || typeof item !== "object") return null;
      const raw = item as PlaywrightPersona;
      const name = typeof raw.name === "string" ? raw.name.trim() : "";
      if (!name) return null;

      const id =
        typeof raw.id === "string" && raw.id.trim()
          ? raw.id
          : createPlaywrightPersonaId();
      const createdAt =
        typeof raw.createdAt === "string"
          ? raw.createdAt
          : new Date().toISOString();
      const updatedAt =
        typeof raw.updatedAt === "string" ? raw.updatedAt : createdAt;
      const settings =
        raw.settings && typeof raw.settings === "object"
          ? buildPlaywrightSettings(raw.settings as Partial<PlaywrightSettings>)
          : buildPlaywrightSettings();
      const description =
        typeof raw.description === "string" ? raw.description : null;

      return {
        id,
        name,
        description,
        settings,
        createdAt,
        updatedAt,
      } as PlaywrightPersona;
    })
    .filter((item): item is PlaywrightPersona => Boolean(item));
};

export const arePlaywrightSettingsEqual = (
  left: PlaywrightSettings,
  right: PlaywrightSettings
) => {
  const proxyPasswordEqual =
    !left.proxyPassword || !right.proxyPassword
      ? true
      : left.proxyPassword === right.proxyPassword;
  return (
    left.headless === right.headless &&
    left.slowMo === right.slowMo &&
    left.timeout === right.timeout &&
    left.navigationTimeout === right.navigationTimeout &&
    left.humanizeMouse === right.humanizeMouse &&
    left.mouseJitter === right.mouseJitter &&
    left.clickDelayMin === right.clickDelayMin &&
    left.clickDelayMax === right.clickDelayMax &&
    left.inputDelayMin === right.inputDelayMin &&
    left.inputDelayMax === right.inputDelayMax &&
    left.actionDelayMin === right.actionDelayMin &&
    left.actionDelayMax === right.actionDelayMax &&
    left.proxyEnabled === right.proxyEnabled &&
    left.proxyServer === right.proxyServer &&
    left.proxyUsername === right.proxyUsername &&
    proxyPasswordEqual &&
    left.emulateDevice === right.emulateDevice &&
    left.deviceName === right.deviceName
  );
};

export const findPlaywrightPersonaMatch = (
  settings: PlaywrightSettings,
  personas: PlaywrightPersona[]
) => {
  return (
    personas.find((persona) =>
      arePlaywrightSettingsEqual(settings, persona.settings)
    ) ?? null
  );
};

export const fetchPlaywrightPersonas = async (): Promise<PlaywrightPersona[]> => {
  const res = await fetch("/api/settings", { cache: "no-store" });
  if (!res.ok) {
    throw new Error("Failed to load Playwright personas.");
  }
  const data = (await res.json()) as Array<{ key: string; value: string }>;
  const map = new Map(data.map((item) => [item.key, item.value]));
  const stored = parseJsonSetting<PlaywrightPersona[]>(
    map.get(PLAYWRIGHT_PERSONA_SETTINGS_KEY),
    []
  );
  return normalizePlaywrightPersonas(stored);
};

"use client";

import { useContext } from "react";
import { ProductFormContext } from "@/features/products/context/ProductFormContext";

export default function DebugPanel() {
  // Directly use the context to avoid throwing an error when it's not available.
  const context = useContext(ProductFormContext);

  // If the context is not found, it means we are not on a page with the ProductFormProvider.
  // In this case, we render nothing.
  if (!context) {
    return null;
  }

  // A function to handle circular references in the context for JSON.stringify
  const getCircularReplacer = () => {
    const seen = new WeakSet();
    return (_key: string, value: unknown) => {
      if (typeof value === "object" && value !== null) {
        if (seen.has(value)) {
          return; // Omit circular reference
        }
        seen.add(value);
      }
      return value;
    };
  };

  return (
    <div className="fixed bottom-0 right-0 bg-gray-800 text-white p-4 rounded-tl-lg shadow-lg max-w-lg max-h-96 overflow-auto z-50">
      <h3 className="text-lg font-bold mb-2">Product Form Debug Panel</h3>
      <pre className="text-xs">
        {JSON.stringify(context, getCircularReplacer(), 2)}
      </pre>
    </div>
  );
}

