"use client";

import { Button, Input, Label, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, DropdownMenu, DropdownMenuCheckboxItem, DropdownMenuContent, DropdownMenuTrigger } from "@/shared/ui";
import { useMemo, useState } from "react";
import { useFormContext } from "react-hook-form";
import { useProductFormContext } from "@/features/products/context/ProductFormContext";



import { X } from "lucide-react";


import { ProductFormData } from "@/features/products/types";

export default function ProductFormOther() {
  const {
    errors,
    catalogs,
    catalogsLoading,
    catalogsError,
    selectedCatalogIds,
    toggleCatalog,
    categories,
    categoriesLoading,
    selectedCategoryIds,
    toggleCategory,
    tags,
    tagsLoading,
    selectedTagIds,
    toggleTag,
    filteredPriceGroups,
    product,
  } = useProductFormContext();

  const { register, setValue, getValues, watch } = useFormContext<ProductFormData>();

  const basePrice = watch("price") || 0;
  const selectedDefaultPriceGroupId = watch("defaultPriceGroupId");
  const hasCatalogs = selectedCatalogIds.length > 0;
  const selectedCatalogLabels = catalogs
    .filter((catalog) => selectedCatalogIds.includes(catalog.id))
    .map((catalog) => catalog.name);
  const selectedCatalogSummary = selectedCatalogLabels.length
    ? selectedCatalogLabels.join(", ")
    : "Select catalogs";

  // Check if price group is auto-assigned from catalog (for new products only)
  const isNewProduct = !product;
  const selectedCatalog = catalogs.find((c) => selectedCatalogIds.includes(c.id));
  const isPriceGroupAutoAssigned = !!(isNewProduct && selectedCatalog?.defaultPriceGroupId);
  const [categoryQuery, setCategoryQuery] = useState("");
  const [tagQuery, setTagQuery] = useState("");
  const filteredCategories = useMemo(() => {
    const normalized = categoryQuery.trim().toLowerCase();
    if (!normalized) return categories;
    return categories.filter((category) =>
      category.name.toLowerCase().includes(normalized)
    );
  }, [categories, categoryQuery]);
  const filteredTags = useMemo(() => {
    const normalized = tagQuery.trim().toLowerCase();
    if (!normalized) return tags;
    return tags.filter((tag) => tag.name.toLowerCase().includes(normalized));
  }, [tags, tagQuery]);

  // Calculate prices for all price groups
  const priceGroupPrices = filteredPriceGroups.map((group) => {
    if (!group.sourceGroupId || !group.priceMultiplier) {
      // This is a base price group (not dependent)
      return {
        ...group,
        calculatedPrice: group.id === selectedDefaultPriceGroupId ? basePrice : null,
        isCalculated: false,
        sourceGroupName: undefined as string | undefined,
      };
    }

    // This is a dependent price group
    // Find the source group's price
    const sourceGroup = filteredPriceGroups.find((g) => g.id === group.sourceGroupId);
    if (!sourceGroup) {
      return {
        ...group,
        calculatedPrice: null,
        isCalculated: true,
        sourceGroupName: undefined as string | undefined,
      };
    }

    // If the source group is the selected default, use the base price
    const sourcePrice = sourceGroup.id === selectedDefaultPriceGroupId ? basePrice : null;
    const calculatedPrice = sourcePrice ? sourcePrice * group.priceMultiplier : null;

    return {
      ...group,
      calculatedPrice,
      isCalculated: true,
      sourceGroupName: sourceGroup.name as string | undefined,
    };
  });

  return (
    <div className="space-y-4">
      {!hasCatalogs && (
        <div className="rounded-md border border-amber-500/40 bg-amber-500/10 px-4 py-3 text-sm text-amber-100">
          Select a catalog to set pricing and price groups.
        </div>
      )}
      {hasCatalogs && (
        <>
          <div className="mb-4">
            <Label htmlFor="price">Base Price</Label>
            <Input
              id="price"
              type="number"
              step="0.01"
              {...register("price", { valueAsNumber: true })}
              aria-invalid={errors.price ? "true" : "false"}
            />
            {errors.price && (
              <p className="text-red-500 text-sm mt-1" role="alert">
                {errors.price.message}
              </p>
            )}
          </div>
          <div className="mb-4">
            <Label htmlFor="defaultPriceGroupId">
              Default Price Group
              {isPriceGroupAutoAssigned && (
                <span className="ml-2 text-xs text-muted-foreground">(Auto-assigned from catalog)</span>
              )}
            </Label>
            <Select
              onValueChange={(value) => setValue("defaultPriceGroupId", value)}
              value={getValues("defaultPriceGroupId") || ""}
              disabled={isPriceGroupAutoAssigned}
            >
              <SelectTrigger className={isPriceGroupAutoAssigned ? "cursor-not-allowed opacity-60" : ""}>
                <SelectValue placeholder="Select default price group" />
              </SelectTrigger>
              <SelectContent>
                {filteredPriceGroups.map((group) => (
                  <SelectItem key={group.id} value={group.id}>
                    {group.name} {group.isDefault ? "(Default)" : ""}{" "}
                    ({group.currency?.code ?? group.currencyCode})
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          {selectedDefaultPriceGroupId && filteredPriceGroups.length > 0 && (
            <div className="mb-4">
              <Label className="mb-2 block">Price Groups Overview</Label>
              <div className="rounded-md border">
                <table className="w-full text-sm">
                  <thead className="border-b bg-muted/50">
                    <tr>
                      <th className="px-3 py-2 text-left font-medium">Price Group</th>
                      <th className="px-3 py-2 text-left font-medium">Currency</th>
                      <th className="px-3 py-2 text-right font-medium">Price</th>
                    </tr>
                  </thead>
                  <tbody>
                    {priceGroupPrices.map((group) => (
                      <tr key={group.id} className="border-b last:border-0">
                        <td className="px-3 py-2">
                          <div className="flex items-center gap-2">
                            <span className={group.id === selectedDefaultPriceGroupId ? "font-semibold" : ""}>
                              {group.name}
                            </span>
                            {group.id === selectedDefaultPriceGroupId && (
                              <span className="text-xs text-muted-foreground">(Selected)</span>
                            )}
                            {group.isCalculated && group.sourceGroupName && (
                              <span className="text-xs text-muted-foreground">
                                (from {group.sourceGroupName} × {group.priceMultiplier})
                              </span>
                            )}
                          </div>
                        </td>
                        <td className="px-3 py-2">{group.currency?.code ?? group.currencyCode}</td>
                        <td className="px-3 py-2 text-right font-mono">
                          {group.calculatedPrice !== null ? (
                            <span className={group.isCalculated ? "text-blue-600" : ""}>
                              {group.calculatedPrice.toFixed(2)}
                            </span>
                          ) : (
                            <span className="text-muted-foreground">-</span>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              <p className="mt-2 text-xs text-muted-foreground">
                Blue prices are calculated based on the selected default price group and multipliers.
              </p>
            </div>
          )}
        </>
      )}
      <div className="mb-4">
        <Label htmlFor="supplierName">Supplier Name</Label>
        <Input
          id="supplierName"
          {...register("supplierName")}
          aria-invalid={errors.supplierName ? "true" : "false"}
        />
        {errors.supplierName && (
          <p className="text-red-500 text-sm mt-1" role="alert">
            {errors.supplierName.message}
          </p>
        )}
      </div>
      <div className="mb-4">
        <Label htmlFor="supplierLink">Supplier Link</Label>
        <Input
          id="supplierLink"
          {...register("supplierLink")}
          aria-invalid={errors.supplierLink ? "true" : "false"}
        />
        {errors.supplierLink && (
          <p className="text-red-500 text-sm mt-1" role="alert">
            {errors.supplierLink.message}
          </p>
        )}
      </div>
      <div className="mb-4">
        <Label htmlFor="priceComment">Price Comment</Label>
        <Input
          id="priceComment"
          {...register("priceComment")}
          aria-invalid={errors.priceComment ? "true" : "false"}
        />
        {errors.priceComment && (
          <p className="text-red-500 text-sm mt-1" role="alert">
            {errors.priceComment.message}
          </p>
        )}
      </div>
      <div className="mb-4">
        <Label htmlFor="stock">Stock</Label>
        <Input
          id="stock"
          type="number"
          {...register("stock", { valueAsNumber: true })}
          aria-invalid={errors.stock ? "true" : "false"}
        />
        {errors.stock && (
          <p className="text-red-500 text-sm mt-1" role="alert">
            {errors.stock.message}
          </p>
        )}
      </div>
      <div className="mb-4">
        <Label className="mb-2 block">Catalogs</Label>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="outline" className="w-full justify-between">
              {selectedCatalogIds.length > 0
                ? selectedCatalogSummary
                : "Select catalogs"}
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent className="w-56">
            {catalogsLoading ? (
              <div className="p-2 text-sm text-muted-foreground">Loading...</div>
            ) : catalogsError ? (
              <div className="p-2 text-sm text-red-500">{catalogsError}</div>
            ) : catalogs.length === 0 ? (
              <div className="p-2 text-sm text-muted-foreground">No catalogs found</div>
            ) : (
              catalogs.map((catalog) => (
                <DropdownMenuCheckboxItem
                  key={catalog.id}
                  checked={selectedCatalogIds.includes(catalog.id)}
                  onCheckedChange={() => toggleCatalog(catalog.id)}
                >
                  {catalog.name}
                </DropdownMenuCheckboxItem>
              ))
            )}
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
      <div className="mb-4">
        <Label className="mb-2 block">Categories</Label>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="outline" className="w-full justify-between" disabled={selectedCatalogIds.length === 0}>
              {selectedCategoryIds.length > 0
                ? `${selectedCategoryIds.length} categor${selectedCategoryIds.length === 1 ? 'y' : 'ies'} selected`
                : selectedCatalogIds.length === 0
                ? "Select a catalog first"
                : "Select categories"}
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent className="w-56">
            {categoriesLoading ? (
              <div className="p-2 text-sm text-muted-foreground">Loading...</div>
            ) : categories.length === 0 ? (
              <div className="p-2 text-sm text-muted-foreground">No categories found</div>
            ) : (
              <>
                <div className="p-2">
                  <div className="relative">
                    <Input
                      value={categoryQuery}
                      onChange={(event) => setCategoryQuery(event.target.value)}
                      placeholder="Search categories..."
                      className="h-8 pr-8"
                    />
                    {categoryQuery && (
                      <Button
                        type="button"
                        onClick={() => setCategoryQuery("")}
                        className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-white"
                        aria-label="Clear category search"
                      >
                        <X className="h-3.5 w-3.5" />
                      </Button>
                    )}
                  </div>
                </div>
                {filteredCategories.length === 0 ? (
                  <div className="px-2 pb-2 text-sm text-muted-foreground">No matching categories</div>
                ) : (
                  filteredCategories.map((category) => (
                    <DropdownMenuCheckboxItem
                      key={category.id}
                      checked={selectedCategoryIds.includes(category.id)}
                      onCheckedChange={() => toggleCategory(category.id)}
                    >
                      {category.name}
                    </DropdownMenuCheckboxItem>
                  ))
                )}
              </>
            )}
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
      <div className="mb-4">
        <Label className="mb-2 block">Tags</Label>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="outline" className="w-full justify-between" disabled={selectedCatalogIds.length === 0}>
              {selectedTagIds.length > 0
                ? `${selectedTagIds.length} tag${selectedTagIds.length === 1 ? '' : 's'} selected`
                : selectedCatalogIds.length === 0
                ? "Select a catalog first"
                : "Select tags"}
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent className="w-56">
            {tagsLoading ? (
              <div className="p-2 text-sm text-muted-foreground">Loading...</div>
            ) : tags.length === 0 ? (
              <div className="p-2 text-sm text-muted-foreground">No tags found</div>
            ) : (
              <>
                <div className="p-2">
                  <div className="relative">
                    <Input
                      value={tagQuery}
                      onChange={(event) => setTagQuery(event.target.value)}
                      placeholder="Search tags..."
                      className="h-8 pr-8"
                    />
                    {tagQuery && (
                      <Button
                        type="button"
                        onClick={() => setTagQuery("")}
                        className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-white"
                        aria-label="Clear tag search"
                      >
                        <X className="h-3.5 w-3.5" />
                      </Button>
                    )}
                  </div>
                </div>
                {filteredTags.length === 0 ? (
                  <div className="px-2 pb-2 text-sm text-muted-foreground">No matching tags</div>
                ) : (
                  filteredTags.map((tag) => (
                    <DropdownMenuCheckboxItem
                      key={tag.id}
                      checked={selectedTagIds.includes(tag.id)}
                      onCheckedChange={() => toggleTag(tag.id)}
                    >
                      {tag.name}
                    </DropdownMenuCheckboxItem>
                  ))
                )}
              </>
            )}
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
    </div>
  );
}

"use client";

import { Button, Input, Label, Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/shared/ui";
import { useMemo } from "react";
import { useProductFormContext } from "@/features/products/context/ProductFormContext";




import { X } from "lucide-react";

const getParameterLabel = (
  parameter: { name_en: string; name_pl?: string | null; name_de?: string | null },
  preferredLocale?: string
) => {
  const preferred = preferredLocale?.toLowerCase();
  if (preferred === "pl" && parameter.name_pl) return parameter.name_pl;
  if (preferred === "de" && parameter.name_de) return parameter.name_de;
  return parameter.name_en || parameter.name_pl || parameter.name_de || "Unnamed parameter";
};

export default function ProductFormParameters() {
  const {
    parameters,
    parametersLoading,
    parameterValues,
    addParameterValue,
    updateParameterId,
    updateParameterValue,
    removeParameterValue,
    selectedCatalogIds,
    filteredLanguages,
  } = useProductFormContext();

  const preferredLocale = filteredLanguages[0]?.code ?? "en";
  const selectedIds = useMemo(
    () => parameterValues.map((entry) => entry.parameterId).filter(Boolean),
    [parameterValues]
  );

  if (selectedCatalogIds.length === 0) {
    return (
      <div className="rounded-md border border-amber-500/40 bg-amber-500/10 px-4 py-3 text-sm text-amber-100">
        Select a catalog to manage product parameters.
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between gap-3">
        <div>
          <Label className="text-sm font-semibold">Parameters</Label>
          <p className="text-xs text-muted-foreground">
            Choose parameters and provide values for this product.
          </p>
        </div>
        <Button
          type="button"
          variant="outline"
          onClick={addParameterValue}
          disabled={parametersLoading || parameters.length === 0}
        >
          Add parameter
        </Button>
      </div>

      {parametersLoading ? (
        <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
          Loading parameters...
        </div>
      ) : parameters.length === 0 ? (
        <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
          No parameters available for the selected catalog(s).
        </div>
      ) : parameterValues.length === 0 ? (
        <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
          Add your first parameter to start building values.
        </div>
      ) : (
        <div className="space-y-3">
          {parameterValues.map((entry, index) => {
            const availableOptions = parameters.filter(
              (param) =>
                !selectedIds.includes(param.id) || param.id === entry.parameterId
            );
            return (
              <div
                key={`${entry.parameterId || "new"}-${index}`}
                className="flex flex-col gap-3 rounded-md border border-border bg-card/60 p-3 md:flex-row md:items-center"
              >
                <div className="w-full md:w-64">
                  <Select
                    value={entry.parameterId}
                    onValueChange={(value) => updateParameterId(index, value)}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select parameter" />
                    </SelectTrigger>
                    <SelectContent>
                      {availableOptions.map((param) => (
                        <SelectItem key={param.id} value={param.id}>
                          {getParameterLabel(param, preferredLocale)}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="flex-1">
                  <Input
                    value={entry.value}
                    onChange={(event) =>
                      updateParameterValue(index, event.target.value)
                    }
                    placeholder="Value"
                    disabled={!entry.parameterId}
                  />
                </div>
                <Button
                  type="button"
                  variant="ghost"
                  onClick={() => removeParameterValue(index)}
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";

import { Input, Label, Button, DropdownMenu, DropdownMenuContent, DropdownMenuGroup, DropdownMenuItem, DropdownMenuLabel, DropdownMenuSeparator, DropdownMenuTrigger } from "@/shared/ui";
import { memo, useCallback, useMemo } from "react";



import { X, CheckSquare, Settings2, Trash2, Store } from "lucide-react";

import type { ProductWithImages } from "@/features/products/types";
import type { RowSelectionState } from "@tanstack/react-table";

interface ProductFiltersProps {
  search: string;
  setSearch: (value: string) => void;
  sku: string;
  setSku: (value: string) => void;
  minPrice: number | undefined;
  setMinPrice: (value: number | undefined) => void;
  maxPrice: number | undefined;
  setMaxPrice: (value: number | undefined) => void;
  startDate: string;
  setStartDate: (value: string) => void;
  endDate: string;
  setEndDate: (value: string) => void;
}

export const ProductFilters = memo(function ProductFilters({
  search,
  setSearch,
  sku,
  setSku,
  minPrice,
  setMinPrice,
  maxPrice,
  setMaxPrice,
  startDate,
  setStartDate,
  endDate,
  setEndDate,
}: ProductFiltersProps) {
  const hasActiveFilters = search || sku || minPrice || maxPrice || startDate || endDate;

  const handleResetFilters = () => {
    setSearch("");
    setSku("");
    setMinPrice(undefined);
    setMaxPrice(undefined);
    setStartDate("");
    setEndDate("");
  };

  return (
    <div className="mb-4 space-y-3 rounded-lg border bg-card p-4">
      {/* Filter title and reset button */}
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold text-foreground">
          Filters
        </h3>
        {hasActiveFilters && (
          <Button
            variant="ghost"
            size="sm"
            onClick={handleResetFilters}
            className="h-8 gap-2"
          >
            <X className="h-3 w-3" />
            Reset filters
          </Button>
        )}
      </div>

      {/* Filters grid */}
      <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 lg:grid-cols-7">
        {/* Search by name */}
        <div className="space-y-1.5">
          <Label htmlFor="search-name" className="text-xs font-medium">
            Name
          </Label>
          <Input
            id="search-name"
            placeholder="Search by name..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="h-8 text-sm"
          />
        </div>

        {/* Search by SKU */}
        <div className="space-y-1.5">
          <Label htmlFor="search-sku" className="text-xs font-medium">
            SKU
          </Label>
          <Input
            id="search-sku"
            placeholder="Search by SKU..."
            value={sku}
            onChange={(e) => setSku(e.target.value)}
            className="h-8 text-sm"
          />
        </div>

        {/* Min Price */}
        <div className="space-y-1.5">
          <Label htmlFor="min-price" className="text-xs font-medium">
            Min Price
          </Label>
          <Input
            id="min-price"
            type="number"
            placeholder="Min price"
            value={minPrice || ""}
            onChange={(e) =>
              setMinPrice(
                e.target.value ? parseInt(e.target.value, 10) : undefined
              )
            }
            className="h-8 text-sm"
          />
        </div>

        {/* Max Price */}
        <div className="space-y-1.5">
          <Label htmlFor="max-price" className="text-xs font-medium">
            Max Price
          </Label>
          <Input
            id="max-price"
            type="number"
            placeholder="Max price"
            value={maxPrice || ""}
            onChange={(e) =>
              setMaxPrice(
                e.target.value ? parseInt(e.target.value, 10) : undefined
              )
            }
            className="h-8 text-sm"
          />
        </div>

        {/* Start Date */}
        <div className="space-y-1.5">
          <Label htmlFor="start-date" className="text-xs font-medium">
            From Date
          </Label>
          <Input
            id="start-date"
            type="date"
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
            className="h-8 text-sm"
          />
        </div>

        {/* End Date */}
        <div className="space-y-1.5">
          <Label htmlFor="end-date" className="text-xs font-medium">
            To Date
          </Label>
          <Input
            id="end-date"
            type="date"
            value={endDate}
            onChange={(e) => setEndDate(e.target.value)}
            className="h-8 text-sm"
          />
        </div>
      </div>
    </div>
  );
});

interface ProductSelectionActionsProps {
  data?: ProductWithImages[];
  rowSelection?: RowSelectionState;
  setRowSelection?: (selection: RowSelectionState) => void;
  onSelectAllGlobal?: () => Promise<void>;
  loadingGlobal?: boolean;
  onDeleteSelected?: () => Promise<void>;
  onAddToMarketplace?: () => void;
}

export const ProductSelectionActions = memo(function ProductSelectionActions({
  data = [],
  rowSelection = {},
  setRowSelection = () => {},
  onSelectAllGlobal,
  loadingGlobal,
  onDeleteSelected,
  onAddToMarketplace,
}: ProductSelectionActionsProps) {
  const handleSelectAllGlobal = useCallback(async () => {
    if (!onSelectAllGlobal) return;
    try {
      await onSelectAllGlobal();
    } catch (error) {
      console.error("Failed to select all products:", error);
    }
  }, [onSelectAllGlobal]);

  const handleDeleteSelected = useCallback(async () => {
    if (!onDeleteSelected) return;
    try {
      await onDeleteSelected();
    } catch (error) {
      console.error("Failed to delete selected products:", error);
    }
  }, [onDeleteSelected]);

  const handleSelectPage = useCallback(() => {
    const newSelection = { ...rowSelection };
    data.forEach((product) => {
      newSelection[product.id] = true;
    });
    setRowSelection(newSelection);
  }, [data, rowSelection, setRowSelection]);

  const handleDeselectPage = useCallback(() => {
    const newSelection = { ...rowSelection };
    data.forEach((product) => {
      delete newSelection[product.id];
    });
    setRowSelection(newSelection);
  }, [data, rowSelection, setRowSelection]);

  const handleDeselectAll = useCallback(() => {
    setRowSelection({});
  }, [setRowSelection]);

  const selectedCount = useMemo(
    () => Object.keys(rowSelection).filter((key) => rowSelection[key]).length,
    [rowSelection]
  );
  const hasSelection = selectedCount > 0;

  return (
    <div className="flex flex-wrap gap-2 border-t pt-3 sm:gap-3">
      <DropdownMenu>
