interface ProductSelectionBarProps {
  data: ProductWithImages[];
  rowSelection: RowSelectionState;
  setRowSelection: (selection: RowSelectionState) => void;
  onSelectAllGlobal: () => Promise<void>;
  loadingGlobal?: boolean;
  onDeleteSelected?: () => Promise<void>;
  onAddToMarketplace?: () => void;
  total?: number;
}

export const ProductSelectionBar = memo(function ProductSelectionBar({
  data,
  rowSelection,
  setRowSelection,
  onSelectAllGlobal,
  loadingGlobal,
  onDeleteSelected,
  onAddToMarketplace,
}: ProductSelectionBarProps) {
  const handleSelectAllGlobal = useCallback(async () => {
    if (!onSelectAllGlobal) return;
    try {
      await onSelectAllGlobal();
    } catch (error) {
      console.error("Failed to select all products:", error);
    }
  }, [onSelectAllGlobal]);

  const handleDeleteSelected = useCallback(async () => {
    if (!onDeleteSelected) return;
    try {
      await onDeleteSelected();
    } catch (error) {
      console.error("Failed to delete selected products:", error);
    }
  }, [onDeleteSelected]);

  const handleSelectPage = useCallback(() => {
    const newSelection = { ...rowSelection };
    data.forEach((product) => {
      newSelection[product.id] = true;
    });
    setRowSelection(newSelection);
  }, [data, rowSelection, setRowSelection]);

  const handleDeselectPage = useCallback(() => {
    const newSelection = { ...rowSelection };
    data.forEach((product) => {
      delete newSelection[product.id];
    });
    setRowSelection(newSelection);
  }, [data, rowSelection, setRowSelection]);

  const handleDeselectAll = useCallback(() => {
    setRowSelection({});
  }, [setRowSelection]);

  const hasSelection = useMemo(
    () => Object.keys(rowSelection).filter((key) => rowSelection[key]).length > 0,
    [rowSelection]
  );

  return (
    <div className="mb-4 flex flex-col gap-2 sm:flex-row sm:items-center sm:gap-3">
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <Button
            variant="outline"
            className="gap-2"
          >
            <CheckSquare className="h-4 w-4" />
            Selection
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start" className="w-56">
          <DropdownMenuLabel>On this Page</DropdownMenuLabel>
          <DropdownMenuGroup>
            <DropdownMenuItem
              onClick={handleSelectPage}
              className="cursor-pointer"
            >
              Select All on Page
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={handleDeselectPage}
              className="cursor-pointer"
            >
              Deselect All on Page
            </DropdownMenuItem>
          </DropdownMenuGroup>
          <DropdownMenuSeparator />
          <DropdownMenuLabel>On All Pages</DropdownMenuLabel>
          <DropdownMenuGroup>
            <DropdownMenuItem
              onClick={() => void handleSelectAllGlobal()}
              className="cursor-pointer"
              disabled={!!loadingGlobal}
            >
              {loadingGlobal ? "Loading..." : "Select All Globally"}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={handleDeselectAll}
              className="cursor-pointer"
            >
              Deselect All
            </DropdownMenuItem>
          </DropdownMenuGroup>
        </DropdownMenuContent>
      </DropdownMenu>

      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <Button
            variant="outline"
            className="gap-2"
            disabled={!hasSelection}
          >
            <Settings2 className="h-4 w-4" />
            Actions
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start" className="w-56">
          <DropdownMenuItem
            onClick={() => {
              if (onAddToMarketplace) onAddToMarketplace();
            }}
            className="cursor-pointer gap-2"
          >
            <Store className="h-4 w-4" />
            Add to Marketplace
          </DropdownMenuItem>
          <DropdownMenuSeparator />
          <DropdownMenuItem
            onClick={() => void handleDeleteSelected()}
            className="cursor-pointer gap-2 text-destructive focus:bg-destructive/10 focus:text-destructive"
          >
            <Trash2 className="h-4 w-4" />
            Delete Selected
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>
    </div>
  );
});

"use client";
import React, { JSX, memo, useState } from "react";

import { Button, useToast, AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/shared/ui";
import { Table as ReactTable } from "@tanstack/react-table";

import { ProductWithImages } from "@/features/products/types";
import { logger } from "@/shared/utils/logger";


import { Trash2 } from "lucide-react";

interface ProductTableFooterProps<TData> {
  table: ReactTable<TData>;
  setRefreshTrigger: React.Dispatch<React.SetStateAction<number>>;
  setActionError: (error: string | null) => void;
}

export const ProductTableFooter = memo(function ProductTableFooter<TData>({
  table,
  setRefreshTrigger,
  setActionError,
}: ProductTableFooterProps<TData>) {
  const selectedCount = table.getFilteredSelectedRowModel().rows.length;
  const hasSelection = selectedCount > 0;
  const { toast } = useToast();
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  const handleMassDelete = async () => {
    logger.log("Mass delete initiated.");
    const selectedProductIds = table
      .getSelectedRowModel()
      .rows.map((row) => (row.original as ProductWithImages)?.id)
      .filter(Boolean);

    if (selectedProductIds.length === 0) {
      setActionError("Please select products to delete.");
      return;
    }

    try {
      const deletePromises = selectedProductIds.map((id) =>
        fetch(`/api/products/${id}`, {
          method: "DELETE",
        })
      );
      const results = await Promise.all(deletePromises);

      const failedDeletions = results.filter((res) => !res.ok);

      if (failedDeletions.length > 0) {
        let errorIdSuffix = "";
        try {
          const firstFailed = failedDeletions[0];
          if (firstFailed) {
            const payload = (await firstFailed.json()) as {
              errorId?: string;
            };
            if (payload?.errorId) {
              errorIdSuffix = ` (Error ID: ${payload.errorId})`;
            }
          }
        } catch {
          errorIdSuffix = "";
        }
        setActionError(`Some products could not be deleted.${errorIdSuffix}`);
        toast("Some products could not be deleted", {
          variant: "error",
        });
      } else {
        toast("Selected products deleted successfully.", {
          variant: "success",
        });
      }
      table.setRowSelection({}); // Clear selection after deletion
      setRefreshTrigger((prev) => prev + 1); // Refresh the product list
      setShowDeleteConfirm(false);
    } catch (error) {
      logger.error("Error during mass deletion:", error);
      setActionError("An error occurred during deletion.");
      toast("An error occurred during deletion", {
        variant: "error",
      });
    }
  };

  return (
    <>
      <div className="space-y-3 border-t bg-muted/50 px-4 py-4">
        <div className="flex flex-col items-start justify-between gap-3 sm:flex-row sm:items-center">
          <div className="text-sm text-muted-foreground">
            <span className="font-medium text-foreground">{selectedCount}</span>{" "}
            of <span className="font-medium text-foreground">{table.getFilteredRowModel().rows.length}</span>{" "}
            row(s) selected.
          </div>
          <Button
            onClick={() => setShowDeleteConfirm(true)}
            disabled={!hasSelection}
            variant="destructive"
            size="sm"
            className="gap-2"
          >
            <Trash2 className="h-4 w-4" />
            Delete Selected ({selectedCount})
          </Button>
        </div>
      </div>

      {/* Delete confirmation dialog */}
      <AlertDialog open={showDeleteConfirm} onOpenChange={setShowDeleteConfirm}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete selected products?</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete {selectedCount} selected{" "}
              {selectedCount === 1 ? "product" : "products"}? This action cannot be
              undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => void handleMassDelete()}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}) as <TData>(props: ProductTableFooterProps<TData>) => JSX.Element;

