"use client";

import { useToast, Button, AppModal, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, Input, Label } from "@/shared/ui";
import { useState } from "react";
import { Plus, Trash2 } from "lucide-react";




import type { Catalog, ProductTag } from "@/features/products/types";


type TagsSettingsProps = {
  loading: boolean;
  tags: ProductTag[];
  catalogs: Catalog[];
  selectedCatalogId: string | null;
  onCatalogChange: (catalogId: string) => void;
  onRefresh: () => void;
};

export function TagsSettings({
  loading,
  tags,
  catalogs,
  selectedCatalogId,
  onCatalogChange,
  onRefresh,
}: TagsSettingsProps) {
  const { toast } = useToast();
  const [showModal, setShowModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [editingTag, setEditingTag] = useState<ProductTag | null>(null);
  const [formData, setFormData] = useState({
    name: "",
    color: "#38bdf8",
    catalogId: "",
  });

  const openCreateModal = () => {
    if (!selectedCatalogId) {
      toast("Please select a catalog first.", { variant: "error" });
      return;
    }
    setEditingTag(null);
    setFormData({
      name: "",
      color: "#38bdf8",
      catalogId: selectedCatalogId,
    });
    setShowModal(true);
  };

  const openEditModal = (tag: ProductTag) => {
    setEditingTag(tag);
    setFormData({
      name: tag.name,
      color: tag.color ?? "#38bdf8",
      catalogId: tag.catalogId,
    });
    setShowModal(true);
  };

  const handleSave = async () => {
    if (!formData.name.trim()) {
      toast("Tag name is required.", { variant: "error" });
      return;
    }
    if (!formData.catalogId) {
      toast("Catalog is required.", { variant: "error" });
      return;
    }

    setSaving(true);
    try {
      const endpoint = editingTag
        ? `/api/products/tags/${editingTag.id}`
        : "/api/products/tags";
      const res = await fetch(endpoint, {
        method: editingTag ? "PUT" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: formData.name.trim(),
          color: formData.color.trim() || null,
          catalogId: formData.catalogId,
        }),
      });
      if (!res.ok) {
        const payload = (await res.json()) as { error?: string };
        throw new Error(payload.error || "Failed to save tag.");
      }
      toast(editingTag ? "Tag updated." : "Tag created.", {
        variant: "success",
      });
      setShowModal(false);
      onRefresh();
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Failed to save tag.";
      toast(message, { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (tag: ProductTag) => {
    const confirmed = window.confirm(`Delete tag "${tag.name}"?`);
    if (!confirmed) return;
    try {
      const res = await fetch(`/api/products/tags/${tag.id}`, {
        method: "DELETE",
      });
      if (!res.ok) {
        const payload = (await res.json()) as { error?: string };
        throw new Error(payload.error || "Failed to delete tag.");
      }
      toast("Tag deleted.", { variant: "success" });
      onRefresh();
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Failed to delete tag.";
      toast(message, { variant: "error" });
    }
  };

  const selectedCatalog = catalogs.find((catalog) => catalog.id === selectedCatalogId);

  return (
    <div className="space-y-5">
      <div className="rounded-md border border-border bg-card/60 p-4">
        <p className="text-sm font-semibold text-white mb-3">Select Catalog</p>
        <p className="text-xs text-gray-400 mb-3">
          Tags are managed per catalog.
        </p>
        <div className="w-full max-w-xs">
          <Select
            value={selectedCatalogId || ""}
            onValueChange={onCatalogChange}
          >
            <SelectTrigger>
              <SelectValue placeholder="Select a catalog..." />
            </SelectTrigger>
            <SelectContent>
              {catalogs.map((catalog) => (
                <SelectItem key={catalog.id} value={catalog.id}>
                  {catalog.name}
                  {catalog.isDefault ? " (Default)" : ""}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {selectedCatalogId && (
        <>
          <div className="flex justify-start">
            <Button
              onClick={openCreateModal}
              className="bg-white text-gray-900 hover:bg-gray-200"
            >
              <Plus className="size-4 mr-2" />
              Add Tag
            </Button>
          </div>

          <div className="rounded-md border border-border bg-card/60 p-4">
            <p className="text-sm font-semibold text-white mb-4">
              Tags for &quot;{selectedCatalog?.name}&quot;
            </p>

            {loading ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                Loading tags...
              </div>
            ) : tags.length === 0 ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                No tags yet for this catalog. Create your first tag!
              </div>
            ) : (
              <div className="space-y-2">
                {tags.map((tag) => (
                  <div
                    key={tag.id}
                    className="flex items-center justify-between gap-3 rounded-md border border-border bg-gray-900 px-3 py-2"
                  >
                    <div className="flex items-center gap-3 min-w-0">
                      <span
                        className="size-3 rounded-full border border"
                        style={{ backgroundColor: tag.color || "#38bdf8" }}
                      />
                      <span className="text-sm text-gray-100 truncate">
                        {tag.name}
                      </span>
                    </div>
                    <div className="flex items-center gap-2">
                      <Button
                        type="button"
                        onClick={() => openEditModal(tag)}
                        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-100 hover:bg-gray-700"
                      >
                        Edit
                      </Button>
                      <Button
                        type="button"
                        onClick={() => void handleDelete(tag)}
                        className="rounded bg-red-600/80 px-2 py-1 text-xs text-white hover:bg-red-600"
                        title="Delete tag"
                      >
                        <Trash2 className="size-3" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}

      {!selectedCatalogId && catalogs.length === 0 && (
        <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
          No catalogs found. Please create a catalog first in the Catalogs section.
        </div>
      )}

      {showModal && (
        <AppModal
          open={showModal}
          onOpenChange={(open) => !open && setShowModal(false)}
          title={editingTag ? "Edit Tag" : "Create Tag"}
        >
          <div className="w-full max-w-md rounded-lg bg-card p-6 shadow-lg">
            <div className="mb-4 flex items-center justify-between">
              <h2 className="text-xl font-semibold text-white">
                {editingTag ? "Edit Tag" : "Create Tag"}
              </h2>
              <Button
                className="text-sm text-gray-400 hover:text-white"
                type="button"
                onClick={() => setShowModal(false)}
              >
                Close
              </Button>
            </div>

            <div className="space-y-4">
              <div>
                <Label className="text-xs text-gray-400">Name</Label>
                <Input
                  className="mt-2 w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                  value={formData.name}
                  onChange={(e) =>
                    setFormData((prev) => ({ ...prev, name: e.target.value }))
                  }
                  placeholder="Tag name"
                />
              </div>

              <div>
                <Label className="text-xs text-gray-400">Catalog</Label>
                <select
                  className="mt-2 w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                  value={formData.catalogId}
                  onChange={(e) =>
                    setFormData((prev) => ({
                      ...prev,
                      catalogId: e.target.value,
                    }))
                  }
                >
                  {catalogs.map((catalog) => (
                    <option key={catalog.id} value={catalog.id}>
                      {catalog.name}
                      {catalog.isDefault ? " (Default)" : ""}
                    </option>
                  ))}
                </select>
              </div>

              <div>
                <Label className="text-xs text-gray-400">Color</Label>
                <div className="mt-2 flex items-center gap-3">
                  <Input
                    type="color"
                    className="h-10 w-20 cursor-pointer rounded border border-border bg-gray-900"
                    value={formData.color}
                    onChange={(e) =>
                      setFormData((prev) => ({ ...prev, color: e.target.value }))
                    }
                  />
                  <Input
                    type="text"
                    className="flex-1 rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                    value={formData.color}
                    onChange={(e) =>
                      setFormData((prev) => ({ ...prev, color: e.target.value }))
                    }
                    placeholder="#38bdf8"
                  />
                </div>
              </div>

              <div className="flex items-center justify-end gap-3 pt-4">
                <Button
                  className="rounded-md border border-border px-3 py-2 text-sm text-gray-300 hover:bg-muted/50"
                  type="button"
                  onClick={() => setShowModal(false)}
                >
                  Cancel
                </Button>
                <Button
                  className="rounded-md bg-white px-4 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-200"
                  type="button"
                  onClick={() => void handleSave()}
                  disabled={saving}
                >
                  {saving ? "Saving..." : "Save"}
                </Button>
              </div>
            </div>
          </div>
        </AppModal>
      )}
    </div>
  );
}

"use client";

import { Button, Input, Label, Select, SelectContent, SelectItem, SelectGroup, SelectLabel, SelectTrigger, SelectValue, Textarea, useToast, Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger, Checkbox } from "@/shared/ui";
import { useState, useEffect } from "react";






import { CopyIcon, InfoIcon, PlayIcon, RefreshCcw, XCircle } from "lucide-react";


import { ProductWithImages } from "@/features/products/types";

const STATIC_VISION_MODELS = [
  { id: "gpt-4o", name: "GPT-4o" },
  { id: "gpt-4-turbo", name: "GPT-4 Turbo" },
];

const STATIC_TEXT_MODELS = [
  { id: "gpt-4o", name: "GPT-4o" },
  { id: "gpt-4-turbo", name: "GPT-4 Turbo" },
  { id: "gpt-3.5-turbo", name: "GPT-3.5 Turbo" },
];

const AVAILABLE_PLACEHOLDERS = [
  { key: "result", description: "Result from the immediate previous step." },
  { key: "analysis", description: "Final result from Signal Path 1 (Image Analysis)." },
  { key: "description", description: "Initial result from Signal Path 2 (Description Generation)." },
  { key: "images", description: "Product images. Only sent to AI if this placeholder is present." },
  { key: "sku", description: "Product SKU" },
  { key: "name_en", description: "Product Name (English)" },
  { key: "name_pl", description: "Product Name (Polish)" },
  { key: "name_de", description: "Product Name (German)" },
  { key: "price", description: "Regular Price" },
  { key: "stock", description: "Current Stock Level" },
  { key: "ean", description: "EAN Code" },
  { key: "gtin", description: "GTIN Code" },
  { key: "asin", description: "ASIN (Amazon)" },
  { key: "supplierName", description: "Supplier Name" },
  { key: "weight", description: "Product Weight" },
  { key: "sizeLength", description: "Size: Length" },
  { key: "sizeWidth", description: "Size: Width" },
  { key: "length", description: "Length" },
];

type TestResultData = { 
  analysisInitial?: string; 
  analysisFinal?: string;
  descriptionInitial?: string;
  descriptionFinal?: string;
};

interface JobData {
  status: "pending" | "running" | "completed" | "failed" | "canceled";
  result?: TestResultData & { analysis?: string; description?: string };
  errorMessage?: string;
}

export function AiDescriptionSettings() {
  const [imageAnalysisModel, setImageAnalysisModel] = useState("");

  // Path 1
  const [visionInputPrompt, setVisionInputPrompt] = useState("");
  const [visionOutputPrompt, setVisionOutputPrompt] = useState("");
  const [visionOutputEnabled, setVisionOutputEnabled] = useState(false);

  const [descriptionGenerationModel, setDescriptionGenerationModel] = useState("");

  // Path 2
  const [generationInputPrompt, setGenerationInputPrompt] = useState("");
  const [generationOutputPrompt, setGenerationOutputPrompt] = useState("");
  const [generationOutputEnabled, setGenerationOutputEnabled] = useState(false);

  const [ollamaModels, setOllamaModels] = useState<{ id: string; name: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const { toast } = useToast();

  const [testProductId, setTestProductId] = useState("");
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState<TestResultData | null>(null);
  const [queuing, setQueuing] = useState(false);

  useEffect(() => {
    const loadData = async () => {
      try {
        const settingsRes = await fetch("/api/settings");
        let settingsMap = new Map<string, string>();
        if (settingsRes.ok) {
          const data = (await settingsRes.json()) as { key: string, value: string }[];
          settingsMap = new Map(data.map(item => [item.key, item.value]));
        }

        setImageAnalysisModel(settingsMap.get("ai_vision_model") || "gpt-4o");
        setVisionInputPrompt(settingsMap.get("ai_vision_user_prompt") || "Analyze these product images...");
        setVisionOutputPrompt(settingsMap.get("ai_vision_prompt") || "");
        setVisionOutputEnabled(settingsMap.get("ai_vision_output_enabled") === "true");

        setDescriptionGenerationModel(settingsMap.get("openai_model") || "gpt-3.5-turbo");
        setGenerationInputPrompt(settingsMap.get("description_generation_user_prompt") || "Generate description for [name_en] using [result]");
        setGenerationOutputPrompt(settingsMap.get("description_generation_prompt") || "");
        setGenerationOutputEnabled(settingsMap.get("ai_generation_output_enabled") === "true");
        setTestProductId(settingsMap.get("ai_description_test_product_id") || "");

        // Load last test result if exists
        const testResultJson = settingsMap.get("ai_description_last_test_result");
        if (testResultJson) {
          try {
            const parsed = JSON.parse(testResultJson) as TestResultData;
            setTestResult(parsed);
            console.log("Loaded previous test result from database");
          } catch (err) {
            console.warn("Failed to parse saved test result:", err);
          }
        }

        const chatbotRes = await fetch("/api/chatbot");
        if (chatbotRes.ok) {
          const data = (await chatbotRes.json()) as { models?: string[] };
          if (Array.isArray(data.models)) {
            setOllamaModels(data.models.map(name => ({ id: name, name })));
          }
        }
      } catch (error) {
        console.error("Failed to load data:", error);
        toast("Failed to load configuration.", { variant: "error" });
      } finally {
        setLoading(false);
      }
    };
    void loadData();
  }, [toast]);

  const handleTest = async () => {
    if (!testProductId) {
      toast("Please enter a Product ID or SKU.", { variant: "error" });
      return;
    }

    setTesting(true);
    setTestResult(null);

    try {
      let product: ProductWithImages | null = null;
      const productRes = await fetch(`/api/products/${testProductId}`);

      if (productRes.ok) {
        product = (await productRes.json()) as ProductWithImages;
      } else {
        const skuRes = await fetch(`/api/products?sku=${testProductId}`);
        if (skuRes.ok) {
          const products = (await skuRes.json()) as ProductWithImages[];
          if (Array.isArray(products) && products.length > 0) {
            product = products[0] || null;
          }
        }
      }

      if (!product) {
        throw new Error(`Product not found: ${testProductId}`);
      }

      const uploadedImages = Array.isArray(product.images) 
        ? product.images.map((img) => img.imageFile?.filepath).filter((p): p is string => Boolean(p)) 
        : [];
      const externalImages = Array.isArray(product.imageLinks) ? product.imageLinks : [];
      const allImageUrls = [...externalImages, ...uploadedImages];

      // Create a job for the test
      const enqueueRes = await fetch("/api/products/ai-jobs/enqueue", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productId: product.id,
          type: "description_generation",
          payload: {
            productData: product,
            imageUrls: allImageUrls,
            visionOutputEnabled,
            generationOutputEnabled,
            isTest: true
          }
        }),
      });

      const enqueueData = (await enqueueRes.json()) as { error?: string; jobId: string };
      if (!enqueueRes.ok) {
        throw new Error(enqueueData.error || "Failed to enqueue test job.");
      }
      const jobId = enqueueData.jobId;

      // Poll for completion
      let completed = false;
      let attempts = 0;
      while (!completed && attempts < 60) { // 2 minutes max
        await new Promise(r => setTimeout(r, 2000));
        const statusRes = await fetch(`/api/products/ai-jobs/${jobId}`);
        if (!statusRes.ok) break;
        const { job } = (await statusRes.json()) as { job: JobData };

        if (job.status === "completed") {
          const data = job.result;

          const newTestResult: TestResultData = {
            analysisInitial: data?.analysisInitial || data?.analysis || "",
            analysisFinal: data?.analysisFinal || "",
            descriptionInitial: data?.descriptionInitial || data?.description || "",
            descriptionFinal: data?.descriptionFinal || "",
          };

          setTestResult(newTestResult);

          // Save test result to database so it persists across page navigations
          try {
            await fetch("/api/settings", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({
                key: "ai_description_last_test_result",
                value: JSON.stringify(newTestResult)
              }),
            });
          } catch (err) {
            console.warn("Failed to save test result to database:", err);
          }

          toast("Test completed. Results saved.", { variant: "success" });
          completed = true;
        } else if (job.status === "failed") {
          throw new Error(job.errorMessage || "Job failed.");
        } else if (job.status === "canceled") {
          throw new Error("Job was canceled.");
        }
        attempts++;
      }

      if (!completed) {
        throw new Error("Test timed out. Check the Jobs page.");
      }

    } catch (error) {
      console.error("Test failed:", error);
      toast(error instanceof Error ? error.message : "Test failed.", { variant: "error" });
    } finally {
      setTesting(false);
    }
  };

  const handleQueueAll = async () => {
    if (!window.confirm("This will queue description generation for ALL products using the current configuration. Proceed?")) return;
    setQueuing(true);
    try {
      const res = await fetch("/api/products/ai-jobs/bulk", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          type: "description_generation",
          config: {
            visionOutputEnabled,
            generationOutputEnabled
          }
        }),
      });
      if (!res.ok) throw new Error("Failed to queue jobs.");
      const data = (await res.json()) as { count: number };
      toast(`Queued ${data.count} products for generation.`, { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to queue jobs.", { variant: "error" });
    } finally {
      setQueuing(false);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const payloads = [
        { key: "ai_vision_model", value: imageAnalysisModel },
        { key: "ai_vision_user_prompt", value: visionInputPrompt },
        { key: "ai_vision_prompt", value: visionOutputPrompt },
        { key: "ai_vision_output_enabled", value: String(visionOutputEnabled) },
        { key: "openai_model", value: descriptionGenerationModel },
        { key: "description_generation_user_prompt", value: generationInputPrompt },
        { key: "description_generation_prompt", value: generationOutputPrompt },
        { key: "ai_generation_output_enabled", value: String(generationOutputEnabled) },
        { key: "ai_description_test_product_id", value: testProductId },
      ];

      for (const payload of payloads) {
        await fetch("/api/settings", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        });
      }

      // Also save to dedicated MongoDB collection
      await fetch("/api/ai-config", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          imageAnalysisModel,
          visionInputPrompt,
          visionOutputPrompt,
          visionOutputEnabled,
          descriptionGenerationModel,
          generationInputPrompt,
          generationOutputPrompt,
          generationOutputEnabled,
          testProductId,
        }),
      });

      toast("Settings saved.", { variant: "success" });
    } catch (error) {
      console.error("Failed to save:", error);
      toast("Failed to save.", { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  const copyResult = (text?: string) => {
    if (!text) return;
    void navigator.clipboard.writeText(text);
    toast("Result copied to clipboard.");
  };

  const clearTestResults = async () => {
    setTestResult(null);
    try {
      await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          key: "ai_description_last_test_result",
          value: ""
        }),
      });
      toast("Test results cleared.", { variant: "success" });
    } catch (err) {
      console.warn("Failed to clear test results from database:", err);
    }
  };

  if (loading) return <div className="text-sm text-gray-400">Loading settings...</div>;

  return (
    <div className="space-y-8">
      <div>
        <div className="flex items-center justify-between mb-6">
          <div>
            <h2 className="text-lg font-medium text-white mb-1">AI Description Configuration</h2>
            <p className="text-sm text-gray-400">Configure multi-step generation flow for product descriptions.</p>
          </div>
          <div className="flex items-center gap-2">
            <Input
              placeholder="Product ID or SKU"
              value={testProductId}
              onChange={(e) => setTestProductId(e.target.value)}
              className="w-[180px] bg-gray-900 border text-white h-9 text-sm"
            />
            <Button variant="secondary" onClick={() => void handleTest()} disabled={testing} className="gap-2 h-9">
              <PlayIcon className="size-3.5" />
              {testing ? "Testing..." : "Test on Product"}
            </Button>

            {testResult && (
              <Button variant="ghost" onClick={() => void clearTestResults()} className="gap-2 h-9 text-red-400 hover:text-red-300">
                <XCircle className="size-3.5" />
                Clear Results
              </Button>
            )}

            <Button variant="outline" onClick={() => void handleQueueAll()} disabled={queuing} className="gap-2 h-9 text-purple-400 border-purple-900/50 hover:bg-purple-950">
              <RefreshCcw className={`size-3.5 ${queuing ? "animate-spin" : ""}`} />
              {queuing ? "Queuing..." : "Queue for All"}
            </Button>

            <Dialog>
              <DialogTrigger asChild>
                <Button variant="outline" className="h-9 gap-2">
                  <InfoIcon className="size-4" />
                  Placeholders
                </Button>
              </DialogTrigger>
              <DialogContent className="max-w-md max-h-[80vh] overflow-y-auto">
                <DialogHeader>
                  <DialogTitle>Available Placeholders</DialogTitle>
                  <DialogDescription>Use these placeholders to inject dynamic data into your prompts.</DialogDescription>
                </DialogHeader>
                <div className="space-y-2 mt-4">
                  {AVAILABLE_PLACEHOLDERS.map((ph) => (
                    <div key={ph.key} className="flex items-center justify-between text-sm border-b border-border/50 pb-2 last:border-0 last:pb-0">
                      <code className="text-purple-400 font-bold bg-purple-500/10 px-1 py-0.5 rounded">[{ph.key}]</code>
                      <span className="text-gray-500 italic text-xs">{ph.description}</span>
                    </div>
                  ))}
                </div>
              </DialogContent>
            </Dialog>
          </div>
        </div>

        <div className="space-y-6 rounded-md border border-border bg-card/50 p-6">
          {/* Path 1 */}
          <div className="space-y-4">
            <div className="flex items-center gap-2">
              <span className="flex h-6 w-6 items-center justify-center rounded-full bg-blue-500/20 text-xs font-bold text-blue-400">1</span>
              <h3 className="text-md font-medium text-white">Signal Path 1: Image Analysis</h3>
            </div>

            <div className="pl-8 space-y-6">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <Label>Input Prompt</Label>
                  <Textarea
                    rows={4}
                    value={visionInputPrompt}
                    onChange={(e) => setVisionInputPrompt(e.target.value)}
                    className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                  />
                </div>
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <Label>Initial Result</Label>
                    <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.analysisInitial)}>
                      <CopyIcon className="size-3 mr-1"/>Copy
                    </Button>
                  </div>
                  <div className="mt-1.5 rounded-md bg-card/50 p-4 text-sm text-gray-300 h-[100px] overflow-y-auto border border-border font-mono">
                    {testResult?.analysisInitial ? (
                      <div className="whitespace-pre-wrap">{testResult.analysisInitial}</div>
                    ) : (
                      <span className="text-gray-600 italic text-xs">Waiting for test...</span>
                    )}
                  </div>
                </div>
              </div>

              <div className="max-w-md">
                <Label>Vision Model</Label>
                <Select value={imageAnalysisModel} onValueChange={setImageAnalysisModel}>
                  <SelectTrigger className="mt-1.5 bg-gray-900 border text-white"><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectGroup>
                      <SelectLabel>OpenAI</SelectLabel>
                      {STATIC_VISION_MODELS.map((m) => (<SelectItem key={m.id} value={m.id}>{m.name}</SelectItem>))}
                    </SelectGroup>
                    {ollamaModels.length > 0 && (
                      <SelectGroup>
                        <SelectLabel>Ollama</SelectLabel>
                        {ollamaModels.map((m) => (<SelectItem key={m.id} value={m.id}>{m.name}</SelectItem>))}
                      </SelectGroup>
                    )}
                  </SelectContent>
                </Select>
              </div>

              <div className="pt-4 border-t border-border/50 space-y-4">
                <div className="flex items-center gap-2">
                  <Checkbox 
                    id="v-output-enabled" 
                    checked={visionOutputEnabled} 
                    onCheckedChange={(checked) => setVisionOutputEnabled(!!checked)} 
                  />
                  <Label htmlFor="v-output-enabled" className="text-blue-400 cursor-pointer">Enable Output Prompt (Refinement using {imageAnalysisModel})</Label>
                </div>
                {visionOutputEnabled && (
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-in fade-in slide-in-from-top-2 duration-300">
                    <div className="space-y-2">
                      <Label>Output Prompt</Label>
                      <Textarea
                        rows={4}
                        value={visionOutputPrompt}
                        onChange={(e) => setVisionOutputPrompt(e.target.value)}
                        className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                        placeholder="Refine result... use [result] for initial analysis."
                      />
                    </div>
                    <div className="space-y-2">
                      <div className="flex items-center justify-between">
                        <Label>Final Analysis</Label>
                        <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.analysisFinal)}>
                          <CopyIcon className="size-3 mr-1"/>Copy
                        </Button>
                      </div>
                      <div className="mt-1.5 rounded-md bg-card/50 p-4 text-sm text-gray-300 h-[100px] overflow-y-auto border border-border font-mono">
                        {testResult?.analysisFinal ? (
                          <div className="whitespace-pre-wrap">{testResult.analysisFinal}</div>
                        ) : (
                          <span className="text-gray-600 italic text-xs">No result yet.</span>
                        )}
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="border-t border-border my-8"></div>

          {/* Path 2 */}
          <div className="space-y-4">
            <div className="flex items-center gap-2">
              <span className="flex h-6 w-6 items-center justify-center rounded-full bg-purple-500/20 text-xs font-bold text-purple-400">2</span>
              <h3 className="text-md font-medium text-white">Signal Path 2: Description Generation</h3>
            </div>

            <div className="pl-8 space-y-6">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <Label>Input Prompt</Label>
                  <Textarea
                    rows={6}
                    value={generationInputPrompt}
                    onChange={(e) => setGenerationInputPrompt(e.target.value)}
                    className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                  />
                </div>
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <Label>Initial Description</Label>
                    <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.descriptionInitial)}>
                      <CopyIcon className="size-3 mr-1"/>Copy
                    </Button>
                  </div>
                  <div className="mt-1.5 rounded-md bg-card/50 p-4 text-sm text-gray-300 h-[132px] overflow-y-auto border border-border font-sans">
                    {testResult?.descriptionInitial ? (
                      <div className="whitespace-pre-wrap">{testResult.descriptionInitial}</div>
                    ) : (
                      <span className="text-gray-600 italic text-xs">Waiting for test...</span>
                    )}
                  </div>
                </div>
              </div>

              <div className="max-w-md">
                <Label>Generation Model</Label>
                <Select value={descriptionGenerationModel} onValueChange={setDescriptionGenerationModel}>
                  <SelectTrigger className="mt-1.5 bg-gray-900 border text-white"><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectGroup>
                      <SelectLabel>OpenAI</SelectLabel>
                      {STATIC_TEXT_MODELS.map((m) => (<SelectItem key={m.id} value={m.id}>{m.name}</SelectItem>))}
                    </SelectGroup>
                    {ollamaModels.length > 0 && (
                      <SelectGroup>
                        <SelectLabel>Ollama</SelectLabel>
                        {ollamaModels.map((m) => (<SelectItem key={m.id} value={m.id}>{m.name}</SelectItem>))}
                      </SelectGroup>
                    )}
                  </SelectContent>
                </Select>
              </div>

              <div className="pt-4 border-t border-border/50 space-y-4">
                <div className="flex items-center gap-2">
                  <Checkbox 
                    id="g-output-enabled" 
                    checked={generationOutputEnabled} 
                    onCheckedChange={(checked) => setGenerationOutputEnabled(!!checked)} 
                  />
                  <Label htmlFor="g-output-enabled" className="text-purple-400 cursor-pointer">Enable Output Prompt (Refinement using {descriptionGenerationModel})</Label>
                </div>
                {generationOutputEnabled && (
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-in fade-in slide-in-from-top-2 duration-300">
                    <div className="space-y-2">
                      <Label>Output Prompt</Label>
                      <Textarea
                        rows={6}
                        value={generationOutputPrompt}
                        onChange={(e) => setGenerationOutputPrompt(e.target.value)}
                        className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                        placeholder="Final polish... use [result] for initial description."
                      />
                    </div>
                    <div className="space-y-2">
                      <div className="flex items-center justify-between">
                        <Label>Final Description</Label>
                        <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.descriptionFinal)}>
                          <CopyIcon className="size-3 mr-1"/>Copy
                        </Button>
                      </div>
                      <div className="mt-1.5 rounded-md bg-card/50 p-4 text-sm text-gray-300 h-[132px] overflow-y-auto border border-border font-sans">
                        {testResult?.descriptionFinal ? (
                          <div className="whitespace-pre-wrap">{testResult.descriptionFinal}</div>
                        ) : (
                          <span className="text-gray-600 italic text-xs">No result yet.</span>
                        )}
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="flex justify-end">
        <Button onClick={() => void handleSave()} disabled={saving} className="bg-white text-black hover:bg-gray-200">
          {saving ? "Saving..." : "Save Configuration"}
        </Button>
      </div>
    </div>
  );
}

"use client";

import { Button, Label, Select, SelectContent, SelectItem, SelectGroup, SelectLabel, SelectTrigger, SelectValue, useToast } from "@/shared/ui";
import { useState, useEffect } from "react";




const STATIC_TRANSLATION_MODELS = [
  { id: "gpt-4o", name: "GPT-4o" },
  { id: "gpt-4-turbo", name: "GPT-4 Turbo" },
  { id: "gpt-3.5-turbo", name: "GPT-3.5 Turbo" },
];

export function AiTranslationSettings() {
  const [translationModel, setTranslationModel] = useState("");
  const [ollamaModels, setOllamaModels] = useState<{ id: string; name: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    const loadData = async () => {
      try {
        const settingsRes = await fetch("/api/settings");
        let settingsMap = new Map<string, string>();
        if (settingsRes.ok) {
          const data = await settingsRes.json() as { key: string, value: string }[];
          settingsMap = new Map(data.map(item => [item.key, item.value]));
        }

        setTranslationModel(settingsMap.get("ai_translation_model") || "gpt-4o");

        const chatbotRes = await fetch("/api/chatbot");
        if (chatbotRes.ok) {
          const data = await chatbotRes.json() as { models?: string[] };
          if (Array.isArray(data.models)) {
            setOllamaModels(data.models.map(name => ({ id: name, name })));
          }
        }
      } catch (error) {
        console.error("Failed to load data:", error);
        toast("Failed to load configuration.", { variant: "error" });
      } finally {
        setLoading(false);
      }
    };
    void loadData();
  }, [toast]);

  const handleSave = async () => {
    setSaving(true);
    try {
      await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          key: "ai_translation_model",
          value: translationModel,
        }),
      });

      toast("Settings saved.", { variant: "success" });
    } catch (error) {
      console.error("Failed to save:", error);
      toast("Failed to save.", { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className="text-sm text-gray-400">Loading settings...</div>;

  return (
    <div className="space-y-8">
      <div>
        <div className="flex items-center justify-between mb-6">
          <div>
            <h2 className="text-lg font-medium text-white mb-1">AI Translation Configuration</h2>
            <p className="text-sm text-gray-400">
              Configure the AI model used for translating product names and descriptions.
            </p>
          </div>
        </div>

        <div className="space-y-6 rounded-md border border-border bg-card/50 p-6">
          <div className="max-w-md space-y-4">
            <div className="space-y-2">
              <Label>Translation Model</Label>
              <Select value={translationModel} onValueChange={setTranslationModel}>
                <SelectTrigger className="mt-1.5 bg-gray-900 border text-white">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectGroup>
                    <SelectLabel>OpenAI</SelectLabel>
                    {STATIC_TRANSLATION_MODELS.map((m) => (
                      <SelectItem key={m.id} value={m.id}>
                        {m.name}
                      </SelectItem>
                    ))}
                  </SelectGroup>
                  {ollamaModels.length > 0 && (
                    <SelectGroup>
                      <SelectLabel>Ollama</SelectLabel>
                      {ollamaModels.map((m) => (
                        <SelectItem key={m.id} value={m.id}>
                          {m.name}
                        </SelectItem>
                      ))}
                    </SelectGroup>
                  )}
                </SelectContent>
              </Select>
              <p className="text-xs text-gray-500 mt-2">
                This model will be used to translate product names and descriptions into
                languages associated with the product&apos;s catalogs.
              </p>
            </div>

            <div className="rounded-md bg-card/50 p-4 border border-border">
              <h4 className="text-sm font-medium text-white mb-2">How It Works</h4>
              <ul className="text-xs text-gray-400 space-y-1 list-disc list-inside">
                <li>
                  Translation requests can be triggered from the Product Edit/Create panel
                </li>
                <li>
                  If the product belongs to catalogs, it translates to those catalog languages
                </li>
                <li>
                  If no catalogs are assigned, it translates to all available languages
                </li>
                <li>
                  Translations are processed as AI jobs and can be monitored on the Jobs page
                </li>
              </ul>
            </div>
          </div>
        </div>
      </div>

      <div className="flex justify-end">
        <Button
          onClick={() => void handleSave()}
          disabled={saving}
          className="bg-white text-black hover:bg-gray-200"
        >
          {saving ? "Saving..." : "Save Configuration"}
        </Button>
      </div>
    </div>
  );
}

import { Button, DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/shared/ui";
import { MoreVertical } from "lucide-react";
import { Catalog } from "@/features/products/types";
import type { Language } from "@/shared/types/internationalization";


type CatalogsSettingsProps = {
  loadingCatalogs: boolean;
  catalogs: Catalog[];
  languages: Language[];
  handleOpenCatalogModal: () => void;
  handleEditCatalog: (catalog: Catalog) => void;
  handleDeleteCatalog: (catalog: Catalog) => void;
};

export function CatalogsSettings({
  loadingCatalogs,
  catalogs,
  languages,
  handleOpenCatalogModal,
  handleEditCatalog,
  handleDeleteCatalog,
}: CatalogsSettingsProps) {
  const getLanguageDisplay = (languageId: string) => {
    const language = languages.find((l) => l.id === languageId);
    return language ? `${language.name} (${language.code})` : languageId;
  };
  const languageIdMap = new Map<string, string>();
  languages.forEach((language) => {
    if (language.id) languageIdMap.set(language.id, language.id);
    if (language.code) languageIdMap.set(language.code, language.id);
  });
  const normalizeLanguageId = (value?: string | null) =>
    value ? languageIdMap.get(value) ?? null : null;
  const resolveCatalogLanguageIds = (catalog: Catalog) => {
    const unique = Array.from(new Set(catalog.languageIds ?? []));
    const normalized = unique
      .map((id) => normalizeLanguageId(id))
      .filter((id): id is string => Boolean(id));
    return normalized.length > 0 ? normalized : unique;
  };
  return (
    <div className="space-y-5">
      <div className="flex justify-start">
        <Button
          className="min-w-[100px] border border-white/20 hover:border-white/40"
          type="button"
          onClick={() => handleOpenCatalogModal()}
        >
          Add Catalog
        </Button>
      </div>
      <div className="rounded-md border border-border bg-card/60 p-4">
        <p className="text-sm font-semibold text-white">Existing Catalogs</p>
        {loadingCatalogs ? (
          <div className="mt-4 rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
            Loading catalogs...
          </div>
        ) : catalogs.length === 0 ? (
          <div className="mt-4 rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
            No catalogs yet.
          </div>
        ) : (
          <div className="mt-4 space-y-3">
            {catalogs.map((catalog) => (
              <div
                key={catalog.id}
                className="flex items-start justify-between gap-3 rounded-md border border-border bg-gray-900 px-3 py-2"
              >
                <div>
                  <p className="text-sm font-semibold text-white">
                    {catalog.name}
                    {catalog.isDefault ? (
                      <span className="ml-2 rounded-full border border-emerald-500/40 bg-emerald-500/10 px-2 py-0.5 text-[10px] font-semibold text-emerald-200">
                        Default
                      </span>
                    ) : null}
                  </p>
                  <p className="text-xs text-gray-400">
                    {catalog.description || "No description"}
                  </p>
                  {catalog.languageIds && catalog.languageIds.length > 0 ? (
                    <div className="mt-2 flex flex-wrap gap-2 text-[11px] text-gray-300">
                      {resolveCatalogLanguageIds(catalog).map(
                        (languageId, index) => (
                          <span
                            key={languageId}
                            className={`rounded-full border px-2 py-0.5 ${
                              normalizeLanguageId(catalog.defaultLanguageId) ===
                              languageId
                                ? "border-emerald-500/40 bg-emerald-500/10 text-emerald-200"
                                : "border bg-gray-900"
                            }`}
                          >
                            {index + 1}. {getLanguageDisplay(languageId)}
                            {normalizeLanguageId(catalog.defaultLanguageId) ===
                              languageId && " (Default)"}
                          </span>
                        )
                      )}
                    </div>
                  ) : null}
                </div>
                <div className="flex gap-2">
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button className="p-1 hover:bg-muted/50 rounded-full text-gray-400 hover:text-white">
                        <MoreVertical className="h-4 w-4" />
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                      <DropdownMenuItem
                        onClick={() => handleEditCatalog(catalog)}
                        className="cursor-pointer"
                      >
                        Edit
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        className="text-red-400 focus:text-red-400 cursor-pointer"
                        onClick={() => handleDeleteCatalog(catalog)}
                      >
                        Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { AppModal, ModalShell, Button, Input, Label, Textarea, Checkbox, useToast } from "@/shared/ui";









import type { Catalog, PriceGroup } from "@/features/products/types";
import type { Language } from "@/shared/types/internationalization";

interface CatalogModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  catalog?: Catalog | null;
  languages: Language[];
  languagesLoading: boolean;
  languagesError: string | null;
  priceGroups: PriceGroup[];
  loadingGroups: boolean;
  defaultGroupId: string;
}

export function CatalogModal({
  isOpen,
  onClose,
  onSuccess,
  catalog,
  languages,
  languagesLoading,
  languagesError,
  priceGroups,
  loadingGroups,
  defaultGroupId,
}: CatalogModalProps) {
  const { toast } = useToast();
  const [saving, setSaving] = React.useState(false);
  const [error, setError] = React.useState<string | null>(null);
  const [form, setForm] = React.useState({
    name: "",
    description: "",
    isDefault: false,
  });
  const [selectedLanguageIds, setSelectedLanguageIds] = React.useState<string[]>([]);
  const [defaultLanguageId, setDefaultLanguageId] = React.useState("");
  const [catalogPriceGroupIds, setCatalogPriceGroupIds] = React.useState<string[]>([]);
  const [catalogDefaultPriceGroupId, setCatalogDefaultPriceGroupId] = React.useState("");
  const [languageQuery, setLanguageQuery] = React.useState("");

  React.useEffect(() => {
    if (catalog) {
      setForm({
        name: catalog.name,
        description: catalog.description ?? "",
        isDefault: catalog.isDefault,
      });
      const nextLanguageIds = catalog.languageIds ?? [];
      setSelectedLanguageIds(nextLanguageIds);
      setDefaultLanguageId(catalog.defaultLanguageId ?? nextLanguageIds[0] ?? "");
      const nextPriceGroupIds = catalog.priceGroupIds?.length ? catalog.priceGroupIds : (defaultGroupId ? [defaultGroupId] : []);
      setCatalogPriceGroupIds(nextPriceGroupIds);
      setCatalogDefaultPriceGroupId(catalog.defaultPriceGroupId ?? nextPriceGroupIds[0] ?? defaultGroupId ?? "");
    } else {
      setForm({
        name: "",
        description: "",
        isDefault: false,
      });
      setSelectedLanguageIds([]);
      setDefaultLanguageId("");
      setCatalogPriceGroupIds(defaultGroupId ? [defaultGroupId] : []);
      setCatalogDefaultPriceGroupId(defaultGroupId ?? "");
    }
    setError(null);
    setLanguageQuery("");
  }, [catalog, defaultGroupId]);

  const handleSubmit = async () => {
    if (saving) return;
    const name = form.name.trim();
    if (!name) {
      toast("Catalog name is required.", { variant: "error" });
      return;
    }
    if (selectedLanguageIds.length === 0) {
      toast("Select at least one language.", { variant: "error" });
      return;
    }
    if (!defaultLanguageId || !selectedLanguageIds.includes(defaultLanguageId)) {
      toast("Select a default language.", { variant: "error" });
      return;
    }
    if (catalogPriceGroupIds.length === 0) {
      toast("Select at least one price group.", { variant: "error" });
      return;
    }
    if (!catalogDefaultPriceGroupId || !catalogPriceGroupIds.includes(catalogDefaultPriceGroupId)) {
      toast("Select a default price group.", { variant: "error" });
      return;
    }

    setSaving(true);
    try {
      const endpoint = catalog ? `/api/catalogs/${catalog.id}` : "/api/catalogs";
      const res = await fetch(endpoint, {
        method: catalog ? "PUT" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name,
          description: form.description.trim(),
          languageIds: selectedLanguageIds,
          defaultLanguageId,
          priceGroupIds: catalogPriceGroupIds,
          defaultPriceGroupId: catalogDefaultPriceGroupId,
          isDefault: form.isDefault,
        }),
      });

      if (!res.ok) {
        const payload = await res.json() as { error?: string; errorId?: string };
        const message = payload.error || "Failed to save catalog.";
        setError(payload.errorId ? `${message} (Error ID: ${payload.errorId})` : message);
        return;
      }

      toast("Catalog saved.", { variant: "success" });
      onSuccess();
    } catch (err) {
      console.error(err);
      setError("Failed to save catalog.");
    } finally {
      setSaving(false);
    }
  };

  const availableLanguages = React.useMemo(() => {
    const query = languageQuery.trim().toLowerCase();
    return languages.filter(l => 
      !selectedLanguageIds.includes(l.id) && 
      (!query || l.name.toLowerCase().includes(query) || l.code.toLowerCase().includes(query))
    );
  }, [languages, selectedLanguageIds, languageQuery]);

  const toggleLanguage = (id: string) => {
    setSelectedLanguageIds(prev => {
      const next = prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id];
      if (!next.includes(defaultLanguageId)) setDefaultLanguageId(next[0] ?? "");
      return next;
    });
  };

  const moveLanguage = (id: string, direction: "up" | "down") => {
    setSelectedLanguageIds(prev => {
      const idx = prev.indexOf(id);
      if (idx === -1) return prev;
      const nextIdx = direction === "up" ? idx - 1 : idx + 1;
      if (nextIdx < 0 || nextIdx >= prev.length) return prev;
      const next = [...prev];
      [next[idx], next[nextIdx]] = [next[nextIdx]!, next[idx]!];
      return next;
    });
  };

  const togglePriceGroup = (id: string) => {
    setCatalogPriceGroupIds(prev => {
      const next = prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id];
      if (!next.includes(catalogDefaultPriceGroupId)) setCatalogDefaultPriceGroupId(next[0] ?? "");
      return next;
    });
  };

  const header = (
    <div className="flex items-center justify-between">
      <div className="flex items-center gap-4">
        <Button
          onClick={() => { void handleSubmit(); }}
          disabled={saving}
          className="min-w-[100px] border border-white/20 hover:border-white/40"
        >
          {saving ? "Saving..." : catalog ? "Update" : "Create"}
        </Button>
        <h2 className="text-2xl font-bold text-white">
          {catalog ? "Edit Catalog" : "Create Catalog"}
        </h2>
      </div>
      <Button
        type="button"
        onClick={onClose}
        className="min-w-[100px] border border-white/20 hover:border-white/40"
      >
        Close
      </Button>
    </div>
  );

  return (
    <AppModal
      open={isOpen}
      onOpenChange={(open) => !open && onClose()}
      title={catalog ? "Edit Catalog" : "Create Catalog"}
    >
      <ModalShell
        title={catalog ? "Edit Catalog" : "Create Catalog"}
        onClose={onClose}
        header={header}
        size="lg"
      >
        <div className="space-y-6">
          {error && (
            <div className="rounded-md border border-red-500/40 bg-red-500/10 p-3 text-xs text-red-200">
              {error}
            </div>
          )}

            <div className="grid gap-4">
              <div className="space-y-2">
                <Label htmlFor="catalog-name">Name</Label>
                <Input
                  id="catalog-name"
                  value={form.name}
                  onChange={(e) => setForm(p => ({ ...p, name: e.target.value }))}
                  placeholder="e.g. Main Store"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="catalog-desc">Description</Label>
                <Textarea
                  id="catalog-desc"
                  value={form.description}
                  onChange={(e) => setForm(p => ({ ...p, description: e.target.value }))}
                  placeholder="Optional description..."
                  rows={2}
                />
              </div>
              <Label className="flex items-center gap-2 text-gray-300">
                <Checkbox
                  checked={form.isDefault}
                  onCheckedChange={(v) => setForm(p => ({ ...p, isDefault: Boolean(v) }))}
                />
                Set as default catalog
              </Label>
            </div>

            <div className="rounded-md border border-border bg-card/70 p-4 space-y-4">
              <Label className="text-sm font-semibold text-white">Languages</Label>
              {languagesLoading ? (
                <p className="text-xs text-gray-500">Loading languages...</p>
              ) : languagesError ? (
                <p className="text-xs text-red-400">{languagesError}</p>
              ) : (
                <div className="space-y-4">
                  <Input
                    placeholder="Search languages..."
                    value={languageQuery}
                    onChange={(e) => setLanguageQuery(e.target.value)}
                  />

                  <div className="space-y-1">
                    {selectedLanguageIds.length === 0 ? (
                      <p className="text-xs text-gray-500">No languages selected.</p>
                    ) : (
                      selectedLanguageIds.map((id, index) => {
                        const lang = languages.find(l => l.id === id);
                        if (!lang) return null;
                        return (
                          <div key={id} className="flex items-center justify-between rounded-md border bg-gray-900 px-3 py-1.5 text-xs text-gray-200">
                            <div className="flex items-center gap-2">
                              <span className="text-gray-500 w-4">{index + 1}.</span>
                              <span>{lang.name} ({lang.code})</span>
                              {id === defaultLanguageId && (
                                <span className="rounded-full bg-emerald-500/20 px-2 py-0.5 text-[10px] text-emerald-300">Default</span>
                              )}
                            </div>
                            <div className="flex gap-1">
                              <Button variant="ghost" size="icon" className="h-6 w-6" onClick={() => moveLanguage(id, "up")} disabled={index === 0}>
                                ↑
                              </Button>
                              <Button variant="ghost" size="icon" className="h-6 w-6" onClick={() => moveLanguage(id, "down")} disabled={index === selectedLanguageIds.length - 1}>
                                ↓
                              </Button>
                              <Button variant="ghost" size="icon" className="h-6 w-6 text-red-400" onClick={() => toggleLanguage(id)}>
                                ×
                              </Button>
                            </div>
                          </div>
                        );
                      })
                    )}
                  </div>

                  <div className="max-h-32 overflow-y-auto rounded-md border border-border bg-gray-900 p-2 text-xs">
                    {availableLanguages.map(lang => (
                      <Button key={lang.id} variant="ghost" className="w-full justify-between h-8 px-2" onClick={() => toggleLanguage(lang.id)}>
                        <span>{lang.name} ({lang.code})</span>
                        <span className="text-gray-500">Add</span>
                      </Button>
                    ))}
                  </div>

                  <div className="space-y-2">
                    <Label className="text-xs text-gray-400">Default language</Label>
                    <select
                      className="w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-xs text-white"
                      value={defaultLanguageId}
                      onChange={(e) => setDefaultLanguageId(e.target.value)}
                      disabled={selectedLanguageIds.length === 0}
                    >
                      <option value="">Select default...</option>
                      {selectedLanguageIds.map(id => {
                        const lang = languages.find(l => l.id === id);
                        return <option key={id} value={id}>{lang?.name} ({lang?.code})</option>;
                      })}
                    </select>
                  </div>
                </div>
              )}
            </div>

            <div className="rounded-md border border-border bg-card/70 p-4 space-y-4">
              <Label className="text-sm font-semibold text-white">Price Groups</Label>
              {loadingGroups ? (
                <p className="text-xs text-gray-500">Loading groups...</p>
              ) : (
                <div className="space-y-4">
                  <div className="flex flex-wrap gap-2">
                    {catalogPriceGroupIds.map(id => {
                      const group = priceGroups.find(g => g.id === id);
                      return (
                        <Button key={id} variant="secondary" className="h-7 rounded-full px-3 text-xs" onClick={() => togglePriceGroup(id)}>
                          {group?.name ?? id} <span className="ml-1 text-gray-500">×</span>
                        </Button>
                      );
                    })}
                  </div>

                  <div className="max-h-32 overflow-y-auto rounded-md border border-border bg-gray-900 p-2 text-xs">
                    {priceGroups.map(group => (
                      <Button key={group.id} variant="ghost" className="w-full justify-between h-8 px-2" onClick={() => togglePriceGroup(group.id)}>
                        <span>{group.name} ({group.currencyCode})</span>
                        <span>{catalogPriceGroupIds.includes(group.id) ? "Remove" : "Add"}</span>
                      </Button>
                    ))}
                  </div>

                  <div className="space-y-2">
                    <Label className="text-xs text-gray-400">Default price group</Label>
                    <select
                      className="w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-xs text-white"
                      value={catalogDefaultPriceGroupId}
                      onChange={(e) => setCatalogDefaultPriceGroupId(e.target.value)}
                      disabled={catalogPriceGroupIds.length === 0}
                    >
                      <option value="">Select default...</option>
                      {catalogPriceGroupIds.map(id => {
                        const group = priceGroups.find(g => g.id === id);
                        return <option key={id} value={id}>{group?.name}</option>;
                      })}
                    </select>
                  </div>
                </div>
              )}
            </div>
        </div>
      </ModalShell>
    </AppModal>
  );
}

