                      onChange={(e) => setForm(p => ({ ...p, priceMultiplier: Number(e.target.value) }))}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="pg-add">Add To Price</Label>
                    <Input
                      id="pg-add"
                      type="number"
                      value={form.addToPrice}
                      onChange={(e) => setForm(p => ({ ...p, addToPrice: Number(e.target.value) }))}
                    />
                  </div>
                </div>
              </div>
            )}
        </div>
      </ModalShell>
    </AppModal>
  );
}

