    label: "Chunky Mono",
    gridSize: 6,
    pixelSizeRatio: 1.6,
    grayscaleOnly: true,
    invertColor: false,
    luminanceMethod: 1,
  },
  inverted: {
    label: "Inverted",
    gridSize: 4,
    pixelSizeRatio: 1,
    grayscaleOnly: false,
    invertColor: true,
    luminanceMethod: 1,
  },
} as const;

type OrderedDitheringPresetKey = keyof typeof orderedDitheringPresets;

const orderedDitheringLuminanceOptions = [
  { value: 0, label: "Average" },
  { value: 1, label: "Rec. 601" },
  { value: 2, label: "Rec. 709" },
  { value: 3, label: "Max Channel" },
];

export function Asset3DPreviewModal({
  open,
  onClose,
  asset,
}: Asset3DPreviewModalProps) {
  // View settings
  const [autoRotate, setAutoRotate] = useState(true);
  const [autoRotateSpeed, setAutoRotateSpeed] = useState(2);

  // Environment & Lighting
  const [environment, setEnvironment] = useState<EnvironmentPreset>("studio");
  const [lighting, setLighting] = useState<LightingPreset>("studio");
  const [lightIntensity, setLightIntensity] = useState(1);

  // Rendering
  const [enableShadows, setEnableShadows] = useState(true);
  const [enableContactShadows, setEnableContactShadows] = useState(true);
  const [showGround, setShowGround] = useState(false);

  // Post-processing
  const [enableBloom, setEnableBloom] = useState(false);
  const [bloomIntensity, setBloomIntensity] = useState(0.5);
  const [enableVignette, setEnableVignette] = useState(false);
  const [enableToneMapping, setEnableToneMapping] = useState(true);
  const [exposure, setExposure] = useState(1);

  // Dithering (special effect)
  const [enableDithering, setEnableDithering] = useState(false);
  const [ditheringIntensity, setDitheringIntensity] = useState(1.0);

  // Pixelation (pixel art effect)
  const [enablePixelation, setEnablePixelation] = useState(false);
  const [pixelSize, setPixelSize] = useState(6);

  // Ordered dithering shader
  const [enableOrderedDithering, setEnableOrderedDithering] = useState(false);
  const [orderedDitheringGridSize, setOrderedDitheringGridSize] = useState(4);
  const [orderedDitheringPixelSizeRatio, setOrderedDitheringPixelSizeRatio] = useState(1);
  const [orderedDitheringGrayscaleOnly, setOrderedDitheringGrayscaleOnly] = useState(false);
  const [orderedDitheringInvertColor, setOrderedDitheringInvertColor] = useState(false);
  const [orderedDitheringLuminanceMethod, setOrderedDitheringLuminanceMethod] = useState(1);
  const [orderedDitheringPreset, setOrderedDitheringPreset] = useState<
    OrderedDitheringPresetKey | "custom"
  >("balanced");

  // Background
  const [backgroundColor, setBackgroundColor] = useState("#1a1a2e");

  // UI State
  const [showSettings, setShowSettings] = useState(false);
  const [activeTab, setActiveTab] = useState<"environment" | "effects" | "view">("environment");

  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / 1024 / 1024).toFixed(2)} MB`;
  };

  const applyOrderedDitheringPreset = (preset: OrderedDitheringPresetKey) => {
    const config = orderedDitheringPresets[preset];
    setOrderedDitheringGridSize(config.gridSize);
    setOrderedDitheringPixelSizeRatio(config.pixelSizeRatio);
    setOrderedDitheringGrayscaleOnly(config.grayscaleOnly);
    setOrderedDitheringInvertColor(config.invertColor);
    setOrderedDitheringLuminanceMethod(config.luminanceMethod);
  };

  const resetSettings = () => {
    setAutoRotate(true);
    setAutoRotateSpeed(2);
    setEnvironment("studio");
    setLighting("studio");
    setLightIntensity(1);
    setEnableShadows(true);
    setEnableContactShadows(true);
    setShowGround(false);
    setEnableBloom(false);
    setBloomIntensity(0.5);
    setEnableVignette(false);
    setEnableToneMapping(true);
    setExposure(1);
    setEnableDithering(false);
    setDitheringIntensity(1);
    setEnablePixelation(false);
    setPixelSize(6);
    setEnableOrderedDithering(false);
    setOrderedDitheringGridSize(4);
    setOrderedDitheringPixelSizeRatio(1);
    setOrderedDitheringGrayscaleOnly(false);
    setOrderedDitheringInvertColor(false);
    setOrderedDitheringLuminanceMethod(1);
    setOrderedDitheringPreset("balanced");
    setBackgroundColor("#1a1a2e");
  };

  return (
    <AppModal open={open} onOpenChange={(o) => !o && onClose()} title={asset.filename}>
      <div className="bg-gray-900 rounded-lg shadow-2xl w-[95vw] max-w-6xl border border-gray-700 flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-gray-700 flex-shrink-0">
          <div className="flex-1 min-w-0">
            <h2 className="text-lg font-semibold text-white truncate">
              {asset.name || asset.filename}
            </h2>
            <p className="text-xs text-gray-400">{formatFileSize(asset.size)}</p>
          </div>
          <div className="flex items-center gap-2">
            <Button
              variant="ghost"
              size="sm"
              onClick={resetSettings}
              title="Reset settings"
            >
              <RotateCcw className="h-4 w-4" />
            </Button>
            <Button
              variant={showSettings ? "default" : "ghost"}
              size="sm"
              onClick={() => setShowSettings(!showSettings)}
            >
              <Settings2 className="h-4 w-4 mr-1" />
              Settings
              {showSettings ? (
                <ChevronUp className="h-4 w-4 ml-1" />
              ) : (
                <ChevronDown className="h-4 w-4 ml-1" />
              )}
            </Button>
            <a href={asset.filepath} download={asset.filename}>
              <Button variant="secondary" size="sm">
                <Download className="h-4 w-4 mr-1" />
                Download
              </Button>
            </a>
            <Button variant="ghost" size="icon" onClick={onClose}>
              <X className="h-4 w-4" />
            </Button>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex flex-1 min-h-0">
          {/* Viewer */}
          <div className={cn("flex-1 bg-gray-950", showSettings ? "lg:w-2/3" : "w-full")}>
            <Viewer3D
              modelUrl={asset.filepath}
              backgroundColor={backgroundColor}
              autoRotate={autoRotate}
              autoRotateSpeed={autoRotateSpeed}
              environment={environment}
              lighting={lighting}
              lightIntensity={lightIntensity}
              enableShadows={enableShadows}
              enableContactShadows={enableContactShadows}
              showGround={showGround}
              enableBloom={enableBloom}
              bloomIntensity={bloomIntensity}
              enableVignette={enableVignette}
              enableToneMapping={enableToneMapping}
              exposure={exposure}
              enableDithering={enableDithering}
              ditheringIntensity={ditheringIntensity}
              enableOrderedDithering={enableOrderedDithering}
              orderedDitheringGridSize={orderedDitheringGridSize}
              orderedDitheringPixelSizeRatio={orderedDitheringPixelSizeRatio}
              orderedDitheringGrayscaleOnly={orderedDitheringGrayscaleOnly}
              orderedDitheringInvertColor={orderedDitheringInvertColor}
              orderedDitheringLuminanceMethod={orderedDitheringLuminanceMethod}
              enablePixelation={enablePixelation}
              pixelSize={pixelSize}
              className="w-full h-[60vh]"
            />
          </div>

          {/* Settings Panel */}
          {showSettings && (
            <div className="w-full lg:w-1/3 border-l border-gray-700 bg-gray-900/50 overflow-y-auto">
              {/* Tabs */}
              <div className="flex border-b border-gray-700">
                <button
                  onClick={() => setActiveTab("environment")}
                  className={cn(
                    "flex-1 py-2 px-3 text-sm font-medium transition-colors",
                    activeTab === "environment"
                      ? "text-white border-b-2 border-blue-500"
                      : "text-gray-400 hover:text-white"
                  )}
                >
                  <Sun className="h-4 w-4 inline mr-1" />
                  Environment
                </button>
                <button
                  onClick={() => setActiveTab("effects")}
                  className={cn(
                    "flex-1 py-2 px-3 text-sm font-medium transition-colors",
                    activeTab === "effects"
                      ? "text-white border-b-2 border-blue-500"
                      : "text-gray-400 hover:text-white"
                  )}
                >
                  <Sparkles className="h-4 w-4 inline mr-1" />
                  Effects
                </button>
                <button
                  onClick={() => setActiveTab("view")}
                  className={cn(
                    "flex-1 py-2 px-3 text-sm font-medium transition-colors",
                    activeTab === "view"
                      ? "text-white border-b-2 border-blue-500"
                      : "text-gray-400 hover:text-white"
                  )}
                >
                  <Eye className="h-4 w-4 inline mr-1" />
                  View
                </button>
              </div>

              <div className="p-4 space-y-4">
                {/* Environment Tab */}
                {activeTab === "environment" && (
                  <>
                    {/* Environment Preset */}
                    <div>
                      <Label className="text-sm text-gray-300 mb-2 block">HDR Environment</Label>
                      <select
                        value={environment}
                        onChange={(e) => setEnvironment(e.target.value as EnvironmentPreset)}
                        className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-md text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                      >
                        {environmentPresets.map((preset) => (
                          <option key={preset.value} value={preset.value}>
                            {preset.label}
                          </option>
                        ))}
                      </select>
                    </div>

                    {/* Lighting Preset */}
                    <div>
                      <Label className="text-sm text-gray-300 mb-2 block">Lighting</Label>
                      <div className="grid grid-cols-2 gap-2">
                        {lightingPresets.map((preset) => (
                          <button
                            key={preset.value}
                            onClick={() => setLighting(preset.value)}
                            className={cn(
                              "flex items-center gap-2 px-3 py-2 rounded-md text-sm transition-colors",
                              lighting === preset.value
                                ? "bg-blue-600 text-white"
                                : "bg-gray-800 text-gray-300 hover:bg-gray-700"
                            )}
                          >
                            {preset.icon}
                            {preset.label}
                          </button>
                        ))}
                      </div>
                    </div>

                    {/* Light Intensity */}
                    <div>
                      <Label className="text-sm text-gray-300 mb-2 block">
                        Light Intensity: {lightIntensity.toFixed(1)}
                      </Label>
                      <input
                        type="range"
                        min="0.1"
                        max="3"
                        step="0.1"
                        value={lightIntensity}
                        onChange={(e) => setLightIntensity(parseFloat(e.target.value))}
                        className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                      />
                    </div>

                    {/* Background Color */}
                    <div>
                      <Label className="text-sm text-gray-300 mb-2 block">Background</Label>
                      <div className="flex gap-2">
                        {["#1a1a2e", "#0a0a0f", "#1f1f1f", "#2d2d3a", "#111827"].map((color) => (
                          <button
                            key={color}
                            onClick={() => setBackgroundColor(color)}
                            className={cn(
                              "w-8 h-8 rounded-md border-2 transition-all",
                              backgroundColor === color
                                ? "border-blue-500 scale-110"
                                : "border-gray-600 hover:border-gray-500"
                            )}
                            style={{ backgroundColor: color }}
                          />
                        ))}
                        <input
                          type="color"
                          value={backgroundColor}
                          onChange={(e) => setBackgroundColor(e.target.value)}
                          className="w-8 h-8 rounded-md cursor-pointer"
                        />
                      </div>
                    </div>

                    {/* Shadows */}
                    <div className="space-y-2">
                      <label className="flex items-center gap-3 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={enableShadows}
                          onChange={(e) => setEnableShadows(e.target.checked)}
                          className="rounded border-gray-600 bg-gray-800 text-blue-500"
                        />
                        <span className="text-sm text-gray-300">Enable Shadows</span>
                      </label>
                      <label className="flex items-center gap-3 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={enableContactShadows}
                          onChange={(e) => setEnableContactShadows(e.target.checked)}
                          className="rounded border-gray-600 bg-gray-800 text-blue-500"
                        />
                        <span className="text-sm text-gray-300">Contact Shadows</span>
                      </label>
                      <label className="flex items-center gap-3 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={showGround}
                          onChange={(e) => setShowGround(e.target.checked)}
                          className="rounded border-gray-600 bg-gray-800 text-blue-500"
                        />
                        <span className="text-sm text-gray-300">Show Ground</span>
                      </label>
                    </div>
                  </>
                )}

                {/* Effects Tab */}
                {activeTab === "effects" && (
                  <>
                    {/* Tone Mapping */}
                    <div className="space-y-2">
                      <label className="flex items-center gap-3 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={enableToneMapping}
                          onChange={(e) => setEnableToneMapping(e.target.checked)}
                          className="rounded border-gray-600 bg-gray-800 text-blue-500"
                        />
                        <span className="text-sm text-gray-300">ACES Tone Mapping</span>
                      </label>
                      {enableToneMapping && (
                        <div className="pl-6">
                          <Label className="text-xs text-gray-400 mb-1 block">
                            Exposure: {exposure.toFixed(1)}
                          </Label>
                          <input
                            type="range"
                            min="0.1"
                            max="3"
                            step="0.1"
                            value={exposure}
                            onChange={(e) => setExposure(parseFloat(e.target.value))}
                            className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                          />
                        </div>
                      )}
                    </div>

                    {/* Bloom */}
                    <div className="space-y-2">
                      <label className="flex items-center gap-3 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={enableBloom}
                          onChange={(e) => setEnableBloom(e.target.checked)}
                          className="rounded border-gray-600 bg-gray-800 text-blue-500"
                        />
                        <span className="text-sm text-gray-300">Bloom Effect</span>
                      </label>
                      {enableBloom && (
                        <div className="pl-6">
                          <Label className="text-xs text-gray-400 mb-1 block">
                            Intensity: {bloomIntensity.toFixed(1)}
                          </Label>
                          <input
                            type="range"
                            min="0"
                            max="2"
                            step="0.1"
                            value={bloomIntensity}
                            onChange={(e) => setBloomIntensity(parseFloat(e.target.value))}
                            className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                          />
                        </div>
                      )}
                    </div>

                    {/* Vignette */}
                    <label className="flex items-center gap-3 cursor-pointer">
                      <input
                        type="checkbox"
                        checked={enableVignette}
                        onChange={(e) => setEnableVignette(e.target.checked)}
                        className="rounded border-gray-600 bg-gray-800 text-blue-500"
                      />
                      <span className="text-sm text-gray-300">Vignette</span>
                    </label>

                    {/* Pixelation */}
                    <div className="space-y-2 pt-4 border-t border-gray-700">
                      <label className="flex items-center gap-3 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={enablePixelation}
                          onChange={(e) => setEnablePixelation(e.target.checked)}
                          className="rounded border-gray-600 bg-gray-800 text-blue-500"
                        />
                        <div>
                          <span className="text-sm text-gray-300">Pixel Art</span>
                          <p className="text-xs text-gray-500">Chunky pixelated rendering</p>
                        </div>
                      </label>
                      {enablePixelation && (
                        <div className="pl-6">
                          <Label className="text-xs text-gray-400 mb-1 block">
                            Pixel Size: {pixelSize}px
                          </Label>
                          <input
                            type="range"
                            min="2"
                            max="24"
                            step="1"
                            value={pixelSize}
                            onChange={(e) => setPixelSize(parseInt(e.target.value, 10))}
                            className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                          />
                        </div>
                      )}
                    </div>

                    {/* Ordered Dithering */}
                    <div className="space-y-2 pt-4 border-t border-gray-700">
                      <label className="flex items-center gap-3 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={enableOrderedDithering}
                          onChange={(e) => setEnableOrderedDithering(e.target.checked)}
                          className="rounded border-gray-600 bg-gray-800 text-blue-500"
                        />
                        <div>
                          <span className="text-sm text-gray-300">Ordered Dithering</span>
                          <p className="text-xs text-gray-500">Shader-based dither with pixel grid</p>
                        </div>
                      </label>
                      {enableOrderedDithering && (
                        <div className="pl-6 space-y-3">
                          <div>
                            <Label className="text-xs text-gray-400 mb-1 block">Preset</Label>
                            <select
                              value={orderedDitheringPreset}
                              onChange={(e) => {
                                const value = e.target.value as OrderedDitheringPresetKey | "custom";
                                setOrderedDitheringPreset(value);
                                if (value !== "custom") {
                                  applyOrderedDitheringPreset(value);
                                }
                              }}
                              className="w-full px-2 py-1 bg-gray-800 border border-gray-700 rounded-md text-xs text-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                            >
                              {Object.entries(orderedDitheringPresets).map(([key, preset]) => (
                                <option key={key} value={key}>
                                  {preset.label}
                                </option>
                              ))}
                              <option value="custom">Custom</option>
                            </select>
                          </div>
                          <div>
                            <Label className="text-xs text-gray-400 mb-1 block">
                              Grid Size: {orderedDitheringGridSize.toFixed(1)}
                            </Label>
                            <input
                              type="range"
                              min="2"
                              max="12"
                              step="0.5"
                              value={orderedDitheringGridSize}
                              onChange={(e) => {
                                setOrderedDitheringGridSize(parseFloat(e.target.value));
                                setOrderedDitheringPreset("custom");
                              }}
                              className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                            />
                          </div>
                          <div>
                            <Label className="text-xs text-gray-400 mb-1 block">
                              Pixel Ratio: {orderedDitheringPixelSizeRatio.toFixed(1)}
                            </Label>
                            <input
                              type="range"
                              min="0.5"
                              max="3"
                              step="0.1"
                              value={orderedDitheringPixelSizeRatio}
                              onChange={(e) => {
                                setOrderedDitheringPixelSizeRatio(parseFloat(e.target.value));
                                setOrderedDitheringPreset("custom");
                              }}
                              className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                            />
                          </div>
                          <div>
                            <Label className="text-xs text-gray-400 mb-1 block">Luminance</Label>
                            <select
                              value={orderedDitheringLuminanceMethod}
                              onChange={(e) => {
                                setOrderedDitheringLuminanceMethod(parseInt(e.target.value, 10));
                                setOrderedDitheringPreset("custom");
                              }}
                              className="w-full px-2 py-1 bg-gray-800 border border-gray-700 rounded-md text-xs text-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                            >
                              {orderedDitheringLuminanceOptions.map((option) => (
                                <option key={option.value} value={option.value}>
                                  {option.label}
                                </option>
                              ))}
                            </select>
                          </div>
                          <label className="flex items-center gap-3 cursor-pointer">
                            <input
                              type="checkbox"
                              checked={orderedDitheringGrayscaleOnly}
                              onChange={(e) => {
                                setOrderedDitheringGrayscaleOnly(e.target.checked);
                                setOrderedDitheringPreset("custom");
                              }}
                              className="rounded border-gray-600 bg-gray-800 text-blue-500"
                            />
                            <span className="text-xs text-gray-300">Grayscale only</span>
                          </label>
                          <label className="flex items-center gap-3 cursor-pointer">
                            <input
                              type="checkbox"
                              checked={orderedDitheringInvertColor}
                              onChange={(e) => {
                                setOrderedDitheringInvertColor(e.target.checked);
                                setOrderedDitheringPreset("custom");
                              }}
                              className="rounded border-gray-600 bg-gray-800 text-blue-500"
                            />
                            <span className="text-xs text-gray-300">Invert colors</span>
                          </label>
                        </div>
                      )}
                    </div>

                    {/* Dithering */}
                    <div className="space-y-2 pt-4 border-t border-gray-700">
                      <label className="flex items-center gap-3 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={enableDithering}
                          onChange={(e) => setEnableDithering(e.target.checked)}
                          className="rounded border-gray-600 bg-gray-800 text-blue-500"
                        />
                        <div>
                          <span className="text-sm text-gray-300">B&W Dithering</span>
                          <p className="text-xs text-gray-500">Artistic retro effect</p>
                        </div>
                      </label>
                      {enableDithering && (
                        <div className="pl-6">
                          <Label className="text-xs text-gray-400 mb-1 block">
                            Intensity: {ditheringIntensity.toFixed(1)}
                          </Label>
                          <input
                            type="range"
                            min="0.1"
                            max="2"
                            step="0.1"
                            value={ditheringIntensity}
                            onChange={(e) => setDitheringIntensity(parseFloat(e.target.value))}
                            className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                          />
                        </div>
                      )}
                    </div>
                  </>
                )}

                {/* View Tab */}
                {activeTab === "view" && (
                  <>
                    {/* Auto Rotate */}
                    <div className="space-y-2">
                      <label className="flex items-center gap-3 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={autoRotate}
                          onChange={(e) => setAutoRotate(e.target.checked)}
                          className="rounded border-gray-600 bg-gray-800 text-blue-500"
                        />
                        <span className="text-sm text-gray-300">Auto-rotate</span>
                      </label>
                      {autoRotate && (
                        <div className="pl-6">
                          <Label className="text-xs text-gray-400 mb-1 block">
                            Speed: {autoRotateSpeed.toFixed(1)}
                          </Label>
                          <input
                            type="range"
                            min="0.5"
                            max="10"
                            step="0.5"
                            value={autoRotateSpeed}
                            onChange={(e) => setAutoRotateSpeed(parseFloat(e.target.value))}
                            className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                          />
                        </div>
                      )}
                    </div>

                    {/* Controls Help */}
                    <div className="p-3 bg-gray-800/50 rounded-lg text-xs text-gray-400 space-y-1">
                      <p className="font-medium text-gray-300 mb-2">Controls:</p>
                      <p>• Left click + drag to rotate</p>
                      <p>• Right click + drag to pan</p>
                      <p>• Scroll to zoom</p>
                    </div>
                  </>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Quick Actions Bar */}
        <div className="flex items-center justify-between px-4 py-2 border-t border-gray-700 bg-gray-900/80 flex-shrink-0">
          <div className="flex items-center gap-2 text-xs text-gray-500">
            <Layers className="h-4 w-4" />
            <span>{environment} environment</span>
            <span className="mx-1">•</span>
            <span>{lighting} lighting</span>
          </div>
          <div className="flex items-center gap-2">
            {enableBloom && (
              <span className="px-2 py-0.5 text-xs bg-purple-500/20 text-purple-400 rounded">
                Bloom
              </span>
            )}
            {enablePixelation && (
              <span className="px-2 py-0.5 text-xs bg-amber-500/20 text-amber-400 rounded">
                Pixel Art
              </span>
            )}
            {enableOrderedDithering && (
              <span className="px-2 py-0.5 text-xs bg-teal-500/20 text-teal-400 rounded">
                Ordered Dither
              </span>
            )}
            {enableDithering && (
              <span className="px-2 py-0.5 text-xs bg-gray-700 text-gray-400 rounded">
                Dithering
              </span>
            )}
            {enableShadows && (
              <span className="px-2 py-0.5 text-xs bg-blue-500/20 text-blue-400 rounded">
                Shadows
              </span>
            )}
          </div>
        </div>
      </div>
    </AppModal>
  );
}

"use client";

import { Button, Input, Label } from "@/shared/ui";
import { Upload, Loader2, Plus, X } from "lucide-react";
import { useState, useRef, useCallback } from "react";
import { validate3DFile, SUPPORTED_3D_FORMATS } from "../utils/validateAsset3d";
import { uploadAsset3DFile } from "../api";
import type { Asset3DRecord } from "../types";
import { cn } from "@/shared/utils";

export interface Asset3DUploaderProps {
  onUpload: (asset: Asset3DRecord) => void;
  onCancel?: () => void;
  existingCategories?: string[];
  existingTags?: string[];
  className?: string;
}

export function Asset3DUploader({
  onUpload,
  onCancel,
  existingCategories = [],
  existingTags = [],
  className,
}: Asset3DUploaderProps) {
  const [file, setFile] = useState<File | null>(null);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [category, setCategory] = useState("");
  const [tags, setTags] = useState<string[]>([]);
  const [newTag, setNewTag] = useState("");
  const [isPublic, setIsPublic] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isDragOver, setIsDragOver] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = useCallback((selectedFile: File) => {
    const validation = validate3DFile(selectedFile);
    if (!validation.valid) {
      setError(validation.error ?? "Invalid file");
      return;
    }
    setFile(selectedFile);
    setError(null);
    // Auto-fill name from filename
    if (!name) {
      const cleanName = selectedFile.name
        .replace(/\.[^/.]+$/, "")
        .replace(/[-_]/g, " ")
        .replace(/\s+/g, " ")
        .trim();
      setName(cleanName);
    }
  }, [name]);

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragOver(false);
      const droppedFile = e.dataTransfer.files[0];
      if (droppedFile) handleFileSelect(droppedFile);
    },
    [handleFileSelect]
  );

  const handleAddTag = () => {
    const trimmed = newTag.trim().toLowerCase();
    if (trimmed && !tags.includes(trimmed)) {
      setTags([...tags, trimmed]);
      setNewTag("");
    }
  };

  const handleRemoveTag = (tag: string) => {
    setTags(tags.filter((t) => t !== tag));
  };

  const handleUpload = async () => {
    if (!file) return;

    setIsUploading(true);
    setError(null);

    try {
      const uploaded = await uploadAsset3DFile(file, {
        ...(name.trim() && { name: name.trim() }),
        ...(description.trim() && { description: description.trim() }),
        ...(category.trim() && { category: category.trim() }),
        ...(tags.length > 0 && { tags }),
        isPublic,
      });
      onUpload(uploaded);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Upload failed");
    } finally {
      setIsUploading(false);
    }
  };

  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / 1024 / 1024).toFixed(2)} MB`;
  };

  return (
    <div className={className}>
      {/* File Drop Zone */}
      {!file ? (
        <div
          className={cn(
            "relative flex h-32 cursor-pointer items-center justify-center rounded-lg border-2 border-dashed transition-colors",
            isDragOver
              ? "border-blue-500 bg-blue-500/10"
              : "border-gray-600 bg-gray-800/50 hover:border-blue-500 hover:bg-gray-800"
          )}
          onDragOver={(e) => {
            e.preventDefault();
            setIsDragOver(true);
          }}
          onDragLeave={(e) => {
            e.preventDefault();
            setIsDragOver(false);
          }}
          onDrop={handleDrop}
          onClick={() => fileInputRef.current?.click()}
        >
          <div className="flex flex-col items-center gap-2">
            <Upload className="h-8 w-8 text-gray-500" />
            <span className="text-sm text-gray-400">
              Drop .glb or .gltf file here
            </span>
            <span className="text-xs text-gray-500">or click to browse</span>
          </div>
          <input
            ref={fileInputRef}
            type="file"
            accept=".glb,.gltf"
            className="hidden"
            onChange={(e) => {
              const selectedFile = e.target.files?.[0];
              if (selectedFile) handleFileSelect(selectedFile);
              e.target.value = "";
            }}
          />
        </div>
      ) : (
        <div className="space-y-4">
          {/* Selected File */}
          <div className="flex items-center justify-between p-3 bg-gray-800 rounded-lg border border-gray-700">
            <div className="flex items-center gap-3">
              <div className="h-10 w-10 bg-blue-500/20 rounded flex items-center justify-center">
                <Upload className="h-5 w-5 text-blue-400" />
              </div>
              <div>
                <p className="text-sm font-medium text-white">{file.name}</p>
                <p className="text-xs text-gray-400">{formatFileSize(file.size)}</p>
              </div>
            </div>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setFile(null)}
              disabled={isUploading}
            >
              <X className="h-4 w-4" />
            </Button>
          </div>

          {/* Name */}
          <div>
            <Label htmlFor="upload-name" className="text-sm text-gray-300">
              Name
            </Label>
            <Input
              id="upload-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Enter asset name..."
              className="mt-1 bg-gray-800 border-gray-700"
              disabled={isUploading}
            />
          </div>

          {/* Description */}
          <div>
            <Label htmlFor="upload-description" className="text-sm text-gray-300">
              Description
            </Label>
            <textarea
              id="upload-description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Enter description..."
              rows={2}
              className="mt-1 w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-md text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 resize-none text-sm"
              disabled={isUploading}
            />
          </div>

          {/* Category */}
          <div>
            <Label htmlFor="upload-category" className="text-sm text-gray-300">
              Category
            </Label>
            <Input
              id="upload-category"
              value={category}
              onChange={(e) => setCategory(e.target.value)}
              placeholder="Enter category..."
              list="upload-categories-list"
              className="mt-1 bg-gray-800 border-gray-700"
              disabled={isUploading}
            />
            <datalist id="upload-categories-list">
              {existingCategories.map((cat) => (
                <option key={cat} value={cat} />
              ))}
            </datalist>
          </div>

          {/* Tags */}
          <div>
            <Label className="text-sm text-gray-300">Tags</Label>
            <div className="mt-1 flex gap-2">
              <Input
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    handleAddTag();
                  }
                }}
                placeholder="Add tag..."
                list="upload-tags-list"
                className="bg-gray-800 border-gray-700 flex-1"
                disabled={isUploading}
              />
              <datalist id="upload-tags-list">
                {existingTags
                  .filter((t) => !tags.includes(t))
                  .map((tag) => (
                    <option key={tag} value={tag} />
                  ))}
              </datalist>
              <Button
                type="button"
                variant="secondary"
                size="icon"
                onClick={handleAddTag}
                disabled={isUploading}
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>
            {tags.length > 0 && (
              <div className="flex flex-wrap gap-1 mt-2">
                {tags.map((tag) => (
                  <span
                    key={tag}
                    className="inline-flex items-center gap-1 px-2 py-1 bg-gray-700 text-gray-300 rounded text-xs"
                  >
                    {tag}
                    <button
                      type="button"
                      onClick={() => handleRemoveTag(tag)}
                      className="text-gray-500 hover:text-red-400"
                      disabled={isUploading}
                    >
                      <X className="h-3 w-3" />
                    </button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Visibility */}
          <label className="flex items-center gap-3 cursor-pointer">
            <input
              type="checkbox"
              checked={isPublic}
              onChange={(e) => setIsPublic(e.target.checked)}
              className="rounded border-gray-600 bg-gray-800 text-blue-500 focus:ring-blue-500"
              disabled={isUploading}
            />
            <span className="text-sm text-gray-300">Make publicly visible</span>
          </label>
        </div>
      )}

      {/* Error */}
      {error && (
        <p className="mt-2 text-sm text-red-400">{error}</p>
      )}

      {/* Format Info */}
      <p className="mt-2 text-xs text-gray-500">
        Supported formats: {Object.keys(SUPPORTED_3D_FORMATS).join(", ")}. Max 100MB.
      </p>

      {/* Actions */}
      {file && (
        <div className="flex justify-end gap-2 mt-4">
          {onCancel && (
            <Button variant="ghost" onClick={onCancel} disabled={isUploading}>
              Cancel
            </Button>
          )}
          <Button onClick={() => void handleUpload()} disabled={isUploading}>
            {isUploading ? (
              <>
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                Uploading...
              </>
            ) : (
              <>
                <Upload className="h-4 w-4 mr-2" />
                Upload Asset
              </>
            )}
          </Button>
        </div>
      )}
    </div>
  );
}

"use client";

import { Canvas, useThree } from "@react-three/fiber";
import {
  OrbitControls,
  Center,
  useGLTF,
  Environment,
  Html,
  ContactShadows,
  useProgress,
  Bounds,
  PresentationControls,
} from "@react-three/drei";
import { EffectComposer, Bloom, SMAA, ToneMapping, Vignette } from "@react-three/postprocessing";
import { Suspense, useEffect, useRef, useMemo } from "react";
import * as THREE from "three";
import { DitheringPass } from "./shaders/DitheringEffect";
import { PixelationPass } from "./shaders/PixelationEffect";
import { OrderedDitheringPass } from "./shaders/OrderedDitheringEffect";
import { ToneMappingMode, BlendFunction } from "postprocessing";

// Loading progress component
function Loader() {
  const { progress } = useProgress();
  return (
    <Html center>
      <div className="flex flex-col items-center gap-3">
        <div className="relative h-16 w-16">
          <svg className="h-16 w-16 -rotate-90" viewBox="0 0 36 36">
            <circle
              cx="18"
              cy="18"
              r="16"
              fill="none"
              className="stroke-gray-700"
              strokeWidth="2"
            />
            <circle
              cx="18"
              cy="18"
              r="16"
              fill="none"
              className="stroke-blue-500"
              strokeWidth="2"
              strokeDasharray={100}
              strokeDashoffset={100 - progress}
              strokeLinecap="round"
            />
          </svg>
          <span className="absolute inset-0 flex items-center justify-center text-xs font-medium text-white">
            {Math.round(progress)}%
          </span>
        </div>
        <span className="text-sm text-gray-400">Loading model...</span>
      </div>
    </Html>
  );
}

// Enhanced model component with PBR material optimization
interface Model3DProps {
  url: string;
  onLoad?: () => void;
  onError?: (error: Error) => void;
  castShadow?: boolean;
  receiveShadow?: boolean;
}

function Model3D({ url, onLoad, onError, castShadow = true, receiveShadow = true }: Model3DProps) {
  const { scene } = useGLTF(url);
  const modelRef = useRef<THREE.Group>(null);

  useEffect(() => {
    if (scene) {
      // Optimize materials for PBR rendering
      scene.traverse((child) => {
        if (child instanceof THREE.Mesh) {
          child.castShadow = castShadow;
          child.receiveShadow = receiveShadow;

          // Enhance material properties for better realism
          if (child.material instanceof THREE.MeshStandardMaterial) {
            child.material.envMapIntensity = 1.5;
            child.material.needsUpdate = true;
          }
        }
      });
      onLoad?.();
    }
  }, [scene, onLoad, castShadow, receiveShadow]);

  useEffect(() => {
    if (!scene && onError) {
      onError(new Error("Failed to load model"));
    }
  }, [scene, onError]);

  /* eslint-disable react/no-unknown-property */
  return (
    <primitive
      ref={modelRef}
      object={scene}
      dispose={null}
    />
  );
  /* eslint-enable react/no-unknown-property */
}

// Ground plane with realistic shadows
function Ground({ visible = true }: { visible?: boolean }) {
  if (!visible) return null;

  /* eslint-disable react/no-unknown-property */
  return (
    <mesh
      rotation={[-Math.PI / 2, 0, 0]}
      position={[0, -0.001, 0]}
      receiveShadow
    >
      <planeGeometry args={[50, 50]} />
      <shadowMaterial
        transparent
        opacity={0.4}
      />
    </mesh>
  );
  /* eslint-enable react/no-unknown-property */
}

// Scene lighting setup
interface SceneLightingProps {
  preset: LightingPreset;
  intensity?: number;
}

function SceneLighting({ preset, intensity = 1 }: SceneLightingProps) {
  const lightConfigs = {
    studio: {
      ambient: 0.4,
      main: { position: [5, 5, 5] as [number, number, number], intensity: 1.2 },
      fill: { position: [-5, 3, -5] as [number, number, number], intensity: 0.5 },
      rim: { position: [0, 5, -10] as [number, number, number], intensity: 0.8 },
    },
    outdoor: {
      ambient: 0.3,
      main: { position: [10, 10, 5] as [number, number, number], intensity: 1.5 },
      fill: { position: [-5, 2, 5] as [number, number, number], intensity: 0.3 },
      rim: { position: [0, 8, -8] as [number, number, number], intensity: 0.4 },
    },
    dramatic: {
      ambient: 0.15,
      main: { position: [3, 8, 3] as [number, number, number], intensity: 2 },
      fill: { position: [-8, 2, -3] as [number, number, number], intensity: 0.2 },
      rim: { position: [-3, 5, -8] as [number, number, number], intensity: 1.2 },
    },
    soft: {
      ambient: 0.6,
      main: { position: [5, 5, 5] as [number, number, number], intensity: 0.8 },
      fill: { position: [-5, 5, 5] as [number, number, number], intensity: 0.6 },
      rim: { position: [0, 3, -5] as [number, number, number], intensity: 0.4 },
    },
  };

  const config = lightConfigs[preset] || lightConfigs.studio;

  /* eslint-disable react/no-unknown-property */
  return (
    <>
      <ambientLight intensity={config.ambient * intensity} />
      <directionalLight
        position={config.main.position}
        intensity={config.main.intensity * intensity}
        castShadow
        shadow-mapSize={[2048, 2048]}
        shadow-camera-far={50}
        shadow-camera-left={-10}
        shadow-camera-right={10}
        shadow-camera-top={10}
        shadow-camera-bottom={-10}
        shadow-bias={-0.0001}
      />
      <directionalLight
        position={config.fill.position}
        intensity={config.fill.intensity * intensity}
      />
      <directionalLight
        position={config.rim.position}
        intensity={config.rim.intensity * intensity}
      />
    </>
  );
  /* eslint-enable react/no-unknown-property */
}

// Camera auto-framing
function CameraController({ autoFit }: { autoFit?: boolean }) {
  const { camera, scene } = useThree();

  useEffect(() => {
    if (autoFit) {
      const box = new THREE.Box3().setFromObject(scene);
      const size = box.getSize(new THREE.Vector3());
      const center = box.getCenter(new THREE.Vector3());

      const maxDim = Math.max(size.x, size.y, size.z);
      const fov = (camera as THREE.PerspectiveCamera).fov * (Math.PI / 180);
      let distance = maxDim / (2 * Math.tan(fov / 2));
      distance *= 1.5; // Add some padding

      camera.position.set(center.x + distance * 0.5, center.y + distance * 0.3, center.z + distance);
      camera.lookAt(center);
      camera.updateProjectionMatrix();
    }
  }, [autoFit, camera, scene]);

  return null;
}

export type LightingPreset = "studio" | "outdoor" | "dramatic" | "soft";
export type EnvironmentPreset = "studio" | "sunset" | "dawn" | "night" | "warehouse" | "forest" | "apartment" | "city" | "park" | "lobby";

export interface Viewer3DProps {
  /** URL to the 3D model file (.glb or .gltf) */
  modelUrl: string;
  /** Background color */
  backgroundColor?: string;
  /** Enable dithering post-processing effect */
  enableDithering?: boolean;
  /** Dithering intensity (0-2, default 1) */
  ditheringIntensity?: number;
  /** Enable ordered dithering shader */
  enableOrderedDithering?: boolean;
  /** Dither grid size (2-12, default 4) */
  orderedDitheringGridSize?: number;
  /** Dither pixel size ratio (0.5-3, default 1) */
  orderedDitheringPixelSizeRatio?: number;
  /** Dither grayscale only */
  orderedDitheringGrayscaleOnly?: boolean;
  /** Dither invert colors */
  orderedDitheringInvertColor?: boolean;
  /** Dither luminance method (0=Average, 1=Rec.601, 2=Rec.709, 3=Max) */
  orderedDitheringLuminanceMethod?: number;
  /** Enable pixelation (pixel art effect) */
  enablePixelation?: boolean;
  /** Pixel size in screen pixels (1-32, default 6) */
  pixelSize?: number;
  /** Container class name */
  className?: string;
  /** Callback when model loads */
  onLoad?: () => void;
  /** Callback on load error */
  onError?: (error: Error) => void;
  /** Enable auto-rotation */
  autoRotate?: boolean;
  /** Auto-rotation speed */
  autoRotateSpeed?: number;
  /** Environment preset for HDR lighting */
  environment?: EnvironmentPreset;
  /** Lighting preset */
  lighting?: LightingPreset;
  /** Light intensity multiplier */
  lightIntensity?: number;
  /** Enable shadows */
  enableShadows?: boolean;
  /** Enable bloom effect */
  enableBloom?: boolean;
  /** Bloom intensity */
  bloomIntensity?: number;
  /** Enable tone mapping */
  enableToneMapping?: boolean;
  /** Tone mapping exposure */
  exposure?: number;
  /** Show ground plane */
  showGround?: boolean;
  /** Enable contact shadows */
  enableContactShadows?: boolean;
  /** Enable vignette effect */
  enableVignette?: boolean;
  /** Auto-fit camera to model */
  autoFit?: boolean;
  /** Enable anti-aliasing */
  enableAntiAliasing?: boolean;
  /** Use presentation controls (drag to rotate) */
  presentationMode?: boolean;
}

export function Viewer3D({
  modelUrl,
  backgroundColor = "#1a1a2e",
  enableDithering = false,
  ditheringIntensity = 1.0,
  enableOrderedDithering = false,
  orderedDitheringGridSize = 4,
  orderedDitheringPixelSizeRatio = 1,
  orderedDitheringGrayscaleOnly = false,
  orderedDitheringInvertColor = false,
  orderedDitheringLuminanceMethod = 1,
  enablePixelation = false,
  pixelSize = 6,
  className,
  onLoad,
  onError,
  autoRotate = true,
  autoRotateSpeed = 2,
  environment = "studio",
  lighting = "studio",
  lightIntensity = 1,
  enableShadows = true,
  enableBloom = false,
  bloomIntensity = 0.5,
  enableToneMapping = true,
  exposure = 1,
  showGround = false,
  enableContactShadows = true,
  enableVignette = false,
  autoFit = true,
  enableAntiAliasing = true,
  presentationMode = false,
}: Viewer3DProps) {
  const hasPostProcessing =
    enableDithering ||
    enableOrderedDithering ||
    enablePixelation ||
    enableBloom ||
    enableToneMapping ||
    enableVignette ||
    enableAntiAliasing;

  const effects = useMemo(() => {
    const effectsList: React.ReactElement[] = [];
    if (enableAntiAliasing) effectsList.push(<SMAA key="smaa" />);
    if (enableToneMapping) effectsList.push(<ToneMapping key="tonemapping" mode={ToneMappingMode.ACES_FILMIC} />);
    if (enableBloom) effectsList.push(<Bloom key="bloom" intensity={bloomIntensity} luminanceThreshold={0.9} luminanceSmoothing={0.025} />);
    if (enableVignette) effectsList.push(<Vignette key="vignette" offset={0.3} darkness={0.5} blendFunction={BlendFunction.NORMAL} />);
    if (enablePixelation) effectsList.push(<PixelationPass key="pixelation" pixelSize={Math.max(1, pixelSize)} />);
    if (enableOrderedDithering) {
      effectsList.push(
        <OrderedDitheringPass
          key="ordered-dithering"
          gridSize={orderedDitheringGridSize}
          pixelSizeRatio={orderedDitheringPixelSizeRatio}
          grayscaleOnly={orderedDitheringGrayscaleOnly}
          invertColor={orderedDitheringInvertColor}
          luminanceMethod={orderedDitheringLuminanceMethod}
        />
      );
    }
    if (enableDithering) effectsList.push(<DitheringPass key="dithering" intensity={ditheringIntensity} />);
    return effectsList;
  }, [
    enableAntiAliasing,
    enableToneMapping,
    enableBloom,
    bloomIntensity,
    enableVignette,
    enablePixelation,
    pixelSize,
    enableOrderedDithering,
    orderedDitheringGridSize,
    orderedDitheringPixelSizeRatio,
    orderedDitheringGrayscaleOnly,
    orderedDitheringInvertColor,
    orderedDitheringLuminanceMethod,
    enableDithering,
    ditheringIntensity,
  ]);

  return (
    <div className={className}>
      <Canvas
        camera={{ position: [0, 0, 5], fov: 45, near: 0.1, far: 1000 }}
        shadows={enableShadows}
        gl={{
          preserveDrawingBuffer: true,
          antialias: !hasPostProcessing, // Disable if using SMAA
          toneMapping: enableToneMapping ? THREE.ACESFilmicToneMapping : THREE.NoToneMapping,
          toneMappingExposure: exposure,
          outputColorSpace: THREE.SRGBColorSpace,
        }}
        dpr={[1, 2]} // Responsive pixel ratio
      >
        {/* eslint-disable react/no-unknown-property */}
        <color attach="background" args={[backgroundColor]} />
        {/* eslint-enable react/no-unknown-property */}

        {/* Lighting */}
        <SceneLighting preset={lighting} intensity={lightIntensity} />

        {/* HDR Environment */}
        <Environment preset={environment} background={false} />

        <Suspense fallback={<Loader />}>
          {presentationMode ? (
            <PresentationControls
              global
              rotation={[0, 0, 0]}
              polar={[-Math.PI / 4, Math.PI / 4]}
              azimuth={[-Math.PI / 4, Math.PI / 4]}
            >
              <Center>
                <Bounds fit clip observe margin={1.2}>
                  <Model3D
                    url={modelUrl}
                    {...(onLoad && { onLoad })}
                    {...(onError && { onError })}
                    castShadow={enableShadows}
                    receiveShadow={enableShadows}
                  />
                </Bounds>
              </Center>
            </PresentationControls>
          ) : (
            <Center>
              <Bounds fit clip observe margin={1.2}>
                <Model3D
                  url={modelUrl}
                  {...(onLoad && { onLoad })}
                  {...(onError && { onError })}
                  castShadow={enableShadows}
                  receiveShadow={enableShadows}
                />
              </Bounds>
            </Center>
          )}

          {/* Ground and shadows */}
          {showGround && <Ground visible={showGround} />}

          {enableContactShadows && (
            <ContactShadows
              opacity={0.5}
              scale={10}
              blur={2}
              far={4}
              resolution={256}
              color="#000000"
            />
          )}
        </Suspense>

        {/* Camera Controls */}
        {!presentationMode && (
          <OrbitControls
            autoRotate={autoRotate}
            autoRotateSpeed={autoRotateSpeed}
            enablePan={true}
            enableZoom={true}
            enableDamping={true}
            dampingFactor={0.05}
            minDistance={0.5}
            maxDistance={100}
            minPolarAngle={0}
            maxPolarAngle={Math.PI}
          />
        )}

        <CameraController autoFit={autoFit} />

        {/* Post-processing */}
        {hasPostProcessing && effects.length > 0 && (
          <EffectComposer multisampling={0}>
            {effects}
          </EffectComposer>
        )}
      </Canvas>
    </div>
  );
}

