  const error = assetsQuery.error instanceof Error ? assetsQuery.error.message : null;
  const categories = categoriesQuery.data ?? [];
  const allTags = tagsQuery.data ?? [];

  const handleUpload = (_asset: Asset3DRecord) => {
    setShowUploader(false);
    void queryClient.invalidateQueries({ queryKey: ["assets3d"] });
  };

  const handleEdit = (_updated: Asset3DRecord) => {
    void queryClient.invalidateQueries({ queryKey: ["assets3d"] });
  };

  const handleDelete = async (asset: Asset3DRecord) => {
    if (!confirm(`Are you sure you want to delete "${asset.name || asset.filename}"?`)) {
      return;
    }

    setDeletingId(asset.id);
    try {
      await deleteAsset3DById(asset.id);
      void queryClient.invalidateQueries({ queryKey: ["assets3d"] });
    } catch (err) {
      alert(err instanceof Error ? err.message : "Failed to delete asset");
    } finally {
      setDeletingId(null);
    }
  };

  const clearFilters = () => {
    setSearchQuery("");
    setSelectedCategory(null);
    setSelectedTags([]);
  };

  const hasActiveFilters = searchQuery || selectedCategory || selectedTags.length > 0;

  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / 1024 / 1024).toFixed(2)} MB`;
  };

  const formatDate = (date: Date | string) => {
    return new Date(date).toLocaleDateString("en-US", {
      year: "numeric",
      month: "short",
      day: "numeric",
    });
  };

  const stats =
    !loading && assets.length > 0 ? (
      <div className="text-sm text-muted-foreground">
