import prisma from "@/shared/lib/db/prisma";
import { Prisma } from "@prisma/client";
import type {
  Asset3DCreateInput,
  Asset3DListFilters,
  Asset3DRecord,
  Asset3DRepository,
  Asset3DUpdateInput,
} from "@/features/viewer3d/types";

const toRecord = (asset: {
  id: string;
  name: string | null;
  description: string | null;
  filename: string;
  filepath: string;
  mimetype: string;
  size: number;
  tags: string[];
  category: string | null;
  metadata: unknown;
  isPublic: boolean;
  createdAt: Date;
  updatedAt: Date;
}): Asset3DRecord => ({
  id: asset.id,
  name: asset.name,
  description: asset.description,
  filename: asset.filename,
  filepath: asset.filepath,
  mimetype: asset.mimetype,
  size: asset.size,
  tags: asset.tags,
  category: asset.category,
  metadata: asset.metadata as Record<string, unknown> | null,
  isPublic: asset.isPublic,
  createdAt: asset.createdAt,
  updatedAt: asset.updatedAt,
});

export const prismaAsset3DRepository: Asset3DRepository = {
  async createAsset3D(data: Asset3DCreateInput) {
    const asset = await prisma.asset3D.create({
      data: {
        name: data.name ?? null,
        description: data.description ?? null,
        filename: data.filename,
        filepath: data.filepath,
        mimetype: data.mimetype,
        size: data.size,
        tags: data.tags ?? [],
        category: data.category ?? null,
        metadata: data.metadata ? (data.metadata as Prisma.InputJsonValue) : Prisma.JsonNull,
        isPublic: data.isPublic ?? false,
      },
    });
    return toRecord(asset);
  },

  async getAsset3DById(id: string) {
    const asset = await prisma.asset3D.findUnique({ where: { id } });
    return asset ? toRecord(asset) : null;
  },

  async listAssets3D(filters?: Asset3DListFilters) {
    const where: Prisma.Asset3DWhereInput = {};

    if (filters?.filename?.trim()) {
      where.filename = {
        contains: filters.filename.trim(),
        mode: "insensitive",
      };
    }

    if (filters?.category) {
      where.category = filters.category;
    }

    if (filters?.isPublic !== undefined) {
      where.isPublic = filters.isPublic;
    }

    if (filters?.tags && filters.tags.length > 0) {
      where.tags = {
        hasSome: filters.tags,
      };
    }

    if (filters?.search?.trim()) {
      const searchTerm = filters.search.trim();
      where.OR = [
        { name: { contains: searchTerm, mode: "insensitive" } },
        { description: { contains: searchTerm, mode: "insensitive" } },
        { filename: { contains: searchTerm, mode: "insensitive" } },
      ];
    }

    const assets = await prisma.asset3D.findMany({
      where,
      orderBy: { createdAt: "desc" },
    });
    return assets.map(toRecord);
  },

  async updateAsset3D(id: string, data: Asset3DUpdateInput) {
    try {
      const updateData: Prisma.Asset3DUpdateInput = {};
      if (data.name !== undefined) updateData.name = data.name;
      if (data.description !== undefined) updateData.description = data.description;
      if (data.tags !== undefined) updateData.tags = data.tags;
      if (data.category !== undefined) updateData.category = data.category;
      if (data.metadata !== undefined) {
        updateData.metadata = data.metadata ? (data.metadata as Prisma.InputJsonValue) : Prisma.JsonNull;
      }
      if (data.isPublic !== undefined) updateData.isPublic = data.isPublic;

      const asset = await prisma.asset3D.update({
        where: { id },
        data: updateData,
      });
      return toRecord(asset);
    } catch {
      return null;
    }
  },

  async deleteAsset3D(id: string) {
    try {
      const asset = await prisma.asset3D.delete({ where: { id } });
      return toRecord(asset);
    } catch {
      return null;
    }
  },

  async getCategories() {
    const results = await prisma.asset3D.findMany({
      where: { category: { not: null } },
      select: { category: true },
      distinct: ["category"],
    });
    return results
      .map((r) => r.category)
      .filter((c): c is string => c !== null);
  },

  async getTags() {
    const assets = await prisma.asset3D.findMany({
      where: { tags: { isEmpty: false } },
      select: { tags: true },
    });
    const allTags = assets.flatMap((a) => a.tags);
    return [...new Set(allTags)];
  },
};

import fs from "fs/promises";
import path from "path";
import { getAsset3DRepository } from "@/features/viewer3d/services/asset3d-repository";
import { ErrorSystem } from "@/features/observability/server";
import type { Asset3DRecord } from "@/features/viewer3d/types";
import { isValid3DAsset } from "./validateAsset3d";

const uploadsRoot = path.join(process.cwd(), "public", "uploads");
const assets3dRoot = path.join(uploadsRoot, "assets3d");

export function getDiskPathFromPublicPath(publicPath: string) {
  return path.join(process.cwd(), "public", publicPath.replace(/^\/+/, ""));
}

export async function uploadAsset3D(
  file: File,
  options?: {
    name?: string;
    description?: string;
    category?: string;
    tags?: string[];
    isPublic?: boolean;
    metadata?: Record<string, unknown>;
  }
): Promise<Asset3DRecord> {
  if (!isValid3DAsset(file)) {
    throw new Error("Invalid 3D asset file type. Supported: .glb, .gltf");
  }

  const fileBuffer = Buffer.from(await file.arrayBuffer());
  const filename = `${Date.now()}-${path.basename(file.name)}`;
  const diskDir = assets3dRoot;
  const publicDir = `/uploads/assets3d`;
  const filepath = path.join(diskDir, filename);

  try {
    await fs.mkdir(diskDir, { recursive: true });
    await fs.writeFile(filepath, fileBuffer);

    const repository = getAsset3DRepository();
    const asset = await repository.createAsset3D({
      filename,
      filepath: `${publicDir}/${filename}`,
      mimetype: file.type || "application/octet-stream",
      size: file.size,
      tags: options?.tags ?? [],
      isPublic: options?.isPublic ?? false,
      ...(options?.name && { name: options.name }),
      ...(options?.description && { description: options.description }),
      ...(options?.category && { category: options.category }),
      ...(options?.metadata && { metadata: options.metadata }),
    });

    return asset;
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "asset3dUploader",
      action: "uploadAsset3D",
      filename,
      diskDir,
    });
    throw error;
  }
}

export async function deleteAsset3D(id: string): Promise<boolean> {
  try {
    const repository = getAsset3DRepository();
    const asset = await repository.getAsset3DById(id);

    if (!asset) {
      return false;
    }

    // Delete file from disk
    const diskPath = getDiskPathFromPublicPath(asset.filepath);
    await fs.unlink(diskPath).catch(() => {});

    // Delete from database
    await repository.deleteAsset3D(id);

    return true;
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "asset3dUploader",
      action: "deleteAsset3D",
      id,
    });
    return false;
  }
}

