export default prisma;

import "server-only";

import { createHash } from "crypto";
import type { SystemLogLevel, SystemLogRecord } from "@/shared/types/system-logs";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import prisma from "@/shared/lib/db/prisma";
import { getAppDbProvider } from "@/shared/lib/db/app-db-provider";
import { withTransientRecovery } from "@/shared/utils/transient-recovery";

const SETTINGS_COLLECTION = "settings";

const NOTIFICATION_SETTINGS_KEYS = {
  enabled: "critical_notifications_enabled",
  webhookUrl: "critical_notifications_webhook_url",
  minLevel: "critical_notifications_min_level",
  throttleSeconds: "critical_notifications_throttle_seconds",
} as const;

const DEFAULT_THROTTLE_SECONDS = 120;

type NotificationConfig = {
  enabled: boolean;
  webhookUrl: string | null;
  minLevel: SystemLogLevel;
  throttleSeconds: number;
};

type SettingRecord = { _id: string; key?: string; value?: string };

const canUsePrismaSettings = () =>
  Boolean(process.env.DATABASE_URL) && "setting" in prisma;

const readPrismaSetting = async (key: string): Promise<string | null> => {
  if (!canUsePrismaSettings()) return null;
  try {
    const setting = await prisma.setting.findUnique({
      where: { key },
      select: { value: true },
    });
    return setting?.value ?? null;
  } catch {
    return null;
  }
};

const readMongoSetting = async (key: string): Promise<string | null> => {
  if (!process.env.MONGODB_URI) return null;
  const mongo = await getMongoDb();
  const doc = await mongo
    .collection<SettingRecord>(SETTINGS_COLLECTION)
    .findOne({ $or: [{ _id: key }, { key }] });
  return typeof doc?.value === "string" ? doc.value : null;
};

const readSettingValue = async (key: string): Promise<string | null> => {
  const provider = await getAppDbProvider();
  if (provider === "mongodb") {
    return readMongoSetting(key);
  }
  return readPrismaSetting(key);
};

const parseBoolean = (value: string | null | undefined, fallback = false) => {
  if (typeof value !== "string") return fallback;
  return value.trim().toLowerCase() === "true";
};

const parseNumber = (value: string | null | undefined, fallback: number) => {
  if (typeof value !== "string") return fallback;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const parseMinLevel = (value: string | null | undefined): SystemLogLevel => {
  const normalized = value?.trim().toLowerCase();
  if (normalized === "warn") return "warn";
  if (normalized === "info") return "info";
  return "error";
};

const levelPriority: Record<SystemLogLevel, number> = {
  info: 1,
  warn: 2,
  error: 3,
};

const shouldNotifyForLevel = (level: SystemLogLevel, minLevel: SystemLogLevel) =>
  levelPriority[level] >= levelPriority[minLevel];

const getNotificationConfig = async (): Promise<NotificationConfig> => {
  const [enabledSetting, webhookSetting, minLevelSetting, throttleSetting] = await Promise.all([
    readSettingValue(NOTIFICATION_SETTINGS_KEYS.enabled),
    readSettingValue(NOTIFICATION_SETTINGS_KEYS.webhookUrl),
    readSettingValue(NOTIFICATION_SETTINGS_KEYS.minLevel),
    readSettingValue(NOTIFICATION_SETTINGS_KEYS.throttleSeconds),
  ]);

  const enabled =
    parseBoolean(enabledSetting) ||
    parseBoolean(process.env.CRITICAL_ERROR_NOTIFICATIONS_ENABLED);
  const webhookUrl = webhookSetting ?? process.env.CRITICAL_ERROR_WEBHOOK_URL ?? null;
  const minLevel = parseMinLevel(minLevelSetting ?? process.env.CRITICAL_ERROR_MIN_LEVEL);
  const throttleSeconds = parseNumber(
    throttleSetting ?? process.env.CRITICAL_ERROR_THROTTLE_SECONDS,
    DEFAULT_THROTTLE_SECONDS
  );

  return {
    enabled,
    webhookUrl,
    minLevel,
    throttleSeconds,
  };
};

const getThrottleCache = (): Map<string, number> => {
  const globalAny = globalThis as typeof globalThis & {
    __criticalErrorNotificationCache?: Map<string, number>;
  };
  if (!globalAny.__criticalErrorNotificationCache) {
    globalAny.__criticalErrorNotificationCache = new Map();
  }
  return globalAny.__criticalErrorNotificationCache;
};

const buildSignature = (log: SystemLogRecord) => {
  const hash = createHash("sha256");
  hash.update(log.message ?? "");
  hash.update(String(log.source ?? ""));
  hash.update(String(log.path ?? ""));
  hash.update(String(log.statusCode ?? ""));
  return hash.digest("hex");
};

const shouldThrottle = (signature: string, throttleSeconds: number) => {
  const cache = getThrottleCache();
  const now = Date.now();
  const previous = cache.get(signature);
  if (previous && now - previous < throttleSeconds * 1000) {
    return true;
  }
  cache.set(signature, now);
  return false;
};

const buildPayload = (log: SystemLogRecord, critical: boolean) => ({
  event: "critical_error",
  critical,
  level: log.level,
  message: log.message,
  source: log.source ?? null,
  path: log.path ?? null,
  method: log.method ?? null,
  statusCode: log.statusCode ?? null,
  requestId: log.requestId ?? null,
  userId: log.userId ?? null,
  createdAt: log.createdAt instanceof Date ? log.createdAt.toISOString() : log.createdAt,
  context: log.context ?? null,
  stack: log.stack ?? null,
  environment: process.env.NODE_ENV ?? "development",
  appUrl: process.env.NEXT_PUBLIC_APP_URL ?? null,
});

export const notifyCriticalError = async (
  log: SystemLogRecord,
  critical: boolean
): Promise<{ delivered: boolean; throttled: boolean }> => {
  try {
    const config = await getNotificationConfig();
    if (!config.enabled || !config.webhookUrl) {
      return { delivered: false, throttled: false };
    }
    if (!shouldNotifyForLevel(log.level, config.minLevel)) {
      return { delivered: false, throttled: false };
    }
    if (!critical) {
      return { delivered: false, throttled: false };
    }

    const signature = buildSignature(log);
    if (shouldThrottle(signature, config.throttleSeconds)) {
      return { delivered: false, throttled: true };
    }

    const payload = buildPayload(log, critical);
    const res = await withTransientRecovery(
      async () =>
        fetch(config.webhookUrl!, {
          method: "POST",
          headers: {
            "content-type": "application/json",
          },
          body: JSON.stringify(payload),
        }),
      {
        source: "critical-error-webhook",
        circuitId: "critical-error-webhook",
        retry: {
          maxAttempts: 3,
          initialDelayMs: 1000,
          maxDelayMs: 10000,
          timeoutMs: 8000,
        },
      }
    );
    if (!res.ok) {
      console.error("[critical-error-notifier] Webhook failed", {
        status: res.status,
        statusText: res.statusText,
      });
      return { delivered: false, throttled: false };
    }
    return { delivered: true, throttled: false };
  } catch (error) {
    console.error("[critical-error-notifier] Webhook error", error);
    return { delivered: false, throttled: false };
  }
};

const SENSITIVE_KEY_PATTERNS = [
  /pass(word)?/i,
  /token/i,
  /secret/i,
  /api[-_]?key/i,
  /authorization/i,
  /^cookie$/i,
  /^set-cookie$/i,
  /session/i,
  /jwt/i,
  /private/i,
  /credential/i,
];

export const REDACTED_VALUE = "[REDACTED]";

export const isSensitiveKey = (key: string) =>
  SENSITIVE_KEY_PATTERNS.some((pattern) => pattern.test(key));

export const truncateString = (value: string, maxLength: number) => {
  if (value.length <= maxLength) return value;
  return `${value.slice(0, maxLength)}…[truncated]`;
};

import "server-only";

import { randomUUID } from "crypto";
import { Prisma } from "@prisma/client";
import { ObjectId, type Filter } from "mongodb";
import { getAppDbProvider } from "@/shared/lib/db/app-db-provider";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import prisma from "@/shared/lib/db/prisma";
import type { SystemLogLevel, SystemLogMetrics, SystemLogRecord } from "@/shared/types/system-logs";

const toMongoId = (id: string): ObjectId | string => {
  if (ObjectId.isValid(id) && id.length === 24) return new ObjectId(id);
  return id;
};

export type CreateSystemLogInput = {
  level?: SystemLogLevel | undefined;
  message: string;
  source?: string | null | undefined;
  context?: Record<string, unknown> | null | undefined;
  stack?: string | null | undefined;
  path?: string | null | undefined;
  method?: string | null | undefined;
  statusCode?: number | null | undefined;
  requestId?: string | null | undefined;
  userId?: string | null | undefined;
  createdAt?: Date | undefined;
};

export type ListSystemLogsInput = {
  page?: number | undefined;
  pageSize?: number | undefined;
  level?: SystemLogLevel | null | undefined;
  source?: string | null | undefined;
  query?: string | null | undefined;
  from?: Date | null | undefined;
  to?: Date | null | undefined;
};

export type ListSystemLogsResult = {
  logs: SystemLogRecord[];
  total: number;
  page: number;
  pageSize: number;
};

const SYSTEM_LOGS_COLLECTION = "system_logs";

type MongoSystemLogDoc = {
  _id?: string | ObjectId;
  id?: string;
  level?: string;
  message?: string;
  source?: string | null;
  context?: Record<string, unknown> | null;
  stack?: string | null;
  path?: string | null;
  method?: string | null;
  statusCode?: number | null;
  requestId?: string | null;
  userId?: string | null;
  createdAt?: Date;
};

const isMissingPrismaTable = (error: unknown) =>
  error instanceof Prisma.PrismaClientKnownRequestError && error.code === "P2021";

const normalizeLogRecord = (record: SystemLogRecord): SystemLogRecord => ({
  ...record,
  createdAt: record.createdAt instanceof Date ? record.createdAt : new Date(record.createdAt),
});

const toSystemLogRecord = (doc: MongoSystemLogDoc): SystemLogRecord => ({
  id: String(doc.id ?? doc._id ?? ""),
  level: (doc.level as SystemLogLevel) ?? "error",
  message: doc.message ?? "",
  source: doc.source ?? null,
  context: doc.context ?? null,
  stack: doc.stack ?? null,
  path: doc.path ?? null,
  method: doc.method ?? null,
  statusCode: doc.statusCode ?? null,
  requestId: doc.requestId ?? null,
  userId: doc.userId ?? null,
  createdAt: doc.createdAt ?? new Date(),
});

const buildPrismaWhere = (input: ListSystemLogsInput): Prisma.SystemLogWhereInput => {
  const where: Prisma.SystemLogWhereInput = {};
  if (input.level) {
    where.level = input.level;
  }
  if (input.source) {
    where.source = { contains: input.source, mode: "insensitive" };
  }
  if (input.query) {
    where.OR = [
      { message: { contains: input.query, mode: "insensitive" } },
      { source: { contains: input.query, mode: "insensitive" } },
    ];
  }
  if (input.from || input.to) {
    where.createdAt = {
      ...(input.from ? { gte: input.from } : {}),
      ...(input.to ? { lte: input.to } : {}),
    };
  }
  return where;
};

const mergeWhere = (base: Prisma.SystemLogWhereInput, extra: Prisma.SystemLogWhereInput): Prisma.SystemLogWhereInput => {
  if (!base || Object.keys(base).length === 0) {
    return extra;
  }
  return { AND: [base, extra] };
};

const buildMongoFilter = (input: ListSystemLogsInput): Filter<MongoSystemLogDoc> => {
  const filter: Filter<MongoSystemLogDoc> = {};
  if (input.level) {
    filter.level = input.level;
  }
  if (input.source) {
    filter.source = { $regex: input.source, $options: "i" };
  }
  if (input.query) {
    filter.$or = [
      { message: { $regex: input.query, $options: "i" } },
      { source: { $regex: input.query, $options: "i" } },
    ];
  }
  if (input.from || input.to) {
    filter.createdAt = {
      ...(input.from ? { $gte: input.from } : {}),
      ...(input.to ? { $lte: input.to } : {}),
    };
  }
  return filter;
};

const getMongoSystemLogMetrics = async (filter: Filter<MongoSystemLogDoc>): Promise<SystemLogMetrics> => {
  const mongo = await getMongoDb();
  const now = new Date();
  const last24 = new Date(now.getTime() - 24 * 60 * 60 * 1000);
  const last7 = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
  const result = await mongo
    .collection(SYSTEM_LOGS_COLLECTION)
    .aggregate([
      { $match: filter },
      {
        $facet: {
          totals: [{ $count: "count" }],
          levels: [
            { $group: { _id: "$level", count: { $sum: 1 } } },
            { $sort: { count: -1 } },
          ],
          sources: [
            { $match: { source: { $nin: [null, ""] } } },
            { $group: { _id: "$source", count: { $sum: 1 } } },
            { $sort: { count: -1 } },
            { $limit: 5 },
          ],
          paths: [
            { $match: { path: { $nin: [null, ""] } } },
            { $group: { _id: "$path", count: { $sum: 1 } } },
            { $sort: { count: -1 } },
            { $limit: 5 },
          ],
          last24Hours: [
            { $match: { createdAt: { $gte: last24 } } },
            { $count: "count" },
          ],
          last7Days: [
            { $match: { createdAt: { $gte: last7 } } },
            { $count: "count" },
          ],
        },
      },
    ])
    .toArray() as unknown as [
      {
        totals: { count: number }[];
        levels: { _id: string; count: number }[];
        sources: { _id: string; count: number }[];
        paths: { _id: string; count: number }[];
        last24Hours: { count: number }[];
        last7Days: { count: number }[];
      },
    ];

  const first = result[0];
  if (!first) {
    return {
      total: 0,
      levels: { info: 0, warn: 0, error: 0 },
      last24Hours: 0,
      last7Days: 0,
      topSources: [],
      topPaths: [],
      generatedAt: now,
    };
  }

  const total = first.totals[0]?.count ?? 0;
  const levels = { info: 0, warn: 0, error: 0 } as Record<SystemLogLevel, number>;
  for (const row of first.levels as { _id: string; count: number }[]) {
    const key = row._id as SystemLogLevel;
    if (key && key in levels) {
      levels[key] = row.count;
    }
  }
  const topSources = first.sources.map((row: { _id: string; count: number }) => ({
    source: String(row._id ?? ""),
    count: row.count,
  }));
  const topPaths = first.paths.map((row: { _id: string; count: number }) => ({
    path: String(row._id ?? ""),
    count: row.count,
  }));
  const last24Hours = first.last24Hours[0]?.count ?? 0;
  const last7Days = first.last7Days[0]?.count ?? 0;

  return {
    total,
    levels,
    last24Hours,
    last7Days,
    topSources,
    topPaths,
    generatedAt: now,
  };
};

export async function createSystemLog(
  input: CreateSystemLogInput
): Promise<SystemLogRecord> {
  const provider = await getAppDbProvider();
  const payload = {
    id: randomUUID(),
    level: input.level ?? "error",
    message: input.message,
    source: input.source ?? null,
    context: input.context ?? null,
    stack: input.stack ?? null,
    path: input.path ?? null,
    method: input.method ?? null,
    statusCode: input.statusCode ?? null,
    requestId: input.requestId ?? null,
    userId: input.userId ?? null,
    createdAt: input.createdAt ?? new Date(),
  };

  if (provider === "mongodb") {
    const mongo = await getMongoDb();
    await mongo.collection<MongoSystemLogDoc>(SYSTEM_LOGS_COLLECTION).insertOne({
      _id: toMongoId(payload.id),
      ...payload,
    });
    return normalizeLogRecord(payload);
  }

  try {
    const created = await prisma.systemLog.create({
      data: {
        level: payload.level,
        message: payload.message,
        ...(payload.source !== null && payload.source !== undefined ? { source: payload.source } : {}),
        ...(payload.context !== null && payload.context !== undefined ? { context: payload.context as Prisma.InputJsonValue } : {}),
        ...(payload.stack !== null && payload.stack !== undefined ? { stack: payload.stack } : {}),
        ...(payload.path !== null && payload.path !== undefined ? { path: payload.path } : {}),
        ...(payload.method !== null && payload.method !== undefined ? { method: payload.method } : {}),
        ...(payload.statusCode !== null && payload.statusCode !== undefined ? { statusCode: payload.statusCode } : {}),
        ...(payload.requestId !== null && payload.requestId !== undefined ? { requestId: payload.requestId } : {}),
        ...(payload.userId !== null && payload.userId !== undefined ? { userId: payload.userId } : {}),
        createdAt: payload.createdAt,
      },
    });

    return normalizeLogRecord({
      ...created,
      level: created.level as SystemLogLevel,
      context: (created.context as Record<string, unknown> | null) ?? null,
      createdAt: created.createdAt,
    });
  } catch (error) {
    if (isMissingPrismaTable(error) && process.env.MONGODB_URI) {
      const mongo = await getMongoDb();
      await mongo.collection<MongoSystemLogDoc>(SYSTEM_LOGS_COLLECTION).insertOne({
        _id: toMongoId(payload.id),
        ...payload,
      });
      return normalizeLogRecord(payload);
    }
    throw error;
  }
}

export async function listSystemLogs(
  input: ListSystemLogsInput
): Promise<ListSystemLogsResult> {
  const provider = await getAppDbProvider();
  const page = Math.max(1, input.page ?? 1);
  const pageSize = Math.min(200, Math.max(1, input.pageSize ?? 50));

  if (provider === "mongodb") {
    const mongo = await getMongoDb();
    const filter = buildMongoFilter(input);
    const total = await mongo
      .collection<MongoSystemLogDoc>(SYSTEM_LOGS_COLLECTION)
      .countDocuments(filter);
    const docs = await mongo
      .collection<MongoSystemLogDoc>(SYSTEM_LOGS_COLLECTION)
      .find(filter)
      .sort({ createdAt: -1 })
      .skip((page - 1) * pageSize)
      .limit(pageSize)
      .toArray();
    const logs = docs.map((doc: MongoSystemLogDoc) => normalizeLogRecord(toSystemLogRecord(doc)));
    return { logs, total, page, pageSize };
  }

  const where = buildPrismaWhere(input);

  try {
    const [total, rows] = await Promise.all([
      prisma.systemLog.count({ where }),
      prisma.systemLog.findMany({
        where,
        orderBy: { createdAt: "desc" },
        skip: (page - 1) * pageSize,
        take: pageSize,
      }),
    ]);

    const logs = rows.map((row: Prisma.SystemLog) =>
      normalizeLogRecord({
        ...row,
        level: row.level as SystemLogLevel,
        context: (row.context as Record<string, unknown> | null) ?? null,
      })
    );

    return { logs, total, page, pageSize };
  } catch (error) {
    if (isMissingPrismaTable(error) && process.env.MONGODB_URI) {
      const mongo = await getMongoDb();
      const filter = buildMongoFilter(input);
      const total = await mongo
        .collection<MongoSystemLogDoc>(SYSTEM_LOGS_COLLECTION)
        .countDocuments(filter);
      const docs = await mongo
        .collection<MongoSystemLogDoc>(SYSTEM_LOGS_COLLECTION)
        .find(filter)
        .sort({ createdAt: -1 })
        .skip((page - 1) * pageSize)
        .limit(pageSize)
        .toArray();
      const logs = docs.map((doc) =>
        normalizeLogRecord(toSystemLogRecord(doc))
      );
      return { logs, total, page, pageSize };
    }
    throw error;
  }
}

export async function getSystemLogMetrics(
  input: ListSystemLogsInput
): Promise<SystemLogMetrics> {
  const provider = await getAppDbProvider();
  const now = new Date();

  if (provider === "mongodb") {
    const filter = buildMongoFilter(input);
    return getMongoSystemLogMetrics(filter);
  }

  const where = buildPrismaWhere(input);
  const last24 = new Date(now.getTime() - 24 * 60 * 60 * 1000);
  const last7 = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

  try {
    const [
      total,
      last24Hours,
      last7Days,
      levelGroups,
      sourceGroups,
      pathGroups,
    ] = await Promise.all([
      prisma.systemLog.count({ where }),
      prisma.systemLog.count({
        where: mergeWhere(where, { createdAt: { gte: last24 } }),
      }),
      prisma.systemLog.count({
        where: mergeWhere(where, { createdAt: { gte: last7 } }),
      }),
      prisma.systemLog.groupBy({
        by: ["level"],
        _count: { _all: true },
        where,
      }),
      prisma.systemLog.groupBy({
        by: ["source"],
        _count: { _all: true },
        where: mergeWhere(where, {
          AND: [{ source: { not: null } }, { source: { not: "" } }],
        }),
        orderBy: { _count: { id: "desc" } },
        take: 5,
      }),
      prisma.systemLog.groupBy({
        by: ["path"],
        _count: { _all: true },
        where: mergeWhere(where, {
          AND: [{ path: { not: null } }, { path: { not: "" } }],
        }),
        orderBy: { _count: { id: "desc" } },
        take: 5,
      }),
    ]);

    const levels = { info: 0, warn: 0, error: 0 } as Record<SystemLogLevel, number>;
    for (const row of levelGroups as Array<{ level: SystemLogLevel; _count: { _all: number } }>) {
      if (row.level in levels) {
        levels[row.level] = row._count._all ?? 0;
      }
    }

    const topSources = (sourceGroups as Array<{ source: string | null; _count: { _all: number } }>)
      .filter((row) => row.source)
      .map((row: { source: string | null; _count: { _all: number } }) => ({ source: row.source as string, count: row._count._all ?? 0 }));
    const topPaths = (pathGroups as Array<{ path: string | null; _count: { _all: number } }>)
      .filter((row) => row.path)
      .map((row: { path: string | null; _count: { _all: number } }) => ({ path: row.path as string, count: row._count._all ?? 0 }));

    return {
      total,
      levels,
      last24Hours,
      last7Days,
      topSources,
      topPaths,
      generatedAt: now,
    };
  } catch (error) {
    if (isMissingPrismaTable(error) && process.env.MONGODB_URI) {
      const filter = buildMongoFilter(input);
      return getMongoSystemLogMetrics(filter);
    }
    throw error;
  }
}

export async function clearSystemLogs(before?: Date | null): Promise<{ deleted: number }> {
  const provider = await getAppDbProvider();
  if (provider === "mongodb") {
    const mongo = await getMongoDb();
    const filter = before ? { createdAt: { $lte: before } } : {};
    const result = await mongo
      .collection<MongoSystemLogDoc>(SYSTEM_LOGS_COLLECTION)
      .deleteMany(filter);
    return { deleted: result.deletedCount ?? 0 };
  }

  const where = before ? { createdAt: { lte: before } } : {};
  try {
    const result = await prisma.systemLog.deleteMany({ where });
    return { deleted: result.count };
  } catch (error) {
    if (isMissingPrismaTable(error) && process.env.MONGODB_URI) {
      const mongo = await getMongoDb();
      const filter = before ? { createdAt: { $lte: before } } : {};
      const result = await mongo
        .collection<MongoSystemLogDoc>(SYSTEM_LOGS_COLLECTION)
        .deleteMany(filter);
      return { deleted: result.deletedCount ?? 0 };
    }
    throw error;
  }
}

import "server-only";

import { createHash } from "crypto";
import type { SystemLogLevel } from "@/shared/types/system-logs";
import { notifyCriticalError } from "@/shared/lib/observability/critical-error-notifier";
import { createSystemLog } from "@/shared/lib/observability/system-log-repository";
import {
  isSensitiveKey,
  REDACTED_VALUE,
  truncateString,
} from "@/shared/lib/observability/log-redaction";

const MAX_CONTEXT_SIZE = 12000;
const MAX_VALUE_LENGTH = 4000;

const sanitizeValue = (value: unknown): Record<string, unknown> | null => {
  try {
    const seen = new WeakSet();
    const json = JSON.stringify(
      value,
      (_key: string, val: unknown): any => {
        if (_key && isSensitiveKey(_key)) return REDACTED_VALUE;
        if (typeof val === "object" && val !== null) {
          if (seen.has(val)) return "[Circular]";
          seen.add(val);
        }
        if (typeof val === "function") return "[Function]";
        if (typeof val === "bigint") return val.toString();
        if (typeof val === "string") return truncateString(val, MAX_VALUE_LENGTH);
        return val;
      },
      2
    );
    if (!json) return null;
    if (json.length > MAX_CONTEXT_SIZE) {
      return {
        truncated: true,
        preview: json.slice(0, MAX_CONTEXT_SIZE),
      };
    }
    const parsed = JSON.parse(json) as unknown;
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      return parsed as Record<string, unknown>;
    }
    return { value: parsed };
  } catch {
    return { error: "Failed to serialize context." };
  }
};

export const normalizeErrorInfo = (error: unknown): { message: string; stack?: string | undefined | null; name?: string; raw?: Record<string, unknown> | null } => {
  if (error instanceof Error) {
    return {
      message: error.message,
      stack: error.stack,
      name: error.name,
    };
  }
  if (typeof error === "string") {
    return { message: error };
  }
  return { message: "Unknown error", raw: sanitizeValue(error) };
};

const extractRequestInfo = (request?: Request): { path?: string; method?: string; requestId?: string } => {
  if (!request) return {};
  try {
    const url = new URL(request.url);
    return {
      path: url.pathname,
      method: request.method,
      requestId: request.headers.get("x-request-id") ?? undefined,
    };
  } catch {
    return {};
  }
};

export const buildErrorFingerprint = (input: {
  message: string;
  source?: string | null;
  path?: string | null;
  statusCode?: number | null;
  errorInfo?: { message?: string; stack?: string | undefined | null; name?: string } | null;
}): string => {
  const hash = createHash("sha256");
  hash.update(input.message ?? "");
  hash.update(String(input.source ?? ""));
  hash.update(String(input.path ?? ""));
  hash.update(String(input.statusCode ?? ""));
  if (input.errorInfo) {
    hash.update(String(input.errorInfo.name ?? ""));
    hash.update(String(input.errorInfo.message ?? ""));
    const stack = input.errorInfo.stack ?? "";
    const normalizedStack = stack
      .split("\n")
      .slice(0, 6)
      .map((line: string) => line.replace(/\s+at\s+/g, " at ").trim())
      .join("\n");
    hash.update(normalizedStack);
  }
  return hash.digest("hex").slice(0, 16);
};

export const getErrorFingerprint = (input: {
  message: string;
  source?: string | null;
  request?: Request;
  statusCode?: number | null;
  error?: unknown;
}): string => {
  const requestInfo = extractRequestInfo(input.request);
  const errorInfo = input.error ? normalizeErrorInfo(input.error) : null;
  return buildErrorFingerprint({
    message: input.message,
    source: input.source ?? null,
    path: requestInfo.path ?? null,
    statusCode: input.statusCode ?? null,
    errorInfo,
  });
};

export type SystemLogInput = {
  level?: SystemLogLevel;
  message: string;
  source?: string;
  context?: Record<string, unknown> | null;
  error?: unknown;
  request?: Request;
  statusCode?: number;
  userId?: string | null;
  requestId?: string | null;
  critical?: boolean;
};

export async function logSystemEvent(input: SystemLogInput): Promise<void> {
  try {
    const errorInfo = input.error ? normalizeErrorInfo(input.error) : null;
    const requestInfo = extractRequestInfo(input.request);
    const fingerprint =
      input.level === "error" || input.level === "warn" || errorInfo
        ? buildErrorFingerprint({
            message: input.message,
            source: input.source ?? null,
            path: input.request?.url ? requestInfo.path ?? null : null,
            statusCode: input.statusCode ?? null,
            errorInfo,
          })
        : null;
    const context = {
      ...(input.context ?? {}),
      ...(errorInfo ? { error: errorInfo } : {}),
      ...(fingerprint ? { fingerprint } : {}),
    };
    const created = await createSystemLog({
      level: input.level ?? "info",
      message: input.message,
      source: input.source ?? null,
      context: sanitizeValue(context),
      stack: errorInfo?.stack ?? null,
      path: input.request?.url ? requestInfo.path : undefined,
      method: requestInfo.method,
      statusCode: input.statusCode ?? null,
      requestId: input.requestId ?? requestInfo.requestId ?? null,
      userId: input.userId ?? null,
    });

    const critical =
      typeof input.critical === "boolean"
        ? input.critical
        : typeof input.context?.critical === "boolean"
          ? Boolean(input.context?.critical)
          : false;

    if (critical) {
      await notifyCriticalError(created, critical);
    }
  } catch (error) {
    console.error("[system-logger] Failed to write system log", error);
  }
}

export async function logSystemError(input: Omit<SystemLogInput, "level">): Promise<void> {
  await logSystemEvent({ ...input, level: "error" });
}

import "server-only";

import prisma from "@/shared/lib/db/prisma";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { ObjectId } from "mongodb";
import { getAppDbProvider } from "@/shared/lib/db/app-db-provider";
import {
  DEFAULT_TRANSIENT_RECOVERY_SETTINGS,
  TRANSIENT_RECOVERY_KEYS,
  type TransientRecoverySettings,
} from "@/shared/lib/transient-recovery/constants";
import { parseJsonSetting } from "@/shared/utils/settings-json";

type SettingRecord = { _id?: string | ObjectId; key?: string; value?: string };

const toMongoId = (id: string): string | ObjectId => {
  if (ObjectId.isValid(id) && id.length === 24) return new ObjectId(id);
  return id;
};

type CacheState = {
  expiresAt: number;
  value: TransientRecoverySettings;
};

const CACHE_TTL_MS = 30000;

let cached: CacheState | null = null;

const canUsePrismaSettings = (): boolean =>
  Boolean(process.env.DATABASE_URL) && "setting" in prisma;

const readPrismaSetting = async (key: string): Promise<string | null> => {
  if (!canUsePrismaSettings()) return null;
  try {
    const setting = await prisma.setting.findUnique({
      where: { key },
      select: { value: true },
    });
    return setting?.value ?? null;
  } catch {
    return null;
  }
};

const readMongoSetting = async (key: string): Promise<string | null> => {
  if (!process.env.MONGODB_URI) return null;
  const mongo = await getMongoDb();
  const doc = await mongo
    .collection<SettingRecord>("settings")
    .findOne({ $or: [{ _id: toMongoId(key) }, { key }] });
  return typeof doc?.value === "string" ? doc.value : null;
};

const readSettingValue = async (key: string): Promise<string | null> => {
  const provider = await getAppDbProvider();
  if (provider === "mongodb") {
    return readMongoSetting(key);
  }
  return readPrismaSetting(key);
};

const toPositiveNumber = (value: unknown, fallback: number, minValue = 0): number => {
  const parsed = typeof value === "number" ? value : Number(value);
  if (!Number.isFinite(parsed) || parsed < minValue) return fallback;
  return parsed;
};

const normalizeSettings = (
  input: TransientRecoverySettings | null | undefined
): TransientRecoverySettings => {
  const base = DEFAULT_TRANSIENT_RECOVERY_SETTINGS;
  const enabled = typeof input?.enabled === "boolean" ? input.enabled : base.enabled;
  const retryEnabled =
    typeof input?.retry?.enabled === "boolean"
      ? input.retry.enabled
      : base.retry.enabled;
  const retry = {
    enabled: retryEnabled,
    maxAttempts: toPositiveNumber(
      input?.retry?.maxAttempts,
      base.retry.maxAttempts,
      1
    ),
    initialDelayMs: toPositiveNumber(input?.retry?.initialDelayMs, base.retry.initialDelayMs),
    maxDelayMs: toPositiveNumber(input?.retry?.maxDelayMs, base.retry.maxDelayMs),
    timeoutMs: ((): number | null => {
      const raw: unknown = input?.retry?.timeoutMs;
      if (raw === null) return null;
      const parsed: number = toPositiveNumber(raw, base.retry.timeoutMs ?? 0);
      return parsed > 0 ? parsed : null;
    })(),
  };
  const circuitEnabled =
    typeof input?.circuit?.enabled === "boolean"
      ? input.circuit.enabled
      : base.circuit.enabled;
  const circuit = {
    enabled: circuitEnabled,
    failureThreshold: toPositiveNumber(
      input?.circuit?.failureThreshold,
      base.circuit.failureThreshold,
      1
    ),
    resetTimeoutMs: toPositiveNumber(input?.circuit?.resetTimeoutMs, base.circuit.resetTimeoutMs),
  };

  return {
    enabled,
    retry,
    circuit,
  };
};

export const getTransientRecoverySettings = async (
  options?: { force?: boolean }
): Promise<TransientRecoverySettings> => {
  const now = Date.now();
  if (!options?.force && cached && cached.expiresAt > now) {
    return cached.value;
  }
  const stored = await readSettingValue(TRANSIENT_RECOVERY_KEYS.settings);
      const parsed: TransientRecoverySettings | null = parseJsonSetting<TransientRecoverySettings | null>(stored, null);  const value = normalizeSettings(parsed);
  cached = {
    value,
    expiresAt: now + CACHE_TTL_MS,
  };
  return value;
};

